-- =============================
-- SP: CALCULANDO_SIHAYEXISTENCIAS
-- =============================
--EXEC CALCULANDO_SIHAYEXISTENCIAS


CREATE PROCEDURE [dbo].[CALCULANDO_SIHAYEXISTENCIAS] @Id_empresa int, @Id_sProducto char(15) as



DECLARE @UNIDADES_AVENDER NUMERIC(12,2)



select *from
(

SELECT	
		SUB.ID_SPRODUCTO,
		(SELECT EXISTENCIA FROM Tbl_existencia WHERE Id_Empresa=@Id_empresa AND Id_Producto=SUB.ID_SPRODUCTO) EXISTENCIA,
        SUB.CANTIDAD,
        @UNIDADES_AVENDER *SUB.Cantidad  AS Minimaexistencia
         FROM Tbl_Productos PROD INNER JOIN Tbl_SProductos SUB
ON PROD.Id_Empresa=SUB.Id_Empresa AND
PROD.Id_Producto =SUB.Id_Producto 
WHERE PROD.Id_Empresa=@Id_empresa   AND PROD.Id_Producto =@Id_sproducto ) x
where x.existencia<Minimaexistencia 

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
-- =============================
-- SP: Clintes_tarjeta_beneficio
-- =============================
CREATE PROCEDURE Clintes_tarjeta_beneficio @id_empresa int as
select nit,nombre,tarjeta from tbl_proveedores where tarjeta<>' '

order by nombre


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: co_catalogo_productos
-- =============================


--exec co_catalogo_productos 1,'06/2005'
--exec co_catalogo_productos 1,'06/2005'
--select *from tbl_productos
CREATE procedure co_catalogo_productos @Id_Empresa	int,@Periodo char(7) as

select 	ltrim(rtrim(P.Id_Producto))+' '+substring(P.descripcion_corta,1,35) as Producto,
	ISNULL(p.Propiedad1,'') as Propiedad1,
	ISNULL(p.Propiedad2,'') as Propiedad2,
	ISNULL(p.Propiedad3,'') as Propiedad3,
	ISNULL(p.Propiedad4,'') as Propiedad4,
	LTRIM(RTRIM(P.Id_articulo))+' '+LTRIM(RTRIM(A.DESCRIPCION))		as Articulo,  
	LTRIM(RTRIM(D.NOMBRE))	 						as depto,
	LTRIM(RTRIM(P.Id_Linea))+' '+LTRIM(RTRIM(LIN.NOMBRE_LINEA))		as Linea,
	(select ISNULL(sum(exis.existencia),0) from tbl_existencia exis 
		where 	exis.Id_Empresa	=p.Id_Empresa 	and
			exis.Id_Producto=p.Id_Producto	and
			exis.Periodo	=@Periodo) as existencia,
	isnull(p.costo_promedio,0000.00000)  as Promedio,
	(select ISNULL(sum(exis.existencia)*round(p.costo_promedio,5),0) from tbl_existencia exis 
		where 	exis.Id_Empresa	=p.Id_Empresa 	and
			exis.Id_Producto=p.Id_Producto	and
			exis.Periodo	=@Periodo) as Total

 From Tbl_Productos p	inner join 	 tbl_articulos a
			on	p.Id_Empresa	=a.Id_Empresa	and
				p.Id_Articulo	=a.Id_Articulo
						inner join tbl_departamentos d
			on	p.Id_Empresa	=d.Id_Empresa	and
				p.Id_Depto	=d.Id_Depto
						inner join tbl_linea	lin
			on	p.Id_Empresa	=lin.Id_Empresa	and
				p.Id_Linea	=lin.Id_Linea







GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
-- =============================
-- SP: co_ordenes_servicio
-- =============================

--*-select *from tbl_orden_servicio
--exec co_ordenes_servicio 1
CREATE procedure co_ordenes_servicio @Id_Empresa int as
select c.Id_Orden,
	c.Num_Placa,
	c.nit,
	cast(year(c.fecha_facturacion) as char(4))+'/'+
	replicate('0',2- ltrim(rtrim(cast(month(c.fecha_facturacion) as char))))+ltrim(rtrim(cast(month(c.fecha_facturacion) as char)))  as anio_mes,
	ltrim(rtrim(d.Id_servicio))+'-'+p.descripcion as servicio,
	d.Costo,
	d.cantidad,
	d.precio,
	d.precio_descuento,
	(d.cantidad*precio_descuento)-(d.cantidad*d.costo) as utilidad,
	d.id_empleado+ltrim(rtrim(v.nombre)) as vendedor,
	h.marca
	from tbl_orden_servicio c	left join tbl_orden_servicio_detalle d
				on 	c.Id_Empresa	=d.Id_Empresa	and
					c.Id_Orden	=d.Id_Orden
					inner join tbl_productos	p
				on	d.Id_Empresa	=p.Id_Empresa	and
					d.Id_Servicio	=p.Id_producto
					inner join tbl_vendedores 	v
				on	d.id_empresa	=v.id_empresa	and
					d.id_empleado	=v.id_empleado
					inner join tbl_vehiculos	h
				on	c.id_empresa	=h.id_empresa	and
					c.num_placa	=h.num_placa
where c.Id_Empresa=@Id_Empresa and c.Tipo<>'' and c.numero<>0	and p.es_servicio=1
--select *from tbl_orden_servicio					
--select *from tbl_orden_servicio_detalle
--select *from tbl_productos
--select *from tbl_vendedores
--select *from tbl_vehiculos



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
-- =============================
-- SP: consulta_saldo
-- =============================
create procedure consulta_saldo @id_cliente_vale varchar(20) as

select saldo 
from tbl_cliente_gasolina
where id_empresa = 1 and id_cliente_vale = @id_cliente_vale

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: consulta_saldo_prepago
-- =============================
CREATE procedure [dbo].[consulta_saldo_prepago] @id_cliente_vale varchar(20) as

select SUM(VALOR_VALE)
from TBL_DETALLE_VENTAS_VALES 
where id_empresa = 1 and ID_CLIENTE_VALE_DETALLE  = @id_cliente_vale

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: dt_addtosourcecontrol
-- =============================
create proc dbo.dt_addtosourcecontrol
    @vchSourceSafeINI varchar(255) = '',
    @vchProjectName   varchar(255) ='',
    @vchComment       varchar(255) ='',
    @vchLoginName     varchar(255) ='',
    @vchPassword      varchar(255) =''

as

set nocount on

declare @iReturn int
declare @iObjectId int
select @iObjectId = 0

declare @iStreamObjectId int
select @iStreamObjectId = 0

declare @VSSGUID varchar(100)
select @VSSGUID = 'SQLVersionControl.VCS_SQL'

declare @vchDatabaseName varchar(255)
select @vchDatabaseName = db_name()

declare @iReturnValue int
select @iReturnValue = 0

declare @iPropertyObjectId int
declare @vchParentId varchar(255)

declare @iObjectCount int
select @iObjectCount = 0

    exec @iReturn = sp_OACreate @VSSGUID, @iObjectId OUT
    if @iReturn <> 0 GOTO E_OAError


    /* Create Project in SS */
    exec @iReturn = sp_OAMethod @iObjectId,
                                'AddProjectToSourceSafe',
                                NULL,
                                @vchSourceSafeINI,
                                @vchProjectName output,
                                @@SERVERNAME,
                                @vchDatabaseName,
                                @vchLoginName,
                                @vchPassword,
                                @vchComment


    if @iReturn <> 0 GOTO E_OAError

    exec @iReturn = sp_OAGetProperty @iObjectId, 'GetStreamObject', @iStreamObjectId OUT

    if @iReturn <> 0 GOTO E_OAError

    /* Set Database Properties */

    begin tran SetProperties

    /* add high level object */

    exec @iPropertyObjectId = dbo.dt_adduserobject_vcs 'VCSProjectID'

    select @vchParentId = CONVERT(varchar(255),@iPropertyObjectId)

    exec dbo.dt_setpropertybyid @iPropertyObjectId, 'VCSProjectID', @vchParentId , NULL
    exec dbo.dt_setpropertybyid @iPropertyObjectId, 'VCSProject' , @vchProjectName , NULL
    exec dbo.dt_setpropertybyid @iPropertyObjectId, 'VCSSourceSafeINI' , @vchSourceSafeINI , NULL
    exec dbo.dt_setpropertybyid @iPropertyObjectId, 'VCSSQLServer', @@SERVERNAME, NULL
    exec dbo.dt_setpropertybyid @iPropertyObjectId, 'VCSSQLDatabase', @vchDatabaseName, NULL

    if @@error <> 0 GOTO E_General_Error

    commit tran SetProperties

    declare cursorProcNames cursor for
        select convert(varchar(255), name) from sysobjects where type = 'P' and name not like 'dt_%'
    open cursorProcNames

    while 1 = 1
    begin
        declare @vchProcName varchar(255)
        fetch next from cursorProcNames into @vchProcName
        if @@fetch_status <> 0
            break

        select colid, text into #ProcLines
        from syscomments
        where id = object_id(@vchProcName)
        order by colid

        declare @iCurProcLine int
        declare @iProcLines int
        select @iCurProcLine = 1
        select @iProcLines = (select count(*) from #ProcLines)
        while @iCurProcLine <= @iProcLines
        begin
            declare @pos int
            select @pos = 1
            declare @iCurLineSize int
            select @iCurLineSize = len((select text from #ProcLines where colid = @iCurProcLine))
            while @pos <= @iCurLineSize
            begin
                declare @vchProcLinePiece varchar(255)
                select @vchProcLinePiece = convert(varchar(255),
                    substring((select text from #ProcLines where colid = @iCurProcLine),
                              @pos, 255 ))
                exec @iReturn = sp_OAMethod @iStreamObjectId, 'AddStream', @iReturnValue OUT, @vchProcLinePiece
                if @iReturn <> 0 GOTO E_OAError
                select @pos = @pos + 255
            end
            select @iCurProcLine = @iCurProcLine + 1
        end
        drop table #ProcLines

        exec @iReturn = sp_OA
