-- =============================
--CREATE  Function [dbo].[Existe_vale_prepago](@Id_empresa int,@serie varchar(20),@numero_factura numeric(12),@numero_vale int )
--exec existe_vale_prepago '1', 'A', 1000, 102
CREATE procedure existe_vale_prepago
@Id_empresa		int,
@serie			varchar(20),
@numero_factura INT,
@numero_vale	int
as

    SELECT COUNT(*)
          FROM [db_inventario_pfp].[dbo].[TBL_DETALLE_CANTIDAD_VALES_VENDIDOS]
          where ID_EMPRESA  =	@Id_empresa		 and
          NUMERO_FACTURA	=	@nUMERO_fACTURA  and
          sERIE				=	@SERIE			 AND
          @NUMERO_VALE	 BETWEEN Del			 AND Al 
        
     
 
      
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: revoca_vales_gasolina
-- =============================
create procedure revoca_vales_gasolina @id_empresa int,
									   @serie	   varchar(15), 
									   @numero	   int as  						   
						   
update TBL_DETALLE_VALES_POR_APLICAR 
set ESTADO_VALE = 2, FACTURADO = 2						   
where ID_VALE_POST_PAGO in(select id_vale_post_pago 
						   from TBL_DETALLE_VENTAS_VALES
						   where id_empresa		=	@id_empresa and 
								 SERIE			=	@serie		AND 
								 NUMERO_FACTURA =   @numero)						   
						   
						   
delete from TBL_DETALLE_VENTAS_VALES  
where id_empresa = @id_empresa and SERIE = @serie  AND NUMERO_FACTURA = @numero 

delete from TBL_CABECERA_VENTAS_VALE 
where ID_EMPRESA = @id_empresa and SERIE  = @serie  AND NUMERO = @numero
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
-- =============================
-- SP: rpt_abonos
-- =============================

--set dateformat dmy
--exec [dbo].[rpt_abonos] 1, '01/01/2020', '31/12/2020', 'FAC'

CREATE procedure [dbo].[rpt_abonos] @Id_Empresa int,@Fecha_inicial datetime,@fecha_final datetime,@Id_tipo_pago char(3) as
			
declare @nombre_empresa char (150)

select @nombre_empresa=nombre_empresa from EMPRESAS where id_empresa = @Id_empresa

select 
c.id_empresa,
e.Nombre_Empresa,
c.Id_Tipo_Pago,
c.Numero_Pago,
c.Fecha_Docto,
c.Descripcion,
c.Total_Abono,
c.Fecha_Abono,
c.Usuario,
c.Fecha_Operacion,
c.Status,
c.nit,
x.Nombre
 from tbl_abonos c, tbl_det_abonos p, tbl_proveedores x, empresas e
	where 
		c.id_empresa = p.id_empresa and
	       	c.id_tipo_pago = p.id_tipo_pago and 
		c.numero_pago = p.numero_pago and
		c.id_empresa = x.id_empresa and
		p.id_empresa = x.id_empresa and
		p.nit = x.nit and

c.id_empresa=@Id_Empresa and
datediff(day,c.fecha_docto,@fecha_final) between 0  and datediff(day,@Fecha_Inicial,@fecha_final)	and
p.valor_aplicado>0	and c.Id_tipo_pago=case when @Id_Tipo_Pago='TOD' Then c.Id_Tipo_pago else @Id_Tipo_pago end
order by c.fecha_docto


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
-- =============================
-- SP: rpt_anticipos_clientes
-- =============================


--set dateformat dmy
--exec rpt_anticipos_clientes 1,'01/01/2006','05/11/2006'
CREATE procedure rpt_anticipos_clientes 		@id_empresa int,
						 	@fecha_inicial datetime,
							@fecha_final	datetime as

set dateformat dmy

select (select nombre_empresa from empresas where id_empresa=@id_empresa) as nombre_empresa,
	p.nombre,
	a.* from tbl_anticipos_clientes a	inner join tbl_proveedores p
						on	a.id_empresa	=p.id_empresa	and
							a.id_cliente		=p.nit
where 	a.id_empresa =@Id_Empresa	and
	datediff(day,fecha_anticipo,@fecha_final) between  0	and datediff(day,@fecha_inicial,@fecha_final)


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
-- =============================
-- SP: rpt_anticipos_clientes_detalle
-- =============================
--exec  [dbo].[rpt_anticipos_clientes_detalle] 1, 6
CREATE procedure [dbo].[rpt_anticipos_clientes_detalle] @Id_Empresa int , @id_numero_anticipo numeric(10) as
select Id_numero_anticipo,
	serie,
	tipo_docto,
	numero_docto,
	valor_aplicado
	from tbl_Detalle_anticipos_clientes where id_empresa=@Id_Empresa and id_numero_anticipo=@Id_numero_anticipo


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
-- =============================
-- SP: rpt_anticipos_clientes_por_aplicar
-- =============================
--exec rpt_anticipos_clientes_por_aplicar 1
CREATE procedure [dbo].[rpt_anticipos_clientes_por_aplicar] @Id_empresa int as
select 
a.Id_Empresa,
e.Nombre_Empresa,
a.id_numero_anticipo,
a. Id_cliente,
a.Fecha_anticipo,
a.Fecha_operacion,
p.Nit,
p.Nombre,
a.Valor_aplicado,
a.Valor_anticipo,
a.descripcion,
(select top 1 tipo_docto + cast (numero_docto as char) from dbo.tbl_cuentas_por_cobrar c
where c.id_empresa=a.id_empresa and c.nit=a.Id_cliente and c.saldo_docto>0 ) as factura
 from tbl_anticipos_clientes a, tbl_proveedores p, empresas e
where  a.id_empresa=p.id_empresa and
a.id_cliente=p.nit and
a.id_empresa=e.id_empresa and
a.id_empresa=@Id_empresa and
a.Valor_aplicado='0.00' and
a.status<>2

select * from dbo.Tbl_anticipos_clientes
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
-- =============================
-- SP: rpt_anticipos_pos
-- =============================

create procedure rpt_anticipos_pos @Id_Empresa int, @Id_Anticipo Int as
select a.*,
	(select nombre_empresa from empresas where id_empresa=1) as nombreempresa
 from tbl_anticipos_pos a
where 	a.id_Empresa	=@Id_Empresa	and
	a.Id_Anticipo	=@Id_Anticipo


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
-- =============================
-- SP: rpt_anticipos_proveedores
-- =============================



--exec rpt_anticipos_proveedores  1
CREATE procedure rpt_anticipos_proveedores @Id_empresa int as


SELECT 	Id_Empresa,
	(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombreempresa,
	Id_Tipo_Pago,
	Numero_Pago,
	Fecha_Docto, 	
	Descripcion,
	Total_Abono,
	Nit,
	Nombre,
	Status,
	Total_aplicado from 
(SELECT   dbo.Tbl_Abonos.Id_Empresa,
	 dbo.Tbl_Abonos.Id_Tipo_Pago,
	 dbo.Tbl_Abonos.Numero_Pago,
	 dbo.Tbl_Abonos.Fecha_Docto, 
         dbo.Tbl_Abonos.Descripcion,
	 dbo.Tbl_Abonos.Total_Abono,
	 dbo.Tbl_Abonos.Nit,
	 dbo.Tbl_Proveedores.Nombre,
	 dbo.Tbl_Abonos.Status,
	(select ISNULL(sum(d.valor_aplicado),0) from tbl_det_abonos d 
		where 	d.Id_empresa	=dbo.Tbl_Abonos.Id_Empresa 	and
			d.Id_Tipo_pago	=dbo.Tbl_Abonos.Id_Tipo_Pago	and
			d.Numero_pago	=dbo.Tbl_Abonos.Numero_Pago) as  total_aplicado

FROM         dbo.Tbl_Abonos INNER JOIN
                      dbo.Tbl_Proveedores ON dbo.Tbl_Abonos.Id_Empresa = dbo.Tbl_Proveedores.Id_Empresa AND dbo.Tbl_Abonos.Nit = dbo.Tbl_Proveedores.Nit
WHERE    dbo.Tbl_Abonos.Id_Empresa=@Id_Empresa 	and 
	(dbo.Tbl_Abonos.Id_Tipo_Pago = 'ANT') 	)  A
where total_abono<>total_aplicado
order by Fecha_Docto


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
-- =============================
-- SP: rpt_anticipos_proveedores_total
-- =============================



--exec rpt_anticipos_proveedores_total  1
CREATE procedure [dbo].[rpt_anticipos_proveedores_total] @Id_empresa int as


SELECT 	Id_Empresa,
	(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombreempresa,
	Id_Tipo_Pago,
	Numero_Pago,
	Fecha_Docto, 	
	Descripcion,
	Total_Abono,
	Nit,
	Nombre,
	Status,
	Total_aplicado from 
(SELECT   dbo.Tbl_Abonos.Id_Empresa,
	 dbo.Tbl_Abonos.Id_Tipo_Pago,
	 dbo.Tbl_Abonos.Numero_Pago,
	 dbo.Tbl_Abonos.Fecha_Docto, 
         dbo.Tbl_Abonos.Descripcion,
	 dbo.Tbl_Abonos.Total_Abono,
	 dbo.Tbl_Abonos.Nit,
	 dbo.Tbl_Proveedores.Nombre,
	 dbo.Tbl_Abonos.Status,
	(select ISNULL(sum(d.valor_aplicado),0) from tbl_det_abonos d 
		where 	d.Id_empresa	=dbo.Tbl_Abonos.Id_Empresa 	and
			d.Id_Tipo_pago	=dbo.Tbl_Abonos.Id_Tipo_Pago	and
			d.Numero_pago	=dbo.Tbl_Abonos.Numero_Pago) as  total_aplicado

FROM         dbo.Tbl_Abonos INNER JOIN
                      dbo.Tbl_Proveedores ON dbo.Tbl_Abonos.Id_Empresa = dbo.Tbl_Proveedores.Id_Empresa AND dbo.Tbl_Abonos.Nit = dbo.Tbl_Proveedores.Nit
WHERE    dbo.Tbl_Abonos.Id_Empresa=@Id_Empresa 	and 
	(dbo.Tbl_Abonos.Id_Tipo_Pago = 'ANT') 	)  A
where total_abono<>total_aplicado
order by Fecha_Docto


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
