-- =============================
-- SP: rpt_avisos
-- =============================





--set dateformat dmy
--select *from tbl_proveedores
--select *from tbl_vehiculos
--exec rpt_avisos 1,'01/01/2007','30/10/2007','15/12/2007'
CREATE procedure [dbo].[rpt_avisos] 	@id_empresa	int,
				@fecha 		datetime,
				@fecha_al   datetime,
				@fecha_Sugerida datetime  as 
--procedimiento para genera registros de avisos a clientes

select 	@fecha_sugerida as fecha_sugerida,
	p.nit,
	p.NOMBRE,
	p.DIRECCION,
	p.num_casa,
	p.COLONIA,
	p.APTO,
	p.ZONA,
	p.CIUDAD,
	p.MUNICIPIO,
	UPPER(ltrim(rtrim(v.marca)))  as marca,
              ltrim(rtrim(v.modelo))    as modelo,
	' placa  '+ltrim(rtrim(v.num_placa)) as vehiculo
	 From tbl_proveedores p	right join tbl_vehiculos	v
					on 	p.id_empresa	=v.id_empresa	and
						p.nit		=v.nit and p.direccion<>''
where 	p.id_empresa=@id_Empresa			and	
		datediff(day,p.fecha_ult_mov,@fecha_al) between 0  and datediff(day,@fecha,@fecha_al) and
		p.tipo		='C'

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_balance_antiguedad_por_cobrar
-- =============================

--select *from Tbl_cuentas_por_cobrar 
--set dateformat dmy
--SELECT *FROM Tbl_Proveedores WHERE Nit IN ('123452-1','21078012','234563-1','ATISA'  )                      
--exec rpt_balance_antiguedad_por_cobrar 1,'25/12/2020','TODOS',1,1,1,'G'
--select *from tbl_proveedores
CREATE  procedure [dbo].[rpt_balance_antiguedad_por_cobrar] @Id_Empresa	int,@Fecha_Tentativa_cobro datetime,@NIT  char(20) ,@Orden int,@Esreporte_sumario int,@Tipo_reporte int,@Cliente_o_grupo char(1) as
--@Tipo_reporte =1 =Fecha Vencimiento
--@Tipo_reporte =2 =Fecha Documento
--@Cliente_grupo='C' Balance antiguedad por cliente
--@Cliente_grupo='G' Balance antiguedad por grupo
--@Cliente_grupo='V' Balance antiguedad por vendedor
Declare @Nombre_Empresa	char(80),
		@Grupo_seleccionado char(10)
select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa
/*@tipo_reporte=1 balance de antiguedad a partir de fecha vencimiento
@tipo _reporte=2balance de antiguedad a partir de fecha_documento*/

select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa

IF @Cliente_o_grupo ='C'
BEGIN

print 'paso por c'
-- cuentas por cobrar originadas por los envios
select @Nombre_empresa  as nombreempresa,
	c.Id_Empresa,
	c.Id_Bodega,
	c.Id_Tipo,
	c.Numero,
	c.Fecha,
	dateadd(day,p.dias_credito,c.fecha) as fecha_tentativa_cobro,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  <=0
		Then c.Saldo_Envio
		Else 0 	end	as No_Vencido,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  between 1 	and 30
		Then c.Saldo_Envio
		Else 0 	end	as dias_1_30,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  between 31 	and 60
		Then c.Saldo_Envio
		Else 0 	end	as dias_31_60,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  between 61 	and 90
		Then c.Saldo_Envio
		Else 0 	end	as dias_61_90,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  between 91	and 120
		Then c.Saldo_Envio
		Else 0 	end	as dias_91_120,
	case when datediff(day,dateadd(day,p.dias_credito,c.fecha),@Fecha_Tentativa_cobro)  > 120
		Then c.Saldo_Envio
		Else 0 	end	as mas_120,
	c.concepto,
	c.nit,
	p.nombre,
	p.limite_credito_cliente,
	c.Saldo_Envio,
	' ' AS ENTEFACTURADOR,
	datediff(day, dateadd(day,p.dias_credito,c.Fecha),@Fecha_Tentativa_cobro ) as dias,
	
	' ' as GRUPOCLIENTE,
	' ' as VENDEDOR,
	
	0   as limitecreditogrupo
	 from tbl_cabecera_movimientos  c inner join tbl_proveedores p
						on 	c.Id_empresa	=p.id_empresa	and
							c.nit		=p.nit
	where c.id_empresa=@Id_empresa and c.id_tipo='ENV' AND c.Saldo_Envio>0 and c.fecha<=@fecha_tentativa_cobro and
	  c.nit  = case when @nit='TODOS'  then c.nit else @nit end
	union all -- query de cuentas por cobrar
	select @nombre_empresa as nombreempresa,
		c.Id_empresa,
		'XX',
		c.Tipo_docto+(case when c.serie='XXX'
					Then ''
					Else '-'+c.serie end),
		c.numero_docto,	c.fecha_docto,c.fecha_tentativa_cobro,
		
	
	case when datediff(day,c.Fecha_tentativa_cobro ,@Fecha_Tentativa_cobro)  <=0
		Then c.Saldo_docto
		Else 0 	end	as No_Vencido,
	case when @Tipo_reporte =1   /*fecha vencimiento*/	
		Then case when datediff(day,c.Fecha_tentativa_cobro ,@Fecha_Tentativa_cobro)  between 1 and 30
				Then c.Saldo_docto
				Else 0 	end
		Else case when DATEDIFF(DAY,c.Fecha_docto,@Fecha_Tentativa_cobro) < 31 /*fecha documento*/
				Then c.Saldo_docto 
				Else 0 end
		end						as dias_1_30,
	case when @Tipo_reporte = 1 /*fecha vencimiento*/
		then case when datediff(day,c.Fecha_tentativa_cobro ,@Fecha_Tentativa_cobro)  between 31 and 60
			Then c.Saldo_docto
			Else 0 	end	
		Else case when DATEDIFF(DAY,c.Fecha_docto,@Fecha_Tentativa_cobro ) between 31 and 60 /*fecha do
-- =============================
-- SP: rpt_Balance_Antiguedad_Saldos
-- =============================



--exec rpt_balance_antiguedad_saldos 1,'03/07/2020','111111','1',1
CREATE procedure [dbo].[rpt_Balance_Antiguedad_Saldos]  @Id_Empresa	int,@Fecha_tentativa_pago	datetime,@nit char(20),@Clasificacion char(10) , @orden_reporte int as
set dateformat dmy
--@orden_reporte=1 nit 2=alfabetico
Declare @Nombre_Empresa	char(80)
select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa
	
select	
a.Id_Empresa,
@Nombre_Empresa as nombre_empresa,
	a.Nit,
	p.nombre,
	a.tipo_cargo,
	a.Numero_Factura,
	a.Descripcion,
	a.Fecha_Documento,
	a.fecha_tentativa_pago as fecha_pago,
	a.Valor_FActura,
	a.Saldo_FActura,
	
	case when datediff(day,a.Fecha_tentativa_pago,@Fecha_Tentativa_pago)  <=0
		Then a.Saldo_Factura
		Else 0 	end	as No_Vencido,
	case when datediff(day,a.Fecha_tentativa_pago,@Fecha_Tentativa_pago)  Between 1 	and 30
		Then a.Saldo_Factura
		Else 0 	end	as Vencido_1_30,
	case when datediff(day,a.Fecha_tentativa_pago,@Fecha_Tentativa_pago)  Between 31	and 45
		Then a.Saldo_Factura
		Else 0 	end	as Vencido_30_45,

	case when datediff(day,a.Fecha_Tentativa_pago ,@Fecha_Tentativa_pago)  Between 46	and 60
		Then Saldo_Factura
		Else 0 	end	as Vencido_46_60,
	case when datediff(day,a.Fecha_Documento,@Fecha_Tentativa_pago)  > 60
		Then a.Saldo_Factura
		Else 0 	end	as Vencido_Mas_60
		from tbl_cargos a inner join tbl_proveedores p	on	a.Id_Empresa	=p.Id_Empresa	and
									a.Nit		=p.nit
where 	a.id_empresa	=@Id_empresa		and
	a.nit		=case when @nit='' Then a.nit else @nit end	and
	a.Saldo_Factura	>0.00						and
	p.clasificacion	=case when @nit='' 
				then (case when @clasificacion IN ('PROVEEDOR','OTRO')
					then @clasificacion
					else p.clasificacion end)
			else	p.clasificacion end	and
	a.fecha_documento<= dateadd(day,1,@fecha_tentativa_pago)
ORDER BY fecha_tentativa_pago


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: rpt_balance_saldos_cxp
-- =============================
--set dateformat dmy
--exec rpt_balance_saldos_cxp 1,'29/06/2020'
CREATE  procedure [dbo].[rpt_balance_saldos_cxp]  @Id_empresa int,
								@Al			datetime  as
								
								
--reporte de saldos de cuentas por pagar a un fecha especifica

select  
(select nombre_empresa from empresas where Id_Empresa=@Id_empresa) as nombreempresa,
(select nombre from Tbl_Proveedores p where p.Id_Empresa=@Id_empresa and p.Nit=x.nit) as proveedor,
x.nit,x.numero_factura,x.tipo_cargo,serie,sum(valor) as saldo from
(								
	select  
			Nit,
			Tipo_Cargo,
			Serie,
			Numero_Factura,
			Valor_Factura as valor   from Tbl_Cargos 
	where	Id_Empresa=@Id_empresa and
			Fecha_Documento <= @Al 
	union all 
	select	
			d.Nit,
			d.Tipo_cargo,
			d.Serie ,
			d.Numero_factura,
			(d.Valor_Aplicado*-1) as valor
			from Tbl_Abonos a,Tbl_Det_Abonos d
	where	a.Id_Empresa	=d.Id_Empresa	and
			a.id_tipo_pago	=d.Id_Tipo_Pago and
			a.Numero_Pago	=d.Numero_Pago	and
			a.Id_Empresa =@Id_empresa and

			d.Fecha_de_pago    <= @Al

	UNION ALL   -- anticipos no aplicados
	SELECT  
			NIT ,
		   ID_TIPO_PAGO,
		   ' ' AS SERIE,
		   NUMERO_PAGO,
		   (TOTAL_ABONO -
		   ( 
		  ISNULL( ( SELECT SUM(VALOR_APLICADO)  FROM TBL_DET_ABONOS
			WHERE ID_EMPRESA=@Id_empresa AND ID_TIPO_PAGO='ANT' AND NUMERO_PAGO=tbl_abonos.numero_pago),0)
			) ) *-1 as Anticipo_pendiente


	FROM TBL_ABONOS 
	WHERE ID_EMPRESA=@Id_empresa AND
	ID_TIPO_PAGO='ANT' AND
	Fecha_docto <=@AL 

/*    union all   --seleccionando todos los anticipos aplicados 
	select d.nit,
		d.tipo_cargo,
		d.serie,
		d.numero_factura,
		(d.valor_aplicado   )   *-1 from tbl_abonos a inner join tbl_det_abonos d
	on	a.id_empresa	=d.id_empresa and
		a.id_tipo_pago	=d.id_tipo_pago and
		a.Numero_Pago	=d.Numero_Pago 
	where a.id_empresa=@Id_empresa and
		a.id_tipo_pago='ANT' and
		d.Fecha_de_pago <=@AL 
*/

		
		
		
		 ) x
group by x.Nit,x.Numero_Factura,x.Tipo_Cargo,x.serie 		


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
