--exec rpt_catalogo_articulos 1
CREATE procedure [dbo].[rpt_catalogo_articulos] @Id_Empresa int as
select 
(select nombre_empresa from empresas where id_empresa=A.Id_empresa) as nombreempresa,	
a.*from tbl_articulos a WHERE a.id_empresa=@Id_empresa order by a.id_articulo



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
