-- SP: rpt_catalogo_clientes
-- =============================
--exec dbo.rpt_catalogo_clientes 1,'NIT'
CREATE procedure rpt_catalogo_clientes @Id_empresa int,@Orden char(10),@CREDITO_CONTADO INT as
select a.*,
(select Nombre_Empresa from empresas where Id_Empresa=@Id_empresa ) as nombreempresa
 from tbl_proveedores a
where id_empresa=@Id_empresa and
clasificacion in ('CLIENTE','PROVE/CLIE') AND
Credito_o_Contado = case when @CREDITO_CONTADO =0 then credito_o_contado else @CREDITO_CONTADO  end 
order by case when @Orden='NIT' THEN  Nit ELSE Nombre END 


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
