--exec rpt_catalogo_grupo 1
CREATE PROCEDURE [dbo].[rpt_catalogo_grupo] @Id_empresa int as

SELECT TOP 1000 g.Id_empresa
      ,[Id_grupo_cliente]
      ,[Descripcion_grupo],
      e.Nombre_Empresa 
  FROM [dbo].[Tbl_grupo_cliente] g, dbo.empresas  e
  where g.Id_empresa =e.Id_Empresa and  g.Id_empresa =@Id_empresa
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_catalogo_productos
-- =============================

--select *from tbl_articulos
--select *from tbl_productos
--tipo="GENERAL"
--TIPO="DEPARTAMENTO"
--exec rpt_catalogo_productos 1,'GENERAL','TOD','TOD',1,1
--exec rpt_catalogo_productos 1,'ARTICULO','TOD','TOD',1,1
--exec rpt_catalogo_productos 1,'DEPTO','TOD','TOD',1,1
CREATE procedure [dbo].[rpt_catalogo_productos] 	@Id_Empresa	int,		--empresa seleccionada
					@Tipo 		char(10),	--GENERAL,ARTICULO,departamento,TIPO-PRODU(NORMAL-TERMINADO,MPRIMA)
					@Filtro1	char(10),	--'TOD',QUE ARTICULO
					@Filtro2	char(10),
					@Incluye_Precio int,		--1=SI 0 =NO
					@Orden		int as --@orden=1 por codigo; 2=Alfabetico

Declare @Nombre_Empresa	char(150)
select @Nombre_Empresa=Nombre_empresa from empresas where id_Empresa=@Id_Empresa
If @Tipo='GENERAL'
Begin
	SELECT @Nombre_Empresa as nombre_empresa,
		t.id_producto,
		t.descripcion,
		t.precioa,
		t.Preciob,
		t.Precioc,
		a.Id_articulo	,
		a.Descripcion	as descripcion_articulo,
		d.Id_Depto	as Id_Depto,
		d.Nombre	as descripcion_depto,
		l.Id_Linea	,
		U.Descripcion AS descripcion_unidad,
		u.Id_medida as id_medida_unidad,
		l.Nombre_Linea,
		t.Tipo
	 FROM TBL_PRODUCTOS	t inner join tbl_articulos	a
					on 	t.Id_Empresa	=a.Id_Empresa	and
						t.Id_Articulo	=a.Id_Articulo
				inner join tbl_departamentos	d
					on 	t.Id_Empresa	=d.Id_Empresa	and
						t.Id_Depto	=d.Id_Depto
				inner join tbl_linea		l
					on	t.Id_Empresa	=l.Id_Empresa	and
						t.Id_Depto	=l.Id_Depto	and
						t.Id_linea	=l.Id_Linea         
			    inner join Tbl_Unidad_Medida u
				    on  t.Id_Empresa=u.Id_Empresa        and
					    t.Id_medida=u.Id_medida          and
						t.Id_medida1=u.Id_medida 
	where t.id_Empresa	=@Id_Empresa	AND
		t.ID_PRODUCTO	=CASE WHEN @tipo='GENERAL'
						THEN t.id_producto end
END
else
	If @Tipo='ARTICULO'
	BEGIN
		SELECT @Nombre_Empresa as nombre_empresa,
			t.id_producto,
			t.descripcion,
			t.precioa,
			t.Preciob,
			t.Precioc,
			a.Id_articulo	,
			a.Descripcion 	as descripcion_articulo,
			d.Id_Depto	as Id_Depto,
			d.Nombre	as descripcion_depto,
			l.Id_Linea	,
			U.Descripcion AS descripcion_unidad,
		    u.Id_medida as id_medida_unidad,
			l.Nombre_Linea,
			t.Tipo
		 FROM TBL_PRODUCTOS	t inner join tbl_articulos	a
						on 	t.Id_Empresa	=a.Id_Empresa	and
							t.Id_Articulo	=a.Id_Articulo
					inner join tbl_departamentos	d
						on 	t.Id_Empresa	=d.Id_Empresa	and
							t.Id_Depto	=d.Id_Depto
					inner join tbl_linea		l
						on	t.Id_Empresa	=l.Id_Empresa	and
							t.Id_Depto	=l.Id_Depto	and
							t.Id_linea	=l.Id_Linea
							inner join Tbl_Unidad_Medida u
				    on  t.Id_Empresa=u.Id_Empresa        and
					    t.Id_medida=u.Id_medida          and
						t.Id_medida1=u.Id_medida 
		where t.id_Empresa	=@Id_Empresa	AND
			t.ID_Articulo	=CASE WHEN @Filtro1='TOD'
							THEN t.Id_Articulo 
							ELSE @Filtro1
					 end
	END
	ELSE	BEGIN
			If @Tipo='DEPTO'
			BEGIN
				SELECT @Nombre_Empresa as nombre_empresa,
					t.id_producto,
					t.descripcion,
					t.precioa,
					t.preciob,
					t.precioc,
					a.Id_articulo	,
					a.Descripcion	as descripcion_articulo,
					d.Id_Depto	as Id_depto,
					d.nombre 	as descripcion_depto,
					l.Id_Linea	,
					U.Descripcion AS descripcion_unidad,
	          	    u.Id_medida as id_medida_unidad,
					l.Nombre_Linea,
					t.Tipo
				 FROM TBL_PRODUCTOS	t inner join tbl_articulos	a
							on 	t.Id_Empresa	=a.Id_Empresa	and
								t.Id_Articulo	=a.Id_Articulo	
							inner join tbl_departamentos	d
							on 	t.Id_Empresa	=d.Id_Empresa	and
								t.Id_Depto	=d.Id_Depto
							inner join tbl_linea		l
							on	t.Id_Empresa	=l.Id_Empresa	and
								t.Id_Depto	=l.Id_Depto	and
								t.Id_linea	=l.Id_Linea
						    inner join Tbl_Unidad_Medida u
				    on  t.Id_Empresa=u.Id_Empresa        and
					    t.Id_medida=u.Id_med
-- =============================
-- SP: rpt_catalogo_productos_por_proveedor
-- =============================
--exec rpt_catalogo_productos_por_proveedor 1,1,'ALTA','TODOS'

CREATE procedure rpt_catalogo_productos_por_proveedor @Id_empresa int, @Incluye_precio int,@Estado char(15), @Nit char(20) as
--@iNCLUYE_PRECIO =1=SI INCLUYE PRECIO
--@INCLUYE_PRECIO =2=NO INCLUYE PRECIO
--@Estado= 'ALTA'
--@Estado= 'BAJA'
--@Estado= 'TODOS'
--@NIT=   'TODOS'
select empre.Nombre_Empresa ,
p.id_producto,
p.descripcion,
p.precioa,
p.preciob,
p.precioc,
prodproveedores.Nit  from tbl_productos p inner join tbl_prod_proveedores prodproveedores
on p.id_empresa=prodproveedores.id_empresa and
p.id_producto=prodproveedores.id_producto  
											inner join empresas empre
on p.Id_Empresa =empre.id_empresa 
where p.id_empresa=@Id_empresa and
p.estado=case when  P.estado='TODOS'
			Then p.estado
			Else @Estado end  AND
PRODPROVEEDORES.NIT= CASE WHEN @NIT='TODOS'
						Then PRODPROVEEDORES.NIT
						else @NIT END


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
-- =============================
-- SP: rpt_catalogo_productos_sproductos
-- =============================

--exec [dbo].[rpt_catalogo_productos_sproductos] 2
CREATE procedure [dbo].[rpt_catalogo_productos_sproductos] @Id_empresa int as





select
(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombreempresa,
p.id_producto,
p.descripcion,
s.id_sproducto,
(select descripcion from tbl_productos x where x.id_empresa=p.id_empresa and
x.id_producto=s.id_sproducto) as nombre_sproducto,
s.cantidad,

(select precioa from tbl_productos x where x.id_empresa=p.id_empresa and
x.id_producto=s.id_sproducto) as precio,

(select  unid.descripcion from tbl_productos prod inner join  Tbl_Unidad_Medida unid
on prod.id_empresa=unid.id_empresa and
	prod.Id_medida1 =unid.Id_medida 
 where prod.id_empresa=@id_empresa and id_producto=s.id_sproducto)


  as unidad_medida


 from tbl_productos p, tbl_sproductos s, Tbl_Unidad_Medida UNID
 
where p.id_empresa=s.id_empresa and
p.id_producto=s.id_producto		and
P.Id_Empresa=UNID.Id_Empresa	AND
P.Id_medida =UNID.Id_medida		and
p.id_empresa=@id_empresa 
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_cheques_pendientes_generar
-- =============================
--EXEC [dbo].[rpt_cheques_pendientes_generar] 1
CREATE procedure [dbo].[rpt_cheques_pendientes_generar] @Id_empresa int as

--los cheques pendientes de emitir son de aquellas facturas que estan en una programacion de pagos
--autorizada

select 	(SELECT Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_empresa,
	det.Nit,
	p.nombre,
	det.Tipo_Cargo,
	det.Serie,
	det.Numero_Factura,
	(select descripcion from tbl_Cargos where id_empresa=det.id_empresa and nit=det.nit and tipo_cargo=det.tipo_cargo and Serie=det.serie and numero_Factura=det.numero_Factura) as descripcionfactura,
	det.Valor_Aplicado from
	 db_inventario_pfp.dbo.tbl_abonos abonos 
	 inner join db_inventario_pfp.dbo.tbl_det_abonos det
						on	abonos.id_empresa	=det.id_empresa and
							abonos.id_tipo_pago	=det.id_tipo_pago and
							abonos.numero_pago	=det.numero_pago 

	inner join tbl_proveedores p
									on 	det.Id_Empresa	=p.Id_Empresa	and
										det.nit		=p.nit
where 	det.Id_Empresa	=@Id_Empresa	and
		det.Anio		=''	and
		det.Mes			=''	and
		det.Id_Banco	=''	and
		det.Tipo		=''	and
		det.Numero		=''	and
		det.Valor_Aplicado	<>0	and
		abonos.status   =1
order by det.nit

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
