a.Id_Empresa,
(select nombre_empresa from empresas where id_empresa=@Id_empresa) as nombreempresa,
a.Id_Tipo_Pago,
a.Numero_Pago,
a.Fecha_Docto,
a.Descripcion,
a.Total_Abono,
a.Fecha_Abono,
a.Usuario,
a.Fecha_Operacion,
a.Status,
a.nit,
p.Nombre,
a.Id_banco,
a.Id_tipo,
a.Numero
	from tbl_abonos A, TBL_PROVEEDORES P
where 	a.Id_empresa	=p.Id_empresa	and
	a.Nit		=p.nit		and	
