-- =============================
-- SP: rpt_cobros
-- =============================

--select *from Tbl_cobros 
--SET DATEFORMAT DMY
--EXEC rpt_cobros 1,'01/01/2000','31/12/2020','COB', 1
CREATE  PROCEDURE [dbo].[rpt_cobros] @Id_empresa int,@fecha_inicial datetime,@fecha_final datetime,@Tipo_cobro char(3), @essumario int as
SET DATEFORMAT DMY
Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa


select 	@Nombre_empresa as nombreempresa,
	c.Id_empresa,
	c.Id_Tipo_cobro,
	c.Num_docto_cobro,
	(case when c.Numero_deposito ='' or  c.numero_deposito is null
		then '' 
		else C.Id_banco_deposito +'-'+C.Numero_deposito  end ) AS REFERENCIA,
	c.fecha_docto,
	ISNULL(c.NO_RECIBO,'') AS NO_RECIBO,
	c.Nit,
	p.nombre,
	
	c.Efectivo,
	c.numero_cheque,
	c.numero_tarjeta ,
	c.Numero_deposito,
	c.Valor_cheque as cheque,
	c.Valor_tarjeta,
	c.Valor_deposito as deposito,
	(c.efectivo+c.valor_cheque+c.valor_tarjeta+c.Valor_deposito ) as total_cobrado,
	c.descripcion,
	d.id_tipo,
	d.numero,
	d.valor_aplicado,
	D.Saldo_actual  from tbl_cobros	c	left join tbl_det_cobros d	
					on	c.id_empresa	=d.id_empresa	and
						c.id_tipo_cobro	=d.id_tipo_cobro	and
						c.num_docto_cobro=d.num_docto_cobro
						inner join tbl_proveedores p
					on	c.id_empresa	=p.id_empresa	and c.nit=p.nit
where 	c.Id_empresa=@Id_empresa	and
	datediff(day,c.fecha_docto,@fecha_final) between 0 	and datediff(day,@fecha_inicial,@fecha_final) and
	c.Id_tipo_cobro= case when @Tipo_cobro ='' then c.Id_tipo_cobro else @Tipo_cobro end and
	d.valor_aplicado>0
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
-- =============================
-- SP: rpt_cobros_por_mes_anual
-- =============================

--exec rpt_cobros_por_mes_anual 1,'2012','SEPTIEMBRE'
CREATE procedure [dbo].[rpt_cobros_por_mes_anual]
				 @id_empresa  int,
				 @año		  char(4),
				 @mes_final   char(10),
				 @tasa_cambio numeric(12,2) as	
				 
				 

DECLARE @MES INT 
set dateformat dmy
IF @mes_final='ENERO'
	SET @mes=1
	ELSE IF @mes_final='FEBRERO'
			SET @MES=2 
				ELSE IF @mes_final='MARZO'
						SET @MES=3
						ELSE IF @mes_final='ABRIL'
								SET @MES=4
								ELSE IF @mes_final='MAYO'
										SET @MES=5
										ELSE IF @mes_final='JUNIO'
												SET @MES=6
												ELSE IF @mes_final='JULIO'
														SET @MES=7
														ELSE IF @mes_final='AGOSTO'
																SET @MES=8
																ELSE IF @mes_final='SEPTIEMBRE'
																		SET @MES=9
																		ELSE IF @mes_final='OCTUBRE'
																				SET @MES=10
																				ELSE IF @mes_final='NOVIEMBRE'
																						SET @MES=11
																						ELSE IF @mes_final='DICIEMBRE'
																						SET @MES=12
																						ELSE SET @MES=01				  

declare @nombre_empresa varchar(100)
set @nombre_empresa = (select nombre_empresa from empresas  where id_empresa = @id_empresa)

select 
@nombre_empresa as nombre_empresa,
p.Nombre,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='01')/@tasa_cambio enero,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='02')/@tasa_cambio febrero,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='03')/@tasa_cambio marzo,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='04')/@tasa_cambio abril,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='05')/@tasa_cambio mayo,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='06')/@tasa_cambio junio,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='07')/@tasa_cambio julio,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='08')/@tasa_cambio agosto,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='09')/@tasa_cambio septiembre,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='10')/@tasa_cambio octubre,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='11')/@tasa_cambio noviembre,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and month(fecha_docto)='12')/@tasa_cambio diciembre,
(SELECT ISNULL(SUM(cc.total_cobro),0) from Tbl_cobros cc			 where cc.id_empresa = @id_empresa and cc.nit = c.nit and Id_tipo_cobro = 'COB' and year(fecha_docto) = @año and month(fecha_docto) <= @mes) as total
--SUM(c.total_cobro) as total
from Tbl_cobros c
inner join Tbl_Proveedores p
on  c.id_empresa = p.id_empresa			and
	c.nit		 = p.nit
where  c.Id
