-- =============================
create procedure rpt_comisiones_facturacion 	@Id_empresa	int,
						@Id_empleado 	char(10),
						@Fecha_Inicial	datetime,
						@Fecha_Final	datetime	 as

set dateformat dmy


SELECT *from vw_comisiones_facturacion
where id_empresa=@Id_empresa		and
	Id_empleado= (Case when @Id_Empleado='TOD' then Id_Empleado else @Id_Empleado end)	and
	datediff(day,Fecha_factura,@Fecha_Final) between 0 and
	datediff(day,@Fecha_inicial,@Fecha_Final)
	

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_compras_al_credito_por_contabilizar
-- =============================





--exec rpt_compras_al_credito_por_contabilizar 1
--SELECT *FROM TBL_PROVEEDORES

CREATE procedure [dbo].[rpt_compras_al_credito_por_contabilizar] @Id_Empresa	int as
	select 	(select nombre_empresa from empresas where id_empresa=@Id_empresa) AS NOMBRE_EMPRESA,
		c.Nit,
		p.nombre as nombre_proveedor,
		c.Id_Tipo,
		c.Serie, 
		c.Numero,
		c.Concepto,
		c.Fecha,
		ISNULL((Select Sum(d.Total)  as total_compra from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo		=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  as valor_factura,
		ISNULL( (Select Sum(d.Total)  as saldo_factura from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo	=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  as saldo_factura
	from tbl_cabecera_movimientos c,tbl_proveedores p
	where 	c.Id_Empresa	=	@Id_Empresa	and
		c.id_tipo	=	'COM'		AND
		C.credito_o_contado=	1		and
		c.Flag		=0			and
		c.id_empresa	=p.id_empresa		and
		c.nit		=p.nit			and

		ltrim(rtrim(cast(c.id_empresa as char)))+
		ltrim(rtrim(c.periodo))+
		ltrim(rtrim(c.id_bodega))+
		ltrim(rtrim(c.nit))+
		ltrim(rtrim(c.numero)) not in 
		(select distinct	ltrim(rtrim(cast(c.id_empresa as char)))+
				ltrim(rtrim(c.periodo))+
				ltrim(rtrim(c.id_bodega))+
				ltrim(rtrim(c.nit))+
				ltrim(rtrim(c.numero)) from  tbl_detalle_generacion_compra c)

union all
select (select nombre_empresa from empresas where id_empresa=@Id_empresa) AS NOMBRE_EMPRESA,
*from 
(select c.nit,
	p.nombre as nombre_proveedor,
	c.id_tipo,
	c.Serie,
	c.numero,
	c.concepto,
	c.fecha,

	(select sum(total_recepcion)
	from 	dbo.tbl_detalle_generacion_compra s
	where s.id_empresa	=c.id_empresa 	and
		s.periodo	=c.periodo	and
		s.id_bodega	=c.id_bodega	and
		s.nit		=c.nit		and
		s.numero	=c.numero) as valor_factura,
	(select sum(total_recepcion)
	from 	dbo.tbl_detalle_generacion_compra s
	where s.id_empresa	=c.id_empresa 	and
		s.periodo	=c.periodo	and
		s.id_bodega	=c.id_bodega	and
		s.nit		=c.nit		and
		s.numero	=c.numero) as saldo_factura

	from tbl_cabecera_movimientos c
			 INNER JOIN tbl_proveedores p
		ON 	c.id_empresa	=p.id_empresa		and
			c.nit		=p.nit			
			inner join tbl_detalle_generacion_compra d
		on 	c.id_empresa	=d.id_empresa	and
			c.periodo	=d.periodo	and
			c.id_bodega	=d.id_bodega	and
			c.nit		=d.nit		and
			c.numero	=d.numero	
	Where		c.Id_Empresa		=	@Id_empresa		and
			c.id_tipo		=	'COM'		AND
			c.credito_o_contado	=1			and
			c.flag			=0 ) x

--UPDATE TBL_CABECERA_MOVIMIENTOS SET FLAG=0 where id_empresa=1 and month(fecha)=1 and year(fecha)=2009 and ltiene_orden_compra=1 and flag=0 and id_tipo='COM'



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
