-- SP: rpt_configuracion_contable_vtas
-- =============================


--select *from db_contabilidad_pfp.dbo.cuentas t
CREATE procedure [dbo].[rpt_configuracion_contable_vtas] @Id_empresa int as
Declare @Nombre_empresa 	char(150)
SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
select 	@Nombre_empresa as nombre_empresa,
	c.Id_Producto,
	p.descripcion,
	c.Id_Cuenta_vta,
	isnull( (select t.descripcion from db_contabilidad_pfp.dbo.cuentas t where t.id_empresa=c.Id_empresa and t.id_cuenta=c.id_cuenta_vta),'CUENTA NO EXISTE'),
	c.id_depto_vta,
	c.Id_Cuenta_dev,
	isnull( (select t.descripcion from db_contabilidad_pfp.dbo.cuentas t where t.id_empresa=c.Id_empresa and t.id_cuenta=c.id_cuenta_dev),'CUENTA NO EXISTE'),
	c.id_depto_dev
 from tbl_productos_configuracion_contable c	RIGHT join tbl_productos p	
						on	c.Id_Empresa	=p.Id_empresa	and
							c.Id_Producto	=p.Id_producto
where p.Id_empresa=@ID_EMPRESA


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
