--exec [dbo].[rpt_contrasena_pago] 1, 24
CREATE procedure [dbo].[rpt_contrasena_pago] 	@Id_Empresa	int,
					@Id_contrasena	int as

			
SELECT     
co.Id_Empresa,
e.Nombre_Empresa,
co.Id_contrasena,
co.Nit,
p.Nombre,
co.Fecha_recepcion,
co.Descripcion,
co.Fecha_operacion,
co.Usuario,
co.status_contrasena,
ca.Tipo_Cargo,
ca.Serie,
ca.Numero_Factura,
ca.Descripcion as descripción_factura,
ca.Valor_Factura,
ca.Fecha_Tentativa_pago,
ca.Numero_Orden_compra,
ca.Fecha_Recepcion as fecha_recepcion_factura
FROM         dbo.Tbl_contrasenas co INNER JOIN
                      dbo.Tbl_Cargos  ca ON co.Id_Empresa = ca.Id_Empresa AND 
                      co.Id_contrasena = ca.Id_contrasena INNER JOIN
                      dbo.empresas e ON co.Id_Empresa = e.Id_Empresa AND 
                      ca.Id_Empresa = e.Id_Empresa INNER JOIN
                      dbo.Tbl_Proveedores p ON co.Id_Empresa = p.Id_Empresa AND 
                      co.Nit = p.Nit AND e.Id_Empresa = p.Id_Empresa
where 	co.Id_Empresa		=@Id_empresa	and
	co.Id_contrasena	=@Id_contrasena


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
