-- =============================




--select *from tbl_Cab_facturacion where CAJERO='DEVELOPER' AND LCORTE_CAJA=2 
--SET DATEFORMAT DMY
--EXEC rpt_cortes 1,'DEVELOPER','30/12/2005'
CREATE  procedure [dbo].[rpt_cortes] 	@Id_Empresa	int,
				@Id_Caja	int,
				@Cajero		char(100),
				@Fecha_Corte	datetime as


declare @dias 			int
declare @Nombre_empresa		char(100)
declare @fecha_inicial		datetime
declare @fecha_final		datetime
SELECT @fecha_inicial=MIN(FECHA_FACTURA) , @fecha_final=MAX(FECHA_FACTURA)  FROM TBL_CAB_FACTURACION
WHERE ID_EMPRESA=@Id_empresa AND LCORTE_CAJA=2	and fecha_factura<dateadd(day,1,@fecha_corte)

set @dias=datediff(day,@fecha_inicial,@fecha_final)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
select	@Nombre_Empresa as nombre_empresa,
	serie,
	id_tipo,
	numero,
	contado_o_credito,
	facturar_a,
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else subtotal end as subototal, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else descuento end as descuento, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else total end as total, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else efectivo end as efectivo, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else vuelto end as vuelto, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else Valor_cheque end as Valor_Cheque, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else Valor_Tarjeta end as Valor_Tarjeta, 
	case when status=3 and upper(facturar_a)='ANULADA' Then 0 else Valor_Anticipo end as anticipos_pagados, 
	'S'	AS ORIGEN
 from tbl_cab_Facturacion
where 	Id_Empresa		=@Id_Empresa		and
	Id_Caja			=@Id_caja		and
	upper(RTRIM(ltrim(Cajero)))	=upper(RTRIM(ltrim(@Cajero)))	and
	DATEDIFF(DAY,fecha_factura,@FECHA_CORTE) between 0 and @dias	and
	lcorte_caja			=2
union all
select	@Nombre_Empresa as nombre_empresa,
	serie,
	id_tipo,
	numero,
	contado_o_credito,
	facturar_a,
	subtotal,
	descuento,
	total,
	Efectivo,
	vuelto,
	Valor_Cheque,
	Valor_Tarjeta,
	Valor_Anticipo  as anticipos_pagados,
	'S'	AS ORIGEN
 from tbl_cab_notas_credito
where 	Id_Empresa		=@Id_Empresa		and
	Id_Caja			=@Id_caja		and
	upper(RTRIM(ltrim(Cajero)))	=upper(RTRIM(ltrim(@Cajero)))	and
	DATEDIFF(DAY,fecha_factura,@FECHA_CORTE) between 0 and @dias	and
	lcorte_caja			=2
order by serie,id_tipo,numero



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
