CREATE  procedure [dbo].[rpt_costo_ventas] 	@Id_Empresa		int,
					@Fecha_Inicial		datetime,
					@Fecha_Final		datetime,
					@Incluye_servicios	int as

Declare @Porcentaje_Iva			Numeric(12,2),
	@Porcentaje_Iva_anterior	Numeric(12,2),
	@apartirde			datetime,
	@Impuesto_gasolina		numeric(12,2)

select @impuesto_gasolina=impto_super from tbl_impuesto_carburantes where id_empresa=@Id_empresa

--seleccionando nombre de la empresa
Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa,
	@Porcentaje_iva=Porcentaje_iva,
	@Porcentaje_iva_anterior=porcentaje_iva_anterior FROM EMPRESAS where Id_Empresa=@Id_Empresa

select 	@Porcentaje_Iva		=isnull( (Porcentaje_Iva),0),
	@Porcentaje_Iva_Anterior=isnull((Porcentaje_Iva_Anterior),0),
	@apartirde		=apartirde from empresas where Id_Empresa=@Id_Empresa

set @porcentaje_iva=@porcentaje_iva/100
set @porcentaje_iva_anterior=@porcentaje_iva_Anterior/100

create table #tmp_Costovtas (	Id_Empresa	int,
				Id_Producto	char(15) COLLATE Modern_Spanish_CI_AS NOT NULL ,
				Cantidad	numeric(12,2),
				Costo		numeric(12,5),
				Costo_insumos	numeric(12,5),
				Precio		numeric(12,2),
				Precio_Insumos	numeric(12,2) )
--Insertando los movimientos que se captaron en el POS y que son no son gasolina y q descuento es por porcentaje
insert #tmp_Costovtas
select 	d.Id_Empresa,
	d.Id_Producto,
	Sum(d.Cantidad) 	as cantidad,
	Sum(d.cantidad*d.Costo)		as costo,
	0,
	Sum(case when c.fecha_factura>=@apartirde
			then Round( d.Precio_Descuento/(@porcentaje_iva+1),2)*d.cantidad
			else Round( d.Precio_Descuento/(1+@Porcentaje_Iva_Anterior),2)*cantidad end) as precio_siva,
	SUM(d.precio_descuento)/SUM(d.cantidad) as precio
from tbl_det_Facturacion d	inner join tbl_cab_facturacion c
								on 	c.Id_Empresa	=d.Id_Empresa	and
									c.Id_Caja	=d.Id_Caja	and
									c.Autorizacion	=d.Autorizacion	and
									c.Serie		=d.Serie	and
									c.Id_tipo	=d.Id_tipo	and
									c.numero	=d.numero
where	c.Id_empresa		=@Id_Empresa	and
	datediff(day,c.fecha_factura,@Fecha_Final)		between 	0 and  datediff(day,@Fecha_Inicial,@Fecha_Final) AND
	d.rebaja_existencias	=1		and
	d.Id_Producto		<>'GAS'		and
	c.status			<>3			/*and
   ((SELECT     SUM(Cantidad * Precio) - SUM(Cantidad * Precio_Descuento) AS Expr1
             FROM         dbo.Tbl_Det_Facturacion AS j
             WHERE     (Id_Empresa		= c.Id_Empresa)		AND
						 (Id_Caja		= c.Id_Caja)		AND 
                         (Autorizacion	= c.Autorizacion)	AND 
                         (Serie			= c.Serie)			AND
                         (Id_Tipo		= c.Id_Tipo)		AND 
                         (Numero		= c.Numero)) = c.Descuento)*/
group by d.id_empresa,d.id_producto








/*insert #tmp_Costovtas
select 	d.Id_Empresa,
	d.Id_Producto,
	Sum(d.Cantidad*-1) 	as cantidad,
	Sum((d.cantidad*-1)*d.Costo)		as costo,
	0,
	Sum(case when c.fecha_factura>=@apartirde
			then Round( d.Precio_Descuento/(@porcentaje_iva+1),2)*d.cantidad
			else Round( d.Precio_Descuento/(1+@Porcentaje_Iva_Anterior),2)*cantidad end) as precio_siva,
	0	
from tbl_det_NOTAS_CREDITO d	inner join tbl_cab_NOTAS_CREDITO c
								on 	c.Id_Empresa	=d.Id_Empresa	and
									c.Id_Caja	=d.Id_Caja	and
									c.Autorizacion	=d.Autorizacion	and
									c.Serie		=d.Serie	and
									c.Id_tipo	=d.Id_tipo	and
									c.numero	=d.numero
where	c.Id_empresa		=@Id_Empresa	and
