-- SP: rpt_costo_ventas_servicios_detallado
-- =============================



/*
SELECT *FROM TBL_ORDEN_SERVICIO WHERE ID_ORDEN=546 OR ID_ORDEN=547
select *from tbl_orden_servicio_detalle where id_orden=546
-- 
SELECT *FROM tbl_orden_servicio_detalle_integracion where id_orden=546 and LINEA=1
*/
--set dateformat dmy
--exec rpt_costo_ventas_servicios_detallado 1,'14/09/2006','14/09/2006',0,'DETALLADO'
CREATE procedure rpt_costo_ventas_servicios_detallado 	@Id_Empresa 	int,
							@Fecha_inicial	datetime,
							@Fecha_final	datetime,
							@Id_orden	int,
							@Tipo_reporte	char(10) as
--@Tipo_reporte="SUMARIO","DETALLADO"

declare @Nombre_empresa char(150),@Porcentaje_iva numeric(12,2),@Porcentaje_iva_anterior numeric(12,2),@apartirde datetime
set dateformat dmy
select 	@Nombre_empresa=nombre_empresa,
	@porcentaje_iva=Porcentaje_iva,
	@porcentaje_iva_anterior=Porcentaje_iva_anterior,
	@apartirde	=apartirde from empresas where id_empresa=@Id_Empresa
set @porcentaje_iva		=1+@porcentaje_iva/100
set @porcentaje_iva_anterior	=1+@porcentaje_iva_anterior/100

select f.Id_Empresa, --SELECCIONANDO TODOS LOS SERVICIOS
	@Nombre_empresa as nombre_empresa,
	f.Id_Caja,
	f.Serie,
	f.Id_Tipo,
	f.numero,
	f.nit,
	f.facturar_a,
	fecha_factura,
	o.Id_Orden,
	d.linea,
	0	as linea_det,
	d.Id_servicio,
	d.cantidad,
	d.costo-	isnull( (SELECT SUM(ISNULL(I.CANTIDAD*I.COSTO,0)) FROM TBL_ORDEN_SERVICIO_DETALLE_INTEGRACION I WHERE I.ID_EMPRESA=D.ID_EMPRESA AND ID_ORDEN=D.ID_ORDEN AND D.LINEA=I.LINEA AND Se_cobra='N'),0) as costo_servicio,
	'S'				as se_cobra,
	d.Id_Servicio	 		as id_producto,
	d.descripcion 			as descripcion_producto,
	0				as costo_producto,
	(d.cantidad*d.costo)-	isnull( (SELECT SUM(ISNULL(I.CANTIDAD*I.COSTO,0)) FROM TBL_ORDEN_SERVICIO_DETALLE_INTEGRACION I WHERE I.ID_EMPRESA=D.ID_EMPRESA AND ID_ORDEN=D.ID_ORDEN AND D.LINEA=I.LINEA AND Se_cobra='N'),0) as costo_total,
	(d.cantidad*d.precio_descuento)/(case when f.fecha_factura>@apartirde then @porcentaje_iva else @porcentaje_iva_anterior end)  
        - isnull( (SELECT SUM(ISNULL(I.CANTIDAD*I.COSTO,0)) FROM TBL_ORDEN_SERVICIO_DETALLE_INTEGRACION I WHERE I.ID_EMPRESA=D.ID_EMPRESA AND ID_ORDEN=D.ID_ORDEN AND D.LINEA=I.LINEA AND Se_cobra='N'),0) AS precio_total
 from tbl_cab_facturacion f,tbl_orden_servicio o,tbl_orden_servicio_detalle d
where f.Id_Empresa=@Id_Empresa	and
	datediff(day,f.fecha_factura,@fecha_final) between 0	and datediff(day,@fecha_inicial,@fecha_final) and
	f.serie		=o.serie			and
	f.id_tipo	=o.tipo				and
	f.numero	=o.numero			and
	o.id_empresa	=d.id_empresa			and
	o.id_orden	=d.id_orden			and
	o.id_orden	=case when @Id_Orden=0
				Then o.id_orden
				Else @Id_orden end	
union all
select f.Id_Empresa, --SELECCIONANDO TODOS LOS INSUMOS
	@Nombre_empresa as nombre_empresa,
	f.Id_Caja,
	f.Serie,
	f.Id_Tipo,
	f.numero,
	f.nit,
	f.facturar_a,
	fecha_factura,
	o.Id_Orden,
	d.linea,
	i.linea_det,
	d.Id_servicio,
	i.cantidad,
	0 as costo_servicio,
	i.se_cobra,
	i.id_producto,
	i.descripcion 			as descripcion_producto,
	i.costo				as costo_producto,
	(i.cantidad*i.costo) 		as costo_total,
	(CASE WHEN i.se_cobra='S'
		THEN (i.cantidad*i.precio_descuento)/(case when f.fecha_factura>@apartirde then @porcentaje_iva else @porcentaje_iva_anterior end)	
		ELSE (i.cantidad*i.costo) END) 		as precio_total
	from tbl_cab_facturacion f,tbl_orden_servicio o,tbl_orden_servicio_detalle d,tbl_orden_servicio_detalle_integracion i
where f.Id_Empresa=@Id_Empresa	and
	datediff(day,f.fecha_factura,@fecha_final) between 0	and datediff(day,@fecha_inicial,@fecha_final) and
	f.serie		=o.serie	and
	f.id_tipo	=o.tipo		and
	f.numero	=o.numero	and
	o.id_empresa	=d.id_empresa	and
	o.id_orden	=d.id_orden	and
	d.id_empresa	=i.id_empresa	and
	d.id_orden	=i.id_orden	and
	d.Linea		=i.linea	and
	o.id_orden	=case when @Id_Orden=0
				Then o.id_orden
				Else @Id_orden end	
order by 
