--exec rpt_cotizacion_clientes 1,2
CREATE  procedure [dbo].[rpt_cotizacion_clientes] @Id_empresa int,@Id_cotizacion int as
select *,
case when c.estado=1
	then 'ABIERTA'
	else 'DESPACHADA' END AS ESTADOCOTIZACION,
CASE WHEN C.CREDITO_O_CONTADO=1
		THEN 'CREDITO'
		ELSE 'CONTADO' END AS FORMACOBRO,
		V.Nombre 	 from dbo.Tbl_cotizacion_clientes c,dbo.Tbl_cotizacion_clientes_detalle d,
dbo.Tbl_Proveedores p,dbo.empresas E,dbo.Tbl_Productos prod,
dbo.Tbl_Vendedores V
where C.Id_Empresa =V.Id_Empresa AND
C.id_vendedor =V.Id_Empleado  AND 
C.Id_Empresa=E.Id_Empresa AND
c.Id_Empresa=d.Id_Empresa and
c.Id_Cotizacion =d.Id_Cotizacion and
c.Id_Empresa=p.Id_Empresa and
c.Nit=p.Nit and
c.Id_Cotizacion =@Id_cotizacion and
d.Id_Empresa=prod.Id_Empresa and
d.Id_Producto =prod.Id_Producto 

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
-- =============================
-- SP: rpt_cotizacion_utilidad
-- =============================
--exec rpt_cotizacion_utilidad 1,3
CREATE procedure rpt_cotizacion_utilidad  @Id_empresa int,
@Id_cotizacion int as 


select *,
(select top 1 precio  from Tbl_Prod_Proveedores where id_empresa=c.Id_Empresa  and Id_Producto=d.Id_Producto ) as precio_compra,
(select nombre from dbo.Tbl_Proveedores where Id_Empresa=c.Id_Empresa  and Nit=c.Nit ) as nombreproveedor,
(select descripcion from tbl_productos p where p.Id_Empresa=c.Id_empresa and p.Id_Producto =d.Id_Producto ) as descripcionproducto
from dbo.Tbl_cotizacion_clientes c,dbo.Tbl_cotizacion_clientes_detalle d
where c.Id_Empresa=d.Id_Empresa and
c.Id_Cotizacion =d.Id_Cotizacion  and
c.Id_Cotizacion =@Id_cotizacion 


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
