CREATE procedure RPT_CUENTAS_POR_COBRAR @Id_Empresa int,@Fecha_inicial datetime,@fecha_final datetime as
			
declare @nombre_empresa char (150)

select @nombre_empresa=nombre_empresa from EMPRESAS where id_empresa = @Id_empresa

SELECT 	@NOMBRE_EMPRESA as NOMBRE_EMPRESA,
	C.ID_EMPRESA,TIPO_DOCTO,C.NUMERO_DOCTO,C.FECHA_DOCTO,P.NIT,P.NOMBRE 
	FROM TBL_CUENTAS_POR_COBRAR c, TBL_PROVEEDORES P
	where 	C.ID_EMPRESA = P.ID_EMPRESA AND

DATEDIFF(DAY,C.FECHA_DOCTO,@FECHA_FINAL) BETWEEN 0  AND DATEDIFF(DAY,@FECHA_INICIAL,@FECHA_FINAL)
ORDER BY C.FECHA_DOCTO

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
