CREATE  procedure [dbo].[rpt_despacho_envio]  @Id_empresa int,@Numero int as

select e.*,
(select cantidad_entregada from tbl_solicitud_despacho_cliente_detalle det where id_empresa=e.id_empresa and det.id_solicitud_despacho=e.id_solicitud_despacho and det.id_producto=e.id_producto) as cantidad_entregada,
(select cantidad from tbl_solicitud_despacho_cliente_detalle det where id_empresa=e.id_empresa and det.id_solicitud_despacho=e.id_solicitud_despacho and det.id_producto=e.id_producto) as cantidad_solicitud_despacho
 from dbo.Vw_despacho_envio e
where e.Id_empresa=@Id_empresa  and e.Numero =@Numero



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
