CREATE procedure rpt_Det_facturacion @Id_Empresa int as

Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa

select @nombre_empresa as nombreempresa,
 *from tbl_Det_facturacion where Id_Empresa=@Id_Empresa


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
-- =============================
-- SP: rpt_detalle_facturas
-- =============================
--set dateformat dmy
-- exec rpt_detalle_facturas 1,'01/02/2019','01/02/2019'

CREATE procedure rpt_detalle_facturas	@Id_empresa int,
										@Fecha_Inicial datetime,
										@Fecha_Final   datetime as


set dateformat dmy



select  empre.nombre_empresa,
		c.id_caja,
		c.autorizacion,
		c.serie+ltrim(rtrim(cast(c.numero as char))) as factura,
		c.nit,
		c.facturar_a ,
		case when c.contado_o_credito=2
				then 'Contado'
				Else 'Credito' end as Forma_pago,
		c.fecha_factura,
		d.id_producto,
		d.descripcion_corta,
		d.cantidad,
		d.precio,
		d.total_linea,
		C.STATUS AS ESTADO

				 from tbl_cab_facturacion c inner join tbl_det_facturacion d
				 on c.id_empresa=d.id_empresa and
					c.autorizacion=d.autorizacion and
					c.serie=d.serie and
					c.numero=d.numero
											inner join empresas empre
				on c.id_empresa=empre.id_empresa 
		where c.id_empresa=@Id_Empresa and
				datediff( day , c.fecha_factura, @Fecha_Final) 
				between 0 and datediff(day,@Fecha_inicial,@Fecha_Final)
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_detalle_orden_servicio_cliente
-- =============================
--exec rpt_detalle_orden_servicio_cliente 1,'660369-6'
CREATE PROCEDURE rpt_detalle_orden_servicio_cliente		@Id_empresa int,
														@nit		char(20) as
		
		
select	ltrim(rtrim(cast(o.id_empresa as CHAR)))+' '+(select nombre_empresa from dbo.empresas where Id_Empresa=o.id_empresa) as empresa,
		o.nit,
		o.id_orden,
		o.fecha,
		o.facturar_a,
		i.id_bodega+(select nombre from Tbl_bodega b where b.Id_Empresa=i.id_empresa and b.Id_Bodega =i.Id_Bodega ) as bodega,
		i.id_producto+' '+ (select p.descripcion from Tbl_Productos p where p.Id_Empresa=o.id_empresa and p.Id_Producto=i.Id_Producto ) as producto,
		
		i.Cantidad,
		i.Precio_Descuento,
		i.Precio,
		i.total_linea
		 from tbl_orden_servicio o, Tbl_Orden_Servicio_Detalle d, Tbl_Orden_Servicio_Detalle_Integracion i
where	o.Id_Empresa=d.Id_Empresa	and o.Id_Orden=d.Id_Orden and
		d.id_empresa=i.Id_Empresa	and
		d.Id_Orden=i.Id_Orden		and
		d.linea=i.linea				and
		o.Nit  =case when @nit='' then o.Nit else @nit end  and
		o.Numero=0 and serie='' and tipo=''
union all
select	ltrim(rtrim(cast(o.id_empresa as CHAR)))+' '+(select nombre_empresa from dbo.empresas where Id_Empresa=o.id_empresa) as empresa,
		o.Nit,
		o.id_orden,
		o.Fecha,
		o.facturar_a,
		' ' as bodega,
		d.id_servicio+' '+ (select p.descripcion from Tbl_Productos p where p.Id_Empresa=d.id_empresa and p.Id_Producto=d.Id_servicio ) as producto,
		d.Cantidad,
		d.Precio_Descuento,
		d.Precio,
		d.total_linea
		 from tbl_orden_servicio o, Tbl_Orden_Servicio_Detalle d
where	o.Id_Empresa=d.Id_Empresa	and o.Id_Orden=d.Id_Orden	and
		o.Nit  =case when @nit='' then o.Nit else @nit end		and
		d.Id_Servicio<>'DESPACHO' and
		o.Numero=0 and serie='' and tipo=''
order by o.id_orden
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: rpt_entradas_salidas_inv
-- =============================


--select *from tbl_productos where id_producto='009'
--select *from tbl_unidad_medida where id_empresa=2
--set dateformat dmy
--EXEC RPT_entradas_salidas_inv 1,'31/12/2016',1,'',0
CREATE  procedure [dbo].[rpt_entradas_salidas_inv] @Id_Empresa	int,@Fecha_Fin datetime,@AGRUPADO INT,@tipo char(10),@muestra_decimales int  as
Declare @Nombre_Empresa char(150),
	@Fecha_Ini datetime,
	@Fecha_periodo_anterior datetime,
	@Periodo_anterior	char(7)
set dateformat dmy
set @Fecha_Ini=cast( '01'+'/'+cast(month(@Fecha_Fin)as char(2))+'/'+cast(year(@Fecha_Fin) as char(4)) as datetime)
--al quitarle un dia a fecha ini fecha perioro anterior tiene el ultimo dia del mes anterior
set @Fecha_periodo_anterior=dateadd(day,-1,@fecha_ini)
set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_periodo_anterior) as char)))))+ltrim(rtrim(str(month(@fecha_periodo_anterior))))+'/'+cast( year(@fecha_periodo_anterior) as char)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
set dateformat dmy
select	nombre_empresa,
		ID_BODEGA,
		ARTICULO,
		DEPTO,
		LINEA,
		TIPO,
		ID_PRODUCTO,
		medida,
		DESCRIPCION,
		SUM(INICIAL) AS INICIAL,
		SUM(ENTRADAS) AS ENTRADAS,
		SUM(SALIDAS)  AS SALIDAS from 
( 

SELECT	@Nombre_empresa	as nombre_empresa,
		e.Id_Bodega+(select nombre from tbl_bodega b where b.Id_Empresa=@Id_Empresa and b.Id_Bodega =e.id_bodega) 		  as id_bodega, 
		p.Id_Articulo	+' '+ (select a.descripcion from Tbl_articulos a where a.Id_Empresa=p.Id_Empresa and a.Id_Articulo =p.Id_Articulo) as articulo,
		p.Id_Depto		+' '+ (select nombre from Tbl_departamentos d where d.Id_Empresa=p.id_empresa and d.id_depto=p.id_depto) as depto,
		p.Id_Linea      +' '+ (select nombre_linea from Tbl_Linea l where l.Id_Empresa=p.Id_Empresa and l.Id_Depto=p.id_depto and l.Id_Linea=p.Id_Linea) as linea,
		p.tipo,
		p.id_producto,
		(select m.descripcion from Tbl_Unidad_Medida m 
		where m.Id_Empresa=@Id_Empresa  and m.Id_medida =p.Id_medida ) as medida,
		p.descripcion,
		SUM(e.EXISTENCIA)	as inicial,
		0					as entradas,
		0					as salidas
 FROM TBL_EXISTENCIA	e INNER JOIN TBL_Productos	p
				on 	e.id_empresa	=p.id_empresa	and
					e.id_producto	=p.id_producto
 WHERE 	e.Id_Empresa	=@Id_empresa	and
		e.PERIODO=@PERIODO_ANTERIOR		AND
		E.EXISTENCIA	<>0				AND
		P.Tipo			= (CASE WHEN @TIPO='' THEN P.Tipo ELSE @tipo END)
group by p.id_empresa,e.id_bodega,p.id_articulo,p.id_depto,P.Id_Linea,p.tipo,p.id_producto,p.descripcion,p.id_medida
union all
select 
	@Nombre_Empresa as nombre_empresa,
	LTRIM(RTRIM(d.id_bodega_movimiento))+' ' +(select b.nombre from tbl_bodega b where b.Id_Empresa=@Id_Empresa and b.Id_Bodega =d.id_bodega_movimiento ) as id_bodega,
	p.Id_Articulo	+ ' '+(select a.descripcion from Tbl_articulos a where a.Id_Empresa=p.Id_Empresa and a.Id_Articulo =p.Id_Articulo) as articulo,
	p.Id_Depto		+ ' '+(select nombre from Tbl_departamentos d where d.Id_Empresa=p.id_empresa and d.id_depto=p.id_depto) as depto,
	p.Id_Linea      + ' '+(select nombre_linea from Tbl_Linea l where l.Id_Empresa=p.Id_Empresa and l.Id_Depto=p.id_depto and l.Id_Linea=p.Id_Linea) as linea,
	p.tipo,
	isnull(d.Id_Producto,'') as id_producto,
	(select descripcion from Tbl_Unidad_Medida  m where m.Id_Empresa=@Id_Empresa  and m.Id_medida =p.Id_medida ) as medida,
	p.Descripcion,
	0							as inicial,
	sum(d.Cantidad)				as entradas,
	0							as salidas
from tbl_detalle_movimientos d	left join	tbl_cabecera_movimientos c
						on	d.Id_Empresa	=c.Id_Empresa	and
							d.Periodo		=c.Periodo	and
							d.Id_Bodega		=c.Id_Bodega	and
							d.nit			=c.nit		and
							d.Id_Tipo		=c.Id_Tipo	and
							d.Numero		=c.Numero
								inner join	tbl_tipos_inv		t
							on	d.Id_Empresa	=t.Id_Empresa	and
								d.Id_Tipo		=t.Id_Tipo
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.
