-- SP: rpt_entradas_salidas_inv_detallado
-- =============================


--set dateformat dmy
--EXEC RPT_entradas_salidas_inv_DETALLADO 2,'10/09/2015','13/09/2015',0,'MATERIA P.',1
CREATE   procedure [dbo].[rpt_entradas_salidas_inv_detallado] @Id_Empresa	int,@Fecha_Inicial datetime, @Fecha_Fin datetime,@AGRUPADO INT,@tipo char(10),@muestra_decimales int  as
Declare @Nombre_Empresa char(150),
	@Fecha_ini				datetime,
	@Fecha_periodo_anterior datetime,
	@Periodo_anterior	char(7)
set dateformat dmy
set @Fecha_Ini=cast( '01'+'/'+cast(month(@Fecha_Fin)as char(2))+'/'+cast(year(@Fecha_Fin) as char(4)) as datetime)

--al quitarle un dia a fecha ini fecha perioro anterior tiene el ultimo dia del mes anterior
set @Fecha_periodo_anterior=dateadd(day,-1,@fecha_ini)
set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_periodo_anterior) as char)))))+ltrim(rtrim(str(month(@fecha_periodo_anterior))))+'/'+cast( year(@fecha_periodo_anterior) as char)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
set dateformat dmy
select	nombre_empresa,
		ID_BODEGA,
		ARTICULO,
		DEPTO,
		LINEA,
		ID_PRODUCTO,
		isnull( (select top 1 id_alterno from Tbl_Prod_Proveedores v where v.Id_Empresa=@Id_Empresa and v.Id_Producto =x.Id_Producto ),'') as alterno,
		DESCRIPCION,
		SUM(INICIAL) AS INICIAL,
		SUM(COMPRAS) AS COMPRAS,
		SUM(OTRAS_ENTRADAS)  AS OTRAS_ENTRADAS,
		SUM(VENTAS)			 AS VENTAS,
		SUM(OTRAS_SALIDAS)	 AS OTRAS_SALIDAS from 
( 
SELECT	@Nombre_empresa	as nombre_empresa,
		e.Id_Bodega  as id_bodega, 
		p.Id_Articulo	+' '+ (select a.descripcion from Tbl_articulos a where a.Id_Empresa=p.Id_Empresa and a.Id_Articulo =p.Id_Articulo) as articulo,
		p.Id_Depto		+' '+ (select nombre from Tbl_departamentos d where d.Id_Empresa=p.id_empresa and d.id_depto=p.id_depto) as depto,
		p.Id_Linea      +' '+ (select nombre_linea from Tbl_Linea l where l.Id_Empresa=p.Id_Empresa and l.Id_Depto=p.id_depto and l.Id_Linea=p.Id_Linea) as linea,
		p.id_producto,
		p.descripcion,
		SUM(e.EXISTENCIA) + dbo.fn_devuelve_total_movimiento( @Id_Empresa ,@fecha_ini,@Fecha_inicial-1 ,p.id_producto )	as inicial,
		0					as inicial_con_movimientos,
		0					as compras,
		0					as otras_entradas,
		0					as ventas,
		0					as otras_salidas
 FROM TBL_EXISTENCIA	e INNER JOIN TBL_Productos	p
				on 	e.id_empresa	=p.id_empresa	and
					e.id_producto	=p.id_producto
 WHERE 	e.Id_Empresa	=@Id_empresa	and
		e.PERIODO=@PERIODO_ANTERIOR	AND
		E.EXISTENCIA	<>0			AND
		P.Tipo			= (CASE WHEN @TIPO='' THEN P.Tipo ELSE @tipo END)

group by p.id_empresa,e.id_bodega,p.id_articulo,p.id_depto,P.Id_Linea,p.id_producto,p.descripcion
union all
select 
	@Nombre_Empresa as nombre_empresa,
	d.id_bodega_movimiento ,
	p.Id_Articulo	+ ' '+(select a.descripcion from Tbl_articulos a where a.Id_Empresa=p.Id_Empresa and a.Id_Articulo =p.Id_Articulo) as articulo,
	p.Id_Depto		+ ' '+(select nombre from Tbl_departamentos d where d.Id_Empresa=p.id_empresa and d.id_depto=p.id_depto) as depto,
	p.Id_Linea      + ' '+(select nombre_linea from Tbl_Linea l where l.Id_Empresa=p.Id_Empresa and l.Id_Depto=p.id_depto and l.Id_Linea=p.Id_Linea) as linea,
	isnull(d.Id_Producto,'') as id_producto,
	p.Descripcion,
	0							as inicial,
	0							as inicial_con_movimientos,
	sum(d.Cantidad)				as compras,
	0							AS otras_entradas,
	0							as ventas,
	0							as otras_salidas 
from tbl_detalle_movimientos d	left join	tbl_cabecera_movimientos c
						on	d.Id_Empresa	=c.Id_Empresa	and
							d.Periodo		=c.Periodo	and
							d.Id_Bodega		=c.Id_Bodega	and
							d.nit			=c.nit		and
							d.Id_Tipo		=c.Id_Tipo	and
							d.Numero		=c.Numero
								inner join	tbl_tipos_inv		t
							on	d.Id_Empresa	=t.Id_Empresa	and
								d.Id_Tipo		=t.Id_Tipo
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.Id_empresa	and
								d.Id_Producto	=p.Id_producto
							inne
-- =============================
-- SP: rpt_estadistica_ventas
-- =============================





--select *from tbl_articulos
--select *from tbl_productos
--exec rpt_estadistica_ventas 1
CREATE procedure rpt_estadistica_ventas @Id_empresa int as
Declare @porcentaje_iva	numeric(12,2),@porcentaje_iva_anterior numeric(12,2), @apartirde datetime 

select 	@Porcentaje_Iva		=isnull( (Porcentaje_Iva),0),
	@Porcentaje_Iva_Anterior=isnull((Porcentaje_Iva_Anterior),0),
	@apartirde		=apartirde from empresas where Id_Empresa=@Id_Empresa

set @porcentaje_iva=@porcentaje_iva/100
set @porcentaje_iva_anterior=@porcentaje_iva_Anterior/100

create table #temporal (anio char(4),nit char(15),nombre char(80),id_producto char(15),articulo char(80),cantidad int,total_Venta numeric(12,2))
insert #temporal
SELECT  year(c.fecha) as anio,
	c.nit,
	p.nombre,
	i.id_producto,
	a.descripcion,
	sum(i.cantidad),
	sum( case when c.fecha > @apartirde
		then   i.total_linea_descuento/(1+@porcentaje_iva) 
		else   i.total_linea_descuento/(1+@porcentaje_iva_anterior) end )
	 FROM TBL_ORDEN_SERVICIO c inner join tbl_orden_servicio_detalle_integracion i
					on 	c.id_empresa	=i.id_empresa	and
						c.id_orden	=i.id_orden
						inner join tbl_proveedores 	p
					on	c.id_empresa	=p.id_empresa	and
						c.nit		=p.nit
						inner join tbl_productos	prod on
						i.id_empresa	=prod.id_empresa	and
						i.id_producto	=prod.id_producto
						inner join tbl_articulos	a
						on 	prod.id_empresa	=a.id_empresa	and
							prod.id_articulo=a.id_articulo
where c.id_empresa=@Id_empresa	and numero<>0 and serie<>''
group by year(c.fecha),c.nit,p.nombre,a.descripcion,i.id_producto
insert #temporal
select 	year(c.fecha_factura) as anio,
	c.nit,
	p.nombre,
	d.id_producto,
	a.descripcion,
	sum(d.cantidad),
	sum( case when c.fecha_factura>@apartirde
		then  	(d.cantidad*d.precio_descuento)/(1+@porcentaje_iva)
		else      (d.cantidad*d.precio_descuento)/(1+@porcentaje_iva_anterior) end) from tbl_cab_facturacion c inner join tbl_det_facturacion d
					on	c.Id_Empresa	=d.Id_Empresa	and
						c.Id_Caja	=d.Id_Caja	and
						c.Autorizacion	=d.Autorizacion	and
						c.serie		=d.serie	and
						c.numero	=d.numero
						inner join tbl_proveedores	p
					on	c.id_empresa	=p.id_empresa	and
						c.nit		=p.nit
						inner join tbl_productos	prod
					on	d.id_empresa	=prod.id_empresa	and
						d.id_producto	=prod.id_producto
						inner join tbl_articulos	a
					on	prod.id_empresa	=a.id_empresa	and
						prod.id_articulo	=a.id_articulo
where c.id_empresa=@Id_empresa	and d.rebaja_existencias=1			
group by year(c.fecha_factura),c.nit,p.nombre,a.descripcion,d.id_producto

select anio,ltrim(rtrim(nit))+' '+nombre as cliente,articulo,id_producto,cantidad,total_venta from #temporal

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: rpt_estado_cuenta_proveedor
-- =============================


--exec rpt_Estado_cuenta_proveedor 1,'813099-K','Face63txw15001'150000008199,'FAC'
CREATE PROCEDURE [dbo].[rpt_estado_cuenta_proveedor]  	@Id_empresa int,
						@Nit		char(20),
						@Serie      char(15),
						@Numero_factura	numeric(15),
						@Tipo_cargo	char(3) as

/*set @Id_Empresa	=1
set @Nit	='660369-6'
set @numero_factura=25
set @tipo_cargo	='FAC'*/


SELECT 	c.ID_EMPRESA,
	(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@Id_Empresa) as nombre_empresa,
	c.NIT,
	p.nombre as nombre_proveedor,
	c.TIPO_CARGO AS TIPO_CARGO,
	C.SERIE      AS SERIE,
	LTRIM(RTRIM(CAST(c.NUMERO_FACTURA  AS CHAR(15)))) AS DOCUMENTO,
	c.DESCRIPCION,
	c.FECHA_DOCUMENTO AS FECHA_DOCUMENTO,
	0	AS CARGO,
	c.VALOR_FACTURA	AS ABONO
FROM TBL_cARGOS c inner join tbl_proveedores p	on 	c.id_empresa=p.id_empresa	and
							c.nit		=p.nit

where c.id_empresa=@id_empresa and c.nit=@nit and c.Tipo_cargo=@tipo_cargo and c.serie=@serie and c.numero_factura=@numero_factura
UNION ALL


SELECT 	D.ID_EMPRESA,
	(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@Id_Empresa) as nombre_empresa,
	D.NIT,
	p.nombre as nombre_proveedor,
	'' AS TIPO_CARGO,
	'' AS SERIE,
	D.ID_TIPO_PAGO+'-'+LTRIM(RTRIM(CAST(D.NUMERO_PAGO  AS CHAR(15)))) AS DOCUMENTO,
	'Pago Factura segun documento'+d.tipo+d.numero,
	A.FECHA_DOCTO	AS FECHA_DOCUMENTO,
	D.Valor_Aplicado as CARGO,
	0		AS ABONO
	FROM TBL_dET_ABONOS D	LEFT JOIN TBL_ABONOS	A
				ON 	D.ID_EMPRESA	=A.ID_EMPRESA	AND
					D.ID_TIPO_PAGO	=A.ID_TIPO_PAGO	AND
					D.NUMERO_PAGO	=A.NUMERO_PAGO
				inner join tbl_proveedores p	on 	d.id_empresa=p.id_empresa	and
									d.nit		=p.nit
WHERE 	D.ID_EMPRESA	=@ID_EMPRESA		AND
	D.NIT		=@NIT			AND
	D.TIPO_CARGO	=@TIPO_CARGO		AND
	D.SERIE			=@Serie				and
	D.NUMERO_FACTURA=@NUMERO_FACTURA	AND
	D.VALOR_APLICADO<>0
ORDER BY 7

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
-- =============================
-- SP: rpt_estado_cuenta_proveedor_general
-- =============================

--set dateformat dmy
--exec rpt_Estado_cuenta_proveedor_general 1,'660369-6','01/10/2015','20/11/2016'
CREATE PROCEDURE [dbo].[rpt_estado_cuenta_proveedor_general]  	@Id_empresa int,
							@Nit		char(20),
							@Fecha_inicial	datetime,
							@Fecha_final	datetime as	
Declare @Saldo_inicial 			numeric(12,2)

Set @Saldo_inicial=isnull((select sum(valor_factura*-1) from tbl_cargos 
where id_empresa=@Id_empresa and nit=@nit and
fecha_documento<@fecha_inicial),0)
+
isnull((select sum(d.valor_aplicado)FROM TBL_dET_ABONOS D	LEFT JOIN TBL_ABONOS	A
				ON 	D.ID_EMPRESA	=A.ID_EMPRESA	AND
					D.ID_TIPO_PAGO	=A.ID_TIPO_PAGO	AND
					D.NUMERO_PAGO	=A.NUMERO_PAGO
Where 	A.id_Empresa=@Id_Empresa	and 
	d.nit=@nit 			and 
	a.fecha_docto<@fecha_inicial),0)		


Select 	@Id_Empresa as id_Empresa,
	(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@Id_Empresa) as nombre_empresa,
	@Nit	as nit,
	(select nombre from tbl_proveedores where id_empresa=@Id_empresa and nit=@nit) as nombre_proveedor,
	'' as documento, 
	'Saldo Inicial ' as descripcion,
	@fecha_inicial   as FECHA_DOCUMENTO,
	(Case when @Saldo_inicial>0 then abs(@Saldo_inicial) else 0 end) as cargo,
	(case when @Saldo_inicial<0 then abs(@Saldo_inicial) else 0 end) as abono
union all
SELECT 	c.ID_EMPRESA,
	(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@Id_Empresa) as nombre_empresa,
	c.NIT,
	p.nombre as nombre_proveedor,
	c.TIPO_CARGO+'-'+LTRIM(RTRIM(c.serie))+'-'+LTRIM(RTRIM(CAST(c.NUMERO_FACTURA  AS CHAR(15)))) AS DOCUMENTO,
	c.DESCRIPCION,
	c.FECHA_DOCUMENTO AS FECHA_DOCUMENTO,
	0	AS CARGO,
	c.VALOR_FACTURA	AS ABONO
FROM TBL_cARGOS c inner join tbl_proveedores p	on 	c.id_empresa=p.id_empresa	and
							c.nit		=p.nit
where c.id_empresa=@id_empresa and c.nit=@nit and datediff(day,c.fecha_documento,@Fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) 

UNION ALL
SELECT 	D.ID_EMPRESA,
	(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@Id_Empresa) as nombre_empresa,
	D.NIT,
	p.nombre as nombre_proveedor,
	D.TIPO+'-'+LTRIM(RTRIM(CAST(D.NUMERO  AS CHAR(15)))) AS DOCUMENTO,
	(Case when d.Id_Tipo_Pago='ANT' 
		Then 'Anticipo a '+d.tipo_cargo+' '+ltrim(rtrim(cast(d.numero_factura as char))) 
		else 'Pago  a '+d.tipo_cargo+' '+ltrim(rtrim(cast(d.numero_factura as char))) end) as DESCRIPCION,
	D.fecha_de_pago 	AS FECHA_DOCUMENTO,
	D.Valor_Aplicado as CARGO,
	0		AS ABONO
	FROM TBL_dET_ABONOS D	LEFT JOIN TBL_ABONOS	A
				ON 	D.ID_EMPRESA	=A.ID_EMPRESA	AND
					D.ID_TIPO_PAGO	=A.ID_TIPO_PAGO	AND
					D.NUMERO_PAGO	=A.NUMERO_PAGO
				inner join tbl_proveedores p	on 	d.id_empresa=p.id_empresa	and
									d.nit		=p.nit
WHERE 	D.ID_EMPRESA	=@ID_EMPRESA		AND
	D.NIT		=@NIT			AND
	D.VALOR_APLICADO<>0			and
	DATEDIFF(DAY,A.FECHA_DOCTO,@Fecha_final) between 0 and	datediff(day,@fecha_inicial,@fecha_final)
	

ORDER BY 7

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_existencias_finales
-- =============================


--exec rpt_existencias_finales 1

CREATE procedure rpt_existencias_finales @Id_Empresa	int as


select 
ltrim(rtrim(p.Id_Producto))+' '+ltrim(rtrim(p.descripcion)) as producto,
ltrim(rtrim(p.Id_Articulo))+' '+ltrim(rtrim(a.descripcion)) as articulo,
	p.Id_Depto+' '+ltrim(rtrim(d.nombre)) as depto,
	p.Id_Linea+' '+ltrim(rtrim(nombre_linea)) as linea,
	e.Id_Empresa,
	e.Id_Bodega,
	e.Periodo,
	isnull(e.existencia,0) 	as existencia,
	isnull(e.costo,0)  		as costo from tbl_existencia	e	inner join tbl_productos p
			on	e.Id_Empresa	=p.Id_Empresa	and
				e.Id_Producto	=p.Id_producto
						inner join tbl_articulos a
			on	p.Id_Empresa	=a.Id_Empresa	and
				p.Id_Articulo	=a.Id_Articulo
						inner join tbl_departamentos d
			on	p.Id_Empresa	=d.Id_Empresa	and
				p.Id_Depto	=d.Id_Depto
						inner join tbl_linea	lin
			on	p.Id_Empresa	=lin.Id_Empresa	and
				p.Id_Linea	=lin.Id_Linea
WhERE e.Id_Empresa=@Id_Empresa






GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
-- =============================
-- SP: rpt_Existencias_por_depto
-- =============================









--SET DATEFORMAT DMY
--select *from tbl_existencia
--exec rpt_existencias_por_depto 1,1,1,1,'17/03/2007'
CREATE   procedure [dbo].[rpt_Existencias_por_depto] 	@Id_empresa int, 
						@Incluyedescripcionlarga int,
						@orden int,--orden del reporte
						@Salta int,--salta al final del c/grupo
						@ALFECHA DATETIME,
						@Existencia_cero int,
						@Linea_inv int
 as --a una fecha especifica
set dateformat dmy
Declare @periodo_ACTUAL char(7),@periodo_anterior char(7),@delfecha datetime

SELECT @periodo_actual=REPLICATE('0',2-LEN(CAST(MONTH(@ALFECHA) AS CHAR(2))) )+LTRIM(RTRIM(CAST( MONTH(@ALFECHA) AS CHAR))) +'/'+CAST(YEAR(@ALFECHA) AS CHAR(4))

set @delfecha= '01/'+@periodo_actual

SELECT @periodo_anterior=REPLICATE('0',2-LEN(CAST(MONTH(dateadd(month,-1,@ALFECHA) ) AS CHAR(2))) )+LTRIM(RTRIM(CAST( MONTH(dateadd(month,-1,@ALFECHA)) AS CHAR))) +'/'+CAST(YEAR(dateadd(month,-1,@ALFECHA)) AS CHAR(4))


select A.Id_empresa,
	(select nombre_empresa from empresas where id_empresa=A.Id_empresa) as nombreempresa,	
	A.periodo,
	A.Id_depto,
	A.Id_Linea,
	A.id_producto,
	A.descripcion,
	A.descripcion_corta,
	D.Nombre as nombredepto,
	SUM(A.Existencia) as existencia
FROM
(
SELECT P.ID_EMPRESA,--query que extrae el saldo inicial
	@periodo_actual as periodo,
	p.Id_depto,
	p.Id_Linea,
	P.ID_PRODUCTO,
	P.DESCRIPCION,
	p.descripcion_corta,
	sum(Existencia) as existencia
	FROM TBL_PRODUCTOS P, TBL_EXISTENCIA E
WHERE 	P.Id_Empresa	=E.Id_Empresa 	And
	P.ID_PRODUCTO=E.ID_PRODUCTO	And
	e.periodo	=@periodo_anterior 	and
	P.Id_Empresa	=@Id_Empresa		
Group by P.Id_empresa,p.Id_depto,P.Id_Linea,P.Id_producto,P.descripcion,p.descripcion_corta
UNION all
select 	d.Id_Empresa, --query que extra los movimientos del presente mes
	@periodo_actual as periodo,
