-- =============================
-- SP: rpt_Existencias_por_producto
-- =============================








--SET DATEFORMAT DMY
--select *from tbl_existencia
--exec rpt_existencias_por_producto 1,1,1,1,'31/12/2009',0,1
CREATE    procedure [dbo].[rpt_Existencias_por_producto] 	@Id_empresa int,
														@Incluyedescripcionlarga int,
														@orden int,
														@Salta int,
														@ALFECHA DATETIME,
														@Existencia_cero int,
														@Linea_inv int as
set dateformat dmy

Declare @periodo_ACTUAL char(7),@periodo_anterior char(7),@delfecha datetime 
SELECT @periodo_actual=REPLICATE('0',2-LEN(CAST(MONTH(@ALFECHA) AS CHAR(2))) )+LTRIM(RTRIM(CAST( MONTH(@ALFECHA) AS CHAR))) +'/'+CAST(YEAR(@ALFECHA) AS CHAR(4))


SELECT @periodo_anterior=REPLICATE('0',2-LEN(CAST(MONTH(dateadd(month,-1,@ALFECHA) ) AS CHAR(2))) )+LTRIM(RTRIM(CAST( MONTH(dateadd(month,-1,@ALFECHA)) AS CHAR))) +'/'+CAST(YEAR(dateadd(month,-1,@ALFECHA)) AS CHAR(4))
set @delfecha= '01/'+@periodo_actual


select A.Id_empresa,
	(select nombre_empresa from empresas where id_empresa=A.Id_empresa) as nombreempresa,	
	A.periodo,
	A.ubicacion,
	A.id_producto,
	A.descripcion,
	A.descripcion_corta,
	SUM(A.Existencia) as existencia
FROM
(
SELECT P.ID_EMPRESA,
	@periodo_actual as periodo,
	p.ubicacion,
	P.ID_PRODUCTO AS ID_PRODUCTO,
	P.DESCRIPCION,
	p.descripcion_corta,
	sum(Existencia) as existencia
	FROM TBL_PRODUCTOS P, TBL_EXISTENCIA E
WHERE 	P.Id_Empresa	=E.Id_Empresa 	And
	P.ID_PRODUCTO=E.ID_PRODUCTO	And
	e.periodo	=@periodo_anterior 	and
	P.Id_Empresa	=@Id_Empresa	
Group by P.Id_empresa,p.ubicacion,P.Id_producto,P.descripcion,p.descripcion_corta
union all
select 	d.Id_Empresa,
	@periodo_actual as periodo,
	p.ubicacion,
	p.id_producto AS ID_PRODUCTO,
	p.descripcion,
	p.descripcion_corta,
	(case when t.efecto_inv=1 then d.cantidad else d.cantidad*-1 end) as cantidad

	FROM tbl_cabecera_movimientos c,tbl_detalle_movimientos d, tbl_productos p,TBL_TIPOS_INV T
where  	c.id_empresa	=@id_empresa		and
	c.id_empresa	=d.id_empresa		and
	c.Periodo	=d.periodo		and
	c.id_bodega	=d.id_bodega		and
	c.id_tipo	=d.id_tipo		and
	c.nit		=d.nit			and
	c.numero	=d.numero		and
	c.id_empresa	=t.id_empresa		and
	c.id_tipo	=t.id_tipo		and
	c.periodo	=@Periodo_actual	and
	d.id_empresa	=p.id_empresa		and
	d.id_producto	=p.id_producto		and
	c.fecha		<=@Alfecha		

union all
select c.id_empresa,
	@periodo_actual as periodo,
	p.ubicacion,
	p.id_producto  AS ID_PRODUCTO,
	p.descripcion,
	p.descripcion_corta,
	(D.cantidad*-1 ) as cantidad
 from tbl_cab_facturacion c,tbl_det_facturacion d, tbl_productos p 
where 	c.id_empresa	=@id_empresa	and
	c.id_empresa=d.id_empresa	 and
	c.id_caja=d.id_caja	 	and
	c.autorizacion=d.autorizacion 	and
	c.serie=d.serie 			and
	c.id_tipo=d.id_tipo 		and 
	c.numero=d.numero 		and
	d.id_empresa=p.id_empresa 	and
	d.id_producto=p.id_producto	 and
	datediff(day,c.fecha_factura,@alfecha) between 0 and datediff(day,@delfecha,@alfecha)
UNION ALL
select c.id_empresa,
	@periodo_actual as periodo,
	p.ubicacion,
	p.id_producto  AS ID_PRODUCTO,
	p.descripcion,
	p.descripcion_corta,
	(D.cantidad*-1 ) as cantidad
 from tbl_cab_notas_credito c,tbl_det_notas_credito d, tbl_productos p 
where 	c.id_empresa	=@id_empresa	and
	c.id_empresa=d.id_empresa	 and
	c.id_caja=d.id_caja	 	and
	c.autorizacion=d.autorizacion 	and
	c.serie=d.serie 			and
	c.id_tipo=d.id_tipo 		and 
	c.numero=d.numero 		and
	d.id_empresa=p.id_empresa 	and
	d.id_producto=p.id_producto	 and
	datediff(day,c.fecha_factura,@alfecha) between 0 and datediff(day,@delfecha,@alfecha)


) A 
GROUP BY
A.ID_EMPRESA,
A.periodo,
	A.ubicacion,
	A.id_producto,
	A.descripcion,
	A.descripcion_corta









GO
                                                                                                                                                                               
