-- SP: rpt_factura
-- =============================
CREATE procedure [dbo].[rpt_factura]  	@Id_Empresa	int,
				@Id_Caja	int,
				@Autorizacion	char(20),
				@Serie		char(3),
				@Id_Tipo	char(3),
				@Numero		Numeric(10) as

Declare @orden_servicio	int,
	@Num_placa	char(10),
	@lectura_actual	int,
	@proximo_servicio int,
	@marca	char(25),
	@modelo	char(4),
	@presion	int,
	@fecha_ingreso datetime
	
SELECT top 1 	@Orden_Servicio		=Id_orden,
		@Num_placa		=Num_PLaca,
		@Lectura_actual		=Lectura_actual,
		@Fecha_ingreso		=fecha,	
		@Proximo_servicio	=Proximo_servicio FROM TBL_ORDEN_SERVICIO 
WHERE 	AUTORIZACION=@Autorizacion	AND
	SERIE	=@Serie		AND
	TIPO	=@Id_Tipo		AND
	NUMERO	=@Numero

select @marca=marca,
	@modelo=modelo,
	@presion=presion_llantas from tbl_vehiculos 
where id_empresa=@Id_empresa and num_placa=@num_placa

Select @ORDEN_SERVICIO AS ORDEN_SERVICIO,
	@NUM_PLACA AS NUMERO_PLACA,
	@LECTURA_ACTUAL AS LECTURA_ACTUAL,
	@PROXIMO_SERVICIO AS PROXIMO_SERVICIO,
	@MARCA AS MARCA,
	@MODELO AS MODELO,
	@PRESION AS PRESION,
	@FECHA_INGRESO AS FECHA_INGRESO,
	(SELECT Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_empresa,
	(SELECT Nit FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nit_empresa,
	(SELECT Nombre_comercial FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_comercial,
	(SELECT Nit FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nit_empresa,
	(SELECT Direccion FROM EMPRESAS where Id_Empresa=@Id_Empresa) as direccion_empresa,
	
	a.Id_Empresa
      ,a.Id_Caja
      ,a.Autorizacion
      ,a.Serie
      ,a.Id_Tipo
      ,a.Numero
      ,a.Nit
      ,a.Facturar_a
      ,a.Contado_o_Credito
      ,a.Porcentaje_Descuento
      ,a.Fecha_Factura
      ,a.Cajero
      ,a.Fecha_Corte
      ,a.Fecha_hora
      ,a.usuario
      ,a.Status
      ,a.Tarjeta_beneficio
      ,a.Efectivo
      ,a.Vuelto
      ,a.Id_Banco
      ,a.Num_Cheque
      ,a.Id_Casa
      ,a.Tcredito
      ,a.Subtotal
      ,a.Descuento
      ,a.Total
      ,a.Valor_cheque
      ,a.Valor_Tarjeta
      ,a.Cuenta_Bancaria
      ,a.Autorizacion_Pago
      ,a.Valor_Anticipo
      ,a.Id_Anticipo
      ,a.Lleva_Orden
      ,a.lcorte_caja
      ,a.anio_poliza
      ,a.mes_poliza
      ,a.Id_Banco_poliza
      ,a.Tipo_poliza
      ,a.numero_poliza
      ,
      (SELECT ltrim(rtrim(NOMBRE)) FROM Tbl_Vendedores WHERE Id_Empresa=@Id_Empresa  AND ID_EMPLEADO=a.Id_empleado ) as Id_empleado

      ,a.Tasa_cambio
      ,a.Tasa_cambio_remedicion
      ,a.Fecha_tasa_remedicion
      ,a.valor_dolares
      ,a.valor_otraformapago,
	
	d.Id_Producto,
	d.Cantidad,
	d.Descripcion_Corta,
	d.Precio,
	d.precio_descuento,
	d.Total_Linea,
	p.direccion,
	p.telefono1,
	p.num_casa,
	p.apto,
	P.Municipio ,
	p.zona,p.ciudad,
	p.tarjeta as tbeneficio,
	''+ltrim(rtrim(cast(x.del as char)))+  ' Al '+ ltrim(rtrim(cast(x.al as char))) AS rango_autorizacion,
	(select Fecha_ingreso from tbl_series
	 where id_empresa=@Id_empresa and autorizacion=a.autorizacion) as fecha_ingreso
	 from Tbl_Cab_Facturacion a	left join Tbl_Det_Facturacion d
				on 	a.Id_Empresa	=d.Id_Empresa	and
					a.Id_Caja	=d.Id_Caja	and
					a.Autorizacion	=d.Autorizacion	and
					a.serie		=d.Serie	and
					a.Id_Tipo	=d.Id_Tipo	and
					a.Numero	=d.Numero
							inner join Tbl_Proveedores p
				on	a.Id_Empresa	=p.Id_Empresa	and
					a.nit		=p.nit
							inner join tbl_series x
				on	a.id_empresa=x.id_empresa	and
					a.autorizacion=x.autorizacion and
					a.serie=x.serie					and
					a.id_tipo=x.id_tipo
WHERE 	a.Id_Empresa	=@Id_Empresa	and
	a.Id_Caja	=@Id_Caja	and
	a.Autorizacion	=@Autorizacion	and
	a.Serie		=@Serie		and
	a.Id_Tipo	=@Id_Tipo	and
	a.Numero	=@Numero


GO
                                                                                                                                                                                  
