--exec rpt_factura_cxc 1,'123452-1','XXX','FAC',44
CREATE procedure [dbo].[rpt_factura_cxc] @Id_Empresa	int,
	@Nit		char(20),
	@Serie		char(3),
	@Tipo_docto	char(3),
	@Numero_docto	Numeric(10) as
select *from tbl_cuentas_por_cobrar c, tbl_proveedores p, Tbl_Ente_facturador e
where	c.Id_empresa=@Id_Empresa	and
	c.Nit=@Nit		and
	c.Serie=@Serie	and
	c.Tipo_docto=@Tipo_docto	and
	c.Numero_docto=@Numero_docto	and
	p.id_empresa	=c.id_empresa	and
	p.nit		=c.nit  and
	c.Id_Empresa=e.Id_Empresa and
	c.id_ente_facturador =e.Id_Ente_facturador 


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
