-- SP: rpt_factura_post_pago
-- =============================
--select *from TBL_DETALLE_VENTAS_VALES 
--exec rpt_factura_post_pago 1,'a',300
CREATE procedure [dbo].[rpt_factura_post_pago] @id_empresa int,@serie char(5),@numero_factura numeric(10) as
 
 
 select *from (
 select d.*,prov.Nit,prov.Facturar_a AS NOMBRE,prov.direccion,C.ID_CLIENTE_VALE ,C.FECHA_FACTURA  from TBL_CABECERA_VENTAS_VALE c , TBL_DETALLE_VENTAS_VALES  d, Tbl_Proveedores prov
 where c.ID_EMPRESA=d.ID_EMPRESA and
 c.SERIE=d.SERIE and
 c.NUMERO=d.NUMERO_FACTURA   and
 c.ID_EMPRESA=prov.Id_Empresa and
 c.ID_CLIENTE_VALE =prov.Nit and
 c.id_empresa=@Id_empresa and
		c.serie=@serie and
		c.numero=@numero_factura and
		c.TIPO_VALE ='POSPAGO'
		
		) x where x.ID_PRODUCTO ='VPOWER'
UNION ALL		
select *from (
 select d.*,prov.Nit,prov.Facturar_a ,prov.direccion,C.ID_CLIENTE_VALE,C.FECHA_FACTURA   from TBL_CABECERA_VENTAS_VALE c , TBL_DETALLE_VENTAS_VALES  d, Tbl_Proveedores prov
 where c.ID_EMPRESA=d.ID_EMPRESA and
 c.SERIE=d.SERIE and
 c.NUMERO=d.NUMERO_FACTURA   and
 c.ID_EMPRESA=prov.Id_Empresa and
 c.ID_CLIENTE_VALE =prov.Nit and
 c.id_empresa=@Id_empresa and
		c.serie=@serie and
		c.numero=@numero_factura and
		c.TIPO_VALE ='POSPAGO'
		
		) x where x.ID_PRODUCTO ='SUPER'
UNION ALL		
select *from (
 select d.*,prov.Nit,prov.Facturar_a, prov.direccion ,C.ID_CLIENTE_VALE ,C.FECHA_FACTURA   from TBL_CABECERA_VENTAS_VALE c , TBL_DETALLE_VENTAS_VALES  d, Tbl_Proveedores prov
 where c.ID_EMPRESA=d.ID_EMPRESA and
 c.SERIE=d.SERIE and
 c.NUMERO=d.NUMERO_FACTURA   and
 c.ID_EMPRESA=prov.Id_Empresa and
 c.ID_CLIENTE_VALE =prov.Nit and
 c.id_empresa=@Id_empresa and
		c.serie=@serie and
		c.numero=@numero_factura and
		c.TIPO_VALE ='POSPAGO'
		
		) x where x.ID_PRODUCTO ='REGULAR'		
UNION ALL		
select *from (
 select d.*,prov.Nit,prov.Facturar_a,prov.direccion ,C.ID_CLIENTE_VALE,C.FECHA_FACTURA   from TBL_CABECERA_VENTAS_VALE c , TBL_DETALLE_VENTAS_VALES  d, Tbl_Proveedores prov
 where c.ID_EMPRESA=d.ID_EMPRESA and
 c.SERIE=d.SERIE and
 c.NUMERO=d.NUMERO_FACTURA   and
 c.ID_EMPRESA=prov.Id_Empresa and
 c.ID_CLIENTE_VALE =prov.Nit and
 c.id_empresa=@Id_empresa and
		c.serie=@serie and
		c.numero=@numero_factura and
		c.TIPO_VALE ='POSPAGO'
		
		) x where x.ID_PRODUCTO ='DIESEL'				
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_factura_prepago
-- =============================

--USE db_cuenta_corriente_gasolinera 
--exec [dbo].[rpt_factura_prepago] 1,'a',1
CREATE  procedure [dbo].[rpt_factura_prepago]	@ID_EMPRESA INT,
												@SERIE CHAR(20),
												@NUMERO NUMERIC(12)  as
		
select	c.fecha_factura AS FECHA_VALE,
		p.Facturar_a ,
		p.direccion ,
		p.num_casa+' '+
		p.zona + ' '+
		p.ciudad + ' ' as direccion,
		c.VALES_TOTAL ,
		c.ID_CLIENTE_VALE 
		from TBL_CABECERA_VENTAS_VALE  c inner join Tbl_Cliente p
				on c.ID_EMPRESA					=p.Id_Empresa and
					c.ID_CLIENTE_VALE			=p.ID_CLIENTE_VALE 
										
where c.ID_EMPRESA=@ID_EMPRESA  and
c.SERIE=@SERIE  and
c.NUMERO =@NUMERO  





GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_factura_vales_gasolina
-- =============================
--exec rpt_factura_vales_gasolina 1, 'A', '1','200'

CREATE procedure rpt_factura_vales_gasolina 
@id_empresa int, 
@serie		char(20),
@del		int,
@al			int
as
select 
c.id_empresa, 
c.serie,
c.numero,
c.FECHA_FACTURA,
c.TIPO_VALE,
c.VALES_TOTAL,
c.FECHA_OPERACION,
c.DESCRIPCION_VENTAS_VALE,
c.ID_CLIENTE_VALE,
p.Nombre,
d.ID_PRODUCTO,
d.FECHA_VALE,
d.VALOR_VALE,
d.CANTIDAD_VALE
from TBL_CABECERA_VENTAS_VALE c, Tbl_Proveedores p, TBL_DETALLE_VENTAS_VALES d
where c.ID_EMPRESA		= @id_empresa  and 
	  c.ID_EMPRESA		= p.Id_Empresa and 
	  c.ID_CLIENTE_VALE = p.Nit		   and
	  c.ID_EMPRESA	    = d.ID_EMPRESA and 
	  c.SERIE			= d.SERIE			and
	  c.NUMERO			= d.NUMERO_FACTURA and
	  c.SERIE			= @serie		and
	  c.NUMERO			Between @del and @al 
	  

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
-- =============================
-- SP: rpt_facturas_anuladas_cuentas_por_cobrar
-- =============================
/*
drop procedure rpt_facturas_anuladas_cuentas_por_cobrar
set dateformat dmy
exec rpt_facturas_anuladas_cuentas_por_cobrar 1, '01/01/2006','31/12/2006'
*/
create procedure [dbo].[rpt_facturas_anuladas_cuentas_por_cobrar]
@id_empresa int,@fecha_inicial datetime, @fecha_final datetime as

select
	(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombreempresa,
	( select p.nombre from tbl_proveedores p  where p.id_empresa=c.id_empresa and nit=c.nit) as nombreproveedor,
 c.* from tbl_cuentas_por_cobrar c
where c.id_empresa=@id_empresa	and
	datediff(day,c.fecha_docto,@fecha_final)	between 0 and
	datediff(day,@fecha_inicial,@fecha_final)	and
	c.status=2
	

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: rpt_facturas_cxp
-- =============================

--set dateformat dmy
--exec rpt_facturas_cxp 1,'01/12/2005','26/12/2005'
CREATE procedure rpt_facturas_cxp  @Id_empresa int,@Fecha_inicial datetime,@fecha_final datetime as

Declare @Nombre_Empresa char(100)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa

SELECT 	@Nombre_empresa as nombre_empresa,
	c.*,
	p.nombre FROM TBL_cARGOS c inner join tbl_proveedores p 
							on 	c.id_Empresa	=p.id_empresa 	and
								c.nit		=p.nit	
where c.id_empresa=@Id_Empresa and
datediff(day,c.fecha_recepcion,@fecha_final) between 0  and datediff(day,@Fecha_Inicial,@fecha_final)
order by c.fecha_recepcion


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: rpt_facturas_emitidas
-- =============================
--set dateformat dmy
--exec [dbo].[rpt_facturas_emitidas] 1, '01/11/2018', '30/01/2019'
CREATE procedure [dbo].[rpt_facturas_emitidas] @Id_empresa int,
@Fecha_inicial datetime,
@Fecha_final datetime as
set dateformat dmy



select c.id_empresa,
c.id_caja,
c.serie,
c.numero,
c.nit,
c.facturar_a,
c.fecha_factura,
case when c.Status=2 or c.status=1
then 'Emitida'
else case when c.status=3
then 'Anulada'
Else case when c.status=4
then 'Aplicada Nota credito'
end 
end
end as estado_factura,
d.id_producto,
d.descripcion_corta,
d.cantidad,
d.precio,
d.total_linea,
d.Precio_Descuento 
from tbl_cab_facturacion c inner join tbl_det_facturacion d
on c.id_empresa=d.id_empresa and
c.id_caja=d.id_caja and
c.autorizacion=d.autorizacion and
c.serie=d.serie and
c.id_tipo=d.id_tipo and
c.numero=d.numero
where c.id_empresa=@id_empresa and
datediff(day,c.fecha_factura,@fecha_final) between 0 and
datediff(day,@fecha_inicial,@fecha_final)
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_facturas_por_cobrar_por_contabilizar
-- =============================

--exec rpt_facturas_por_cobrar_por_contabilizar 1
CREATE procedure [dbo].[rpt_facturas_por_cobrar_por_contabilizar] @Id_empresa int as
select 
c.Id_Empresa,
c.nit,
c.Serie,
c.Tipo_docto,
p.Nombre,
c.numero,
c.Numero_docto,
c.Descripcion,
c.Fecha_docto,
c.Valor_docto,
c.Iva

from tbl_cuentas_por_cobrar c inner join dbo.Tbl_Proveedores p	 on
c.Id_Empresa=p.Id_Empresa and 
c.nit=p.nit
where 	c.Id_Empresa=@Id_empresa and
c.provisionado =1 and 
c.Contabilizado=2
order by c.fecha_docto, c.nit

