-- =============================
-- SP: rpt_facturas_por_cobrar_vales
-- =============================
--SET DATEFORMAT DMY
--exec rpt_facturas_por_cobrar_vales 1, '29/01/2014'
CREATE procedure [dbo].[rpt_facturas_por_cobrar_vales] 
@id_empresa as int,
@fecha		as datetime as

select id_empresa,
(select nombre_empresa from empresas where Id_Empresa=@id_empresa) AS NOMBREEMPRESA,
id_cliente_vale, nombre, SUM(valor_vale) as valor_vale 
from vw_vales_prepago_pospago 
WHERE datediff(day,@fecha,fecha_vale)=0
group by id_empresa, id_cliente_vale, nombre 
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
-- =============================
-- SP: rpt_facturas_provisionadas
-- =============================

--exec rpt_facturas_provisionadas 2
CREATE procedure [dbo].[rpt_facturas_provisionadas] @Id_Empresa int as
--reporte de facturas provisionadas y no contabilizadas
SELECT 
	(SELECT Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_empresa,
	a.Id_Empresa,
	a.Nit,
	a.Id_Tipo_Cargo,
	a.Serie ,
	a.Numero_Factura ,
	a.linea,
	case when  a.Id_Cuenta=''
		then '**********'
		else a.Id_Cuenta end as Id_cuenta ,
	case when 
	(select AUXILIARES  from db_contabilidad_pfp.dbo.cuentas 
	where id_empresa=@Id_empresa and
	Id_Cuenta=a.Id_Cuenta)=1 and (a.Id_Auxiliar ='' or  a.Id_Auxiliar =null  )
		then '****'
		else a.Id_Auxiliar  end Id_Auxiliar,
		

	a.Id_Departamento ,
	a.Debe ,
	a.Haber , 
	
	p.nombre as nombre_proveedor,
(select descripcion from db_contabilidad_pfp.dbo.cuentas where id_empresa=@Id_empresa and
	Id_Cuenta=a.Id_Cuenta) as nombrecuenta
	
	

 FROM TBL_CONTABILIZA_CARGOS a	inner join tbl_proveedores p on a.id_empresa=p.id_empresa and
								a.nit	=p.nit
WHERE LTRIM(RTRIM(CAST(a.ID_EMPRESA AS CHAR)))+LTRIM(RTRIM(a.NIT))+a.ID_TIPO_CARGO+LTRIM(RTRIM(CAST(a.NUMERO_FACTURA AS CHAR))) IN
(SELECT LTRIM(RTRIM(CAST( ID_EMPRESA AS CHAR)))+LTRIM(RTRIM(NIT))+TIPO_CARGO+LTRIM(RTRIM(CAST(NUMERO_FACTURA AS CHAR))) FROM TBL_cARGOS 
WHERE ID_EMPRESA=@Id_Empresa	AND PROVISIONADO=1	AND CONTABILIZADO=2)




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
-- =============================
-- SP: rpt_historial_facturas
-- =============================



--set dateformat dmy
--exec dbo.rpt_historial_facturas 1,'01/01/2008','31/12/2008','TOD'

CREATE procedure [dbo].[rpt_historial_facturas] @Id_empresa int,
										@Fecha_inicial datetime,
										@Fecha_final   datetime,
										@Tipo		char(3) as
set dateformat dmy
--set @Id_empresa=1
--set @Fecha_inicial	='01/01/2008'
--set @Fecha_final	='30/09/2008'
select *from
(
select	c.Id_empresa,
		(select nombre_empresa from empresas e where e.id_empresa=c.id_empresa) as nombre_empresa,
		(select nit from empresas e where e.id_empresa=c.id_empresa) as nit_empresa,
		c.Id_caja,
		c.Autorizacion,
		c.Serie,
		c.Id_tipo,
		c.Numero,
		c.Nit,
		c.Facturar_a,
		Case when c.contado_o_credito=1
			Then 'Crèdito'
			Else 'Contado' end as credito_contado,
		'' as Factura_aplicada,
		c.status,
		c.Fecha_factura,
		c.Cajero,
		c.total
		from tbl_cab_facturacion c
where	c.Id_empresa	=@Id_Empresa	and
		datediff(day,c.fecha_Factura,@Fecha_final)	between 0 and
		datediff(day,@fecha_inicial,@Fecha_final)
union  all
select	c.Id_empresa,
		(select nombre_empresa from empresas e where e.id_empresa=c.id_empresa) as nombre_empresa,
		(select nit from empresas e where e.id_empresa=c.id_empresa) as nit_empresa,
		c.Id_caja,
		c.Autorizacion,
		c.Serie,
		c.Id_tipo,
		c.Numero,
		c.Nit,
		c.Facturar_a,
		Case when c.contado_o_credito=1
			Then 'Crèdito'
			Else 'Contado' end as credito_contado,
		'Factura '+ltrim(rtrim(c.serie_factura))+'-'+ltrim(rtrim(cast(c.numero_factura as char))) as Factura_aplicada,
		c.status,
		c.Fecha_factura,
		c.Cajero,
		c.total
		from tbl_cab_notas_credito c
where	c.Id_empresa	=@Id_empresa	and
		datediff(day,c.fecha_Factura,@Fecha_final)	between 0 and
		datediff(day,@fecha_inicial,@Fecha_final)
) x
where  x.id_tipo= case when @tipo='TOD' then x.id_tipo else @tipo end





GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
-- =============================
-- SP: rpt_historico_cuentas_por_cobrar
-- =============================

--select *from tbl_cuentas_por_cobrar
--select *from tbl_cuentas_por_cobrar where numero_docto='6655'
--select *from tbl_det_cobros where numero='6655'
--set dateformat dmy
---exec rpt_historico_cuentas_por_cobrar 1,'15/09/2016',1
CREATE procedure [dbo].[rpt_historico_cuentas_por_cobrar]  @Id_Empresa int,@Hasta datetime,@Orden int as 
set dateformat dmy
/*set @Id_empresa	=1
set @Hasta	='31/12/2006'*/
Declare @nombre_empresa varchar(100)
select @nombre_empresa=nombre_empresa from empresas where id_empresa=@Id_empresa
Select  @Id_Empresa as Id_empresa,
	@nombre_empresa as nombre_empresa,
	a.Nit,
	(select nombre from tbl_proveedores where id_empresa=@id_empresa and nit=a.nit) as nombreproveedor,
	a.Serie,
	a.Tipo,
	a.numero,
	(select descripcion from tbl_cuentas_por_cobrar where id_empresa		=@Id_empresa 	and
							nit		=a.nit		and	
							serie		=a.serie	and
							tipo_docto	=a.tipo		and
							numero_docto	=a.numero	) as descripcion,

	sum(a.valor) as valor
From
(--seleccionando todas las facturas a una fecha especifica

select 	c.Nit,
	c.Serie,
	c.Tipo_docto  	as tipo,
	c.Numero_docto 	as numero,
	c.Valor_docto	as valor from tbl_cuentas_por_cobrar c
where 	c.id_empresa=@Id_Empresa	and
	DATEDIFF(DAY,c.Fecha_docto,@Hasta )>-1 and c.status=1
union all
select  c.Nit, --seleccionando todos los cobros a una fecha especifica
	d.Serie,
	d.Id_Tipo as tipo,
	d.Numero  as numero,
	(d.Valor_aplicado*-1) as valor
	from tbl_cobros c, tbl_det_cobros d, tbl_proveedores p
where 	c.id_empresa		=@Id_Empresa 			and
	c.id_tipo_cobro		=d.id_tipo_cobro 	and
	c.num_docto_cobro	=d.num_docto_cobro	and
	c.id_empresa		=p.id_empresa		and
	c.nit			=p.nit		and	
	DATEDIFF(DAY,c.fecha_docto,@hasta)>-1
union all
select nit,
Serie,
tipo_docto,
numero_docto,
Valor_retencion_iva *-1 as valor

from Tbl_cuentas_por_cobrar_retencion_iva 
where Id_empresa=@Id_Empresa 	and
DATEDIFF(day,fecha,@hasta)>-1
) A
where a.valor<>0
group by a.Nit,
	a.Serie,
	a.Tipo,
	a.NUMERO
	
	
	




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
-- =============================
-- SP: rpt_importacion
-- =============================



--exec rpt_importacion 1,11
CREATE procedure [dbo].[rpt_importacion] @Id_empresa int,@Id_pedido int as



select	e.nombre_empresa,c.*,
		(select nombre from tbl_proveedores r where r.id_empresa=@Id_empresa  and r.nit=c.nit) as nombreprov,
		
		d.id_sproducto,
		d.cantidad_recibida,
		d.costo_recibida,
		d.total_importacion,
		d.flete_dolares,
		d.gastos_locales as gastoslocalesdetalle,
		d.valor_soporte as valor_soporte_detalle,
		d.costo_total_real,
		d.costo_unitario,
		d.impuesto_importacion as impuesto_impdetalle,
		(select p.porcentaje_utilidad from tbl_prod_proveedores j, tbl_productos p
		 where	j.id_empresa=p.id_Empresa and
				j.id_producto=p.id_producto and
				j.id_empresa= d.id_empresa and 
				j.id_alterno=d.id_sproducto) as porcentaje_utilidad,
		(select p.descripcion from tbl_prod_proveedores j, tbl_productos p
		 where	j.id_empresa=p.id_Empresa and
				j.id_producto=p.id_producto and
				j.id_empresa= d.id_empresa and 
				j.id_alterno=d.id_sproducto) as descripcion

 from tbl_importacion c,
		tbl_detalle_importacion d,
		empresas				e
where	c.id_empresa=d.id_empresa	and 
		c.id_pedido=d.id_pedido		and
		c.id_empresa	=e.id_empresa and
		c.id_empresa	=@id_empresa	and
		c.id_pedido		=@id_pedido



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: rpt_Integracion_Insumos
-- =============================


CREATE procedure rpt_Integracion_Insumos 	@Id_Empresa	int,
						@Id_Orden	int,
						@Linea		int as
select 	@linea as linea,
	d.Id_Empresa,
	d.Id_Orden,
	d.linea,
	d.se_cobra,
	d.Id_Producto,
	p.Descripcion as descripcion,
	d.Cantidad,
	d.Precio,
	d.Total_LINEA from tbl_orden_servicio_DETALLE_integracion	d inner join tbl_productos	p on
									d.Id_Empresa	=p.Id_Empresa	and
									d.Id_Producto	=p.Id_Producto
			
where	d.Id_Empresa	=@Id_Empresa	and
	d.Id_Orden	=@Id_Orden	and
	d.Linea		=@Linea


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
