--select *from tbl_cargos
--exec rpt_integracion_poliza_provision_cxp 1,'2015','08','1'
CREATE procedure [dbo].[rpt_integracion_poliza_provision_cxp] @Id_Empresa	int,
					@Anio		char(4),
					@Mes		char(2),
					@Numero		char(10) as
Declare @Nombre_Empresa char(150)
SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa



select @Nombre_Empresa as nombre_empresa,
	t.Nit,
	(select nombre from Tbl_Proveedores 
	where id_empresa=@id_empresa and nit=t.nit) as nombre_proveedor,

	t.Id_Tipo_Cargo,
	t.Numero_factura,
	t.Linea,
	t.Id_Cuenta,
	(select descripcion from db_contabilidad_pfp.dbo.cuentas where id_empresa=t.Id_Empresa and id_cuenta=t.Id_cuenta) as nombrecuenta,
	t.Id_Auxiliar,
	t.Id_Departamento,
	t.debe,
	t.haber from tbl_contabiliza_cargos t
where ltrim(rtrim(cast(t.Id_empresa as char)))+t.Nit+t.Id_Tipo_Cargo+ltrim(rtrim(cast(t.Numero_Factura as char)))in
(select ltrim(rtrim(cast(Id_Empresa as char)))+NIT+Tipo_Cargo+ltrim(rtrim(cast(Numero_Factura  as char))) from tbl_cargos
where 	Id_Empresa	=@Id_Empresa	and 
	Anio		=@Anio		and
	Mes		=@Mes		and
	Numero		=@Numero)



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
