CREATE procedure [dbo].[rpt_inventario_fisico] @Id_empresa int,@Id_inventario  int,@Id_transac int as
select * from vw_inventario_fisico vw inner join dbo.Tbl_Productos pr on
vw.id_empresa=pr.Id_Empresa and vw.Id_producto=pr.Id_Producto inner join dbo.Tbl_Unidad_Medida u
on pr.Id_empresa=u.Id_Empresa and
   pr.Id_medida=u.Id_medida
where vw.Id_empresa=@Id_empresa and id_inventario=@Id_inventario and
id_transac= @Id_transac

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
