--SET DATEFORMAT DMY

--drop procedure dbo.rpt_inventario_valorizado
--SELECT *FROM TBL_EXISTENCIA WHERE PERIODO='09/2006' AND ID_PRODUCTO='586'
--EXEC rpt_inventario_valorizado 1,'31/01/2011',1
create procedure [dbo].[rpt_inventario_valorizado] @Id_Empresa int,@Fecha_fin datetime,@incluye_ptransito int as
--@incluye_ptransito=1= incluye productos en transito
--@incluye_ptransito=2	no incluye productos en transito

Declare @Periodo 	char(7),
	@Periodo_Anterior char(7),
	@Fecha_Ini	datetime,
	@Nombre_empresa char(150)

set dateformat dmy

set @Periodo	=Replicate('0',2-len( ltrim(rtrim(cast(Month(@Fecha_Fin) as char))) ))+ltrim(rtrim(cast(Month(@Fecha_Fin) as char)))+'/'+cast(year(@Fecha_Fin) as char)

SET @Fecha_ini='01/'+@Periodo


Declare @fecha_Inicial datetime
set @fecha_inicial=dateadd(month,-1, cast('01/'+@Periodo as datetime))
set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_inicial) as char)))))+ltrim(rtrim(str(month(@fecha_inicial))))+'/'+cast( year(@fecha_inicial) as char)

Declare @Id_Producto 	char(15),
	@Existencia	numeric(12,5),
	@Costo		Numeric(12,5)

--Cargo existencia inicial
create table #temporal(Id_Producto 		char(15)COLLATE Modern_Spanish_CI_AS  ,
			Existencia		numeric(10,2),
			Costo_Total		numeric(12,5),
			Existencia_transito	numeric(10,2),
			Costo_Total_transito	numeric(12,5))


--insertando saldo inicial
insert #temporal
select 	e.Id_Producto,
	SUM(e.Existencia)		as existencia,
	SUM(e.Costo) 			as costo_total,
	0,
	0
	from tbl_existencia e,tbl_productos p
		WHERE 	e.Id_Empresa	=p.Id_Empresa		and
			e.Id_Producto	=p.Id_Producto		and
			e.Id_Empresa	=@Id_Empresa		and 
			e.Periodo	=@Periodo_Anterior	
				
		group by e.Id_Empresa,e.Id_producto



Declare productos cursor for
select Id_Producto from tbl_productos where Id_Empresa=@Id_Empresa and es_servicio=2 
Open productos
fetch productos into @Id_Producto
while @@fetch_status=0
begin
--insertando las facturas
	insert #temporal
	select 	d.Id_Producto,
		SUM(Case when d.Id_Tipo='FAC'
			THEN (d.cantidad*-1)
			ELSE (d.cantidad) end),
		SUM(Case when d.Id_Tipo='FAC'
			THEN (d.Cantidad*d.costo*-1)
			Else (d.Cantidad*d.costo) end) as costo_total,
		0,
		0
		from tbl_det_facturacion	d	left join	tbl_cab_facturacion	c
							on	d.Id_Empresa	=c.Id_Empresa	and
								d.Id_Caja	=c.Id_Caja	and
								d.Autorizacion	=c.Autorizacion	and
								d.serie		=c.serie	and
								d.Id_Tipo	=c.Id_Tipo	and
								d.Numero	=c.Numero
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.Id_empresa	and
								d.Id_Producto	=p.Id_producto
	Where	d.Id_Empresa		=@Id_Empresa	and
		d.Id_Producto		=@Id_Producto	and
		d.rebaja_existencias	=1		and
		datediff(day,c.fecha_factura,@Fecha_Fin)	between 0	and datediff(day,@Fecha_Ini,@Fecha_Fin)
	group by d.Id_Producto
	
	--insertando las notas de credito
	insert #temporal
	select 	d.Id_Producto,
		SUM(D.cantidad*-1),
		SUM((d.Cantidad*-1)*d.costo) as costo_total,
		0,
		0
		from tbl_det_notas_credito	d	left join	tbl_cab_NOTAS_CREDITO c
							on	d.Id_Empresa	=c.Id_Empresa	and
								d.Id_Caja	=c.Id_Caja	and
								d.Autorizacion	=c.Autorizacion	and
								d.serie		=c.serie	and
								d.Id_Tipo	=c.Id_Tipo	and
								d.Numero	=c.Numero
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.Id_empresa	and
								d.Id_Producto	=p.Id_producto
	Where	d.Id_Empresa		=@Id_Empresa	and
		d.Id_Producto			=@Id_Producto	and
		d.rebaja_existencias	=1		and
		datediff(day,c.fecha_factura,@Fecha_Fin)	between 0	and datediff(day,@Fecha_Ini,@Fecha_Fin) 
	group by d.Id_Producto

	
	
	
--insertando los movimientos de inventarios
	insert #temporal
	select d.Id_producto,	
		SUM(Case when t.efecto_inv=1
			Then (d.cantidad)
			Else d.cantidad*-1 end),
		SUM(Case when t.efecto_inv=1
			Then (d
-- =============================
-- SP: rpt_kardex
-- =============================




--select *from tbl_cab_facturacion
--select *from tbl_detalle_movimientos where id_producto='1503'
--SET DATEFORMAT DMY

--EXEC RPT_KARDEX 3,'28/12/2009','01.01',0, 1
CREATE  procedure [dbo].[rpt_kardex] @Id_Empresa	int,@Fecha_Fin datetime,@Id_Producto char(15),@Muestradecimales int, @id_bodega char(10) as
Declare @Nombre_Empresa char(150),
	@Fecha_Ini datetime,
	@Fecha_periodo_anterior datetime,
	@Periodo_anterior	char(7)
set dateformat dmy
set @Fecha_Ini=cast( '01'+'/'+cast(month(@Fecha_Fin)as char(2))+'/'+cast(year(@Fecha_Fin) as char(4)) as datetime)
--al quitarle un dia a fecha ini fecha perioro anterior tiene el ultimo dia del mes anterior
set @Fecha_periodo_anterior=dateadd(day,-1,@fecha_ini)
set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_periodo_anterior) as char)))))+ltrim(rtrim(str(month(@fecha_periodo_anterior))))+'/'+cast( year(@fecha_periodo_anterior) as char)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
set dateformat dmy

SELECT 0,
	 @Nombre_empresa	as nombre_empresa,
	@Fecha_ini	as fecha_ini,
	p.descripcion,
	'INI' as id_tipo, --tipo existencia inicial
	1 as numero,
	DATEADD(DAY,-1,@FECHA_INI) as fecha,
	'' as id_bodega, 
	1 as efecto_inv,---efecto en inventario
	'Existencia inicial' as concepto,
	e.id_producto,
	SUM(e.EXISTENCIA) as cantidad,
	1 as precio  ,
	SUM(e.COSTO)/sum(e.existencia) as costo,
	'N' as status,
	cast(0	 as char) as referencia FROM TBL_EXISTENCIA	e INNER JOIN TBL_Productos	p
				on 	e.id_empresa	=p.id_empresa	and
					e.id_producto	=p.id_producto
 WHERE 	e.Id_Empresa	=@Id_empresa	and
	e.ID_PRODUCTO=@Id_Producto	AND 
	e.PERIODO=@PERIODO_ANTERIOR	AND
	E.EXISTENCIA	<>0
group by e.id_producto,p.descripcion
union all
select 	1,
	@Nombre_Empresa as nombre_empresa,@Fecha_Ini	as fecha_ini,
	p.descripcion,d.Id_Tipo,d.Numero,
	c.Fecha,d.id_bodega,t.efecto_inv,
	isnull(prov.nombre,'')+'/'+cast(isnull(c.concepto,'') as char(150)) as concepto,
	isnull(d.Id_Producto,'') as id_producto,
	d.Cantidad,
	d.Precio,
	d.Costo,
	'N' as status,
	cast(0 AS CHAR) 	as referencia 
from tbl_detalle_movimientos d	left join	tbl_cabecera_movimientos c
						on	d.Id_Empresa	=c.Id_Empresa	and
							d.Periodo	=c.Periodo	and
							d.Id_Bodega	=c.Id_Bodega	and
							d.nit		=c.nit		and
							d.Id_Tipo	=c.Id_Tipo	and
							d.Numero	=c.Numero
						inner join	tbl_tipos_inv		t
						on	d.Id_Empresa	=t.Id_Empresa	and
							d.Id_Tipo	=t.Id_Tipo
						inner join	tbl_productos		p
						on	d.Id_Empresa	=p.Id_empresa	and
							d.Id_Producto	=p.Id_producto
						inner join 	tbl_proveedores 	prov
						on	c.Id_Empresa	=prov.id_empresa	and
							c.nit		=prov.nit
where 	d.id_empresa	=@Id_empresa		and
	d.Id_Producto		=@Id_producto		and
	d.Id_Tipo	='COM'			and
	datediff(day,c.fecha,@Fecha_fin)		between	0	and datediff(day,@Fecha_Ini,@Fecha_Fin)
union all

select 	2,
	@Nombre_Empresa as nombre_empresa,
	@Fecha_Ini	as fecha_ini,
	p.descripcion,
	d.Id_Tipo,
	d.Numero,
	c.Fecha_Factura as fecha,
	d.id_bodega,
	1 as efecto_inv,
		isnull(c.Facturar_a,'') as concepto,
	
	isnull(d.Id_Producto,'') as id_producto,
	(d.Cantidad*-1),
	d.Precio,
	d.Costo,
	'S' as status, --indica si esta facturado o no
	ltrim(rtrim(c.serie_factura ))+ ltrim(rtrim(cast(numero_factura as char)))   as referencia 
	from Tbl_Det_Notas_Credito 	d	left join	Tbl_Cab_Notas_Credito 	c
						on	d.Id_Empresa	=c.Id_Empresa	and
							d.Id_Caja	=c.Id_Caja	and
							d.Autorizacion	=c.Autorizacion	and
							d.serie		=c.serie	and
							d.Id_Tipo	=c.Id_Tipo	and
							d.Numero	=c.Numero
						inner join	tbl_productos		p
						on	d.Id_Empresa	=p.Id_empresa	and
							d.Id_Producto	=p.Id_producto
						
Where	d.Id_Empresa	=@Id_Empresa	and
	d.Id_Producto	=@Id_Producto	and
	datediff(day,c.fecha_factura,@Fecha_Fin)	between 0
-- =============================
-- SP: rpt_kardex_clientes
-- =============================




--set dateformat dmy
--drop procedure rpt_kardex_clientes
---exec rpt_kardex_clientes 1,'C1045','01/01/2009','31/12/2017'
CREATE procedure [dbo].[rpt_kardex_clientes] 	@Id_Empresa	int,
					@Nit		char(20),
					@fecha_inicial	datetime,
					@fecha_final	datetime  as

	
/*set @Id_Empresa	=	1
set @Nit='341536-8'
set @fecha_inicial	='01/01/2000'
set @fecha_final	='15/01/2006'*/
Declare @Nombre_Empresa	char(80),@nombre_proveedor char(150)
select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa

select @Nombre_proveedor=nombre from tbl_proveedores	 where id_empresa=@Id_empresa and nit=@nit

SELECT 	@Nombre_empresa as nombreempresa,
	RTRIM(LTRIM(@nit))+' '+@Nombre_proveedor as  nombre_proveedor,
	@fecha_inicial as fecha,--seleccionando los envioscorrespondientes al periodo
	' INI' as Id_tipo,
	0 as numero,
	'' as recibo,
	'Saldo Inicial al' as concepto,
	dbo.saldo_ini_clientes( @Id_empresa,@NIT,@Fecha_inicial)   as total_envio
	union all

SELECT 	@Nombre_empresa as nombreempresa,
	RTRIM(LTRIM(@nit))+' '+@Nombre_proveedor as  nombre_proveedor,
	c.Fecha,--seleccionando los envioscorrespondientes al periodo
	c.Id_Tipo,
	c.Numero,
	'' as recibo,
	c.concepto,
	
	(select sum(total) as total  from tbl_detalle_movimientos d 
	where 	d.Id_empresa	=c.Id_Empresa 	and
		d.Periodo	=c.Periodo	and
		d.Id_bodega	=c.Id_bodega	and
		d.Id_tipo	=c.Id_tipo	and
		d.Numero	=c.Numero	and
		d.Nit		=c.Nit) as total_envio
	FROM TBL_CABECERA_MOVIMIENTOS c
where 	c.Id_empresa	=@Id_Empresa	and
	c.Nit		=@Nit		and
	c.Id_Tipo		='ENV'		and
	datediff(day,c.fecha,@fecha_final)	between	0	and datediff(day,@fecha_inicial,@fecha_final)
union all
select @Nombre_empresa as nombreempresa,
	LTRIM(RTRIM(@nit))+' '+@Nombre_proveedor as  nombre_proveedor,
	Fecha_docto,--seleccionando los cargos correspondientes al perido
	Tipo_docto,
	Numero_docto,
	''  as recibo,
	descripcion ,
	
	valor_docto from tbl_cuentas_por_cobrar
where	Id_empresa	=@Id_Empresa	and
	Nit		=@Nit		and
	datediff(day,fecha_docto,@fecha_final)	between 0	and datediff(day,@fecha_inicial,@fecha_final) and status=1
union all--seleccinando los cobros correspondientes al periodo
select @Nombre_empresa as nombreempresa,
	LTRIM(RTRIM(@nit))+' '+@Nombre_proveedor as  nombre_proveedor,
	Fecha_docto,
	Id_Tipo_cobro,
	num_docto_cobro,
	no_recibo AS recibo,
	Descripcion,
	(efectivo+valor_cheque+valor_tarjeta+valor_deposito)*-1 as total_cobro
from tbl_cobros
where	Id_Empresa	=@Id_Empresa	and
	nit		=@nit		and
	datediff(day,fecha_docto,@fecha_final)	between	0	and datediff(day,@fecha_inicial,@fecha_final)
union all
select @Nombre_empresa as nombreempresa,
	LTRIM(RTRIM(@nit))+' '+@Nombre_proveedor as nombre_proveedor,
	a.fecha_anticipo,
	'ANT',
	A.ID_NUMERO_ANTICIPO,
	'' as recibo,
	A.DESCRIPCION,
	(a.Valor_anticipo  *-1 ) AS TOTAL_COBRO		
	from tbl_anticipos_clientes a
 where 	a.Id_empresa=@Id_empresa	and
		A.id_cliente	=@NIT 		AND
		DATEDIFF(DAY, a.fecha_anticipo,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final)
UNION all
SELECT @Nombre_empresa as nombreempresa,
	LTRIM(RTRIM(@nit))+' '+@Nombre_proveedor as nombre_proveedor,
	a.fecha,
	'RET',
	Numero_docto,
	'' as recibo,
	'Segun retención IVA',
	(Valor_retencion_iva * -1) AS TOTAL_RETENCION
	FROM Tbl_cuentas_por_cobrar_retencion_iva a
WHERE Id_empresa=@Id_Empresa and
      Nit=@Nit  and
      DATEDIFF(day,a.fecha,@fecha_final) between 0 and DATEDIFF(day,@fecha_inicial,@fecha_final)	

union all
select	@Nombre_Empresa as nombreempresa,
		@nombre_proveedor as nombre_proveedor,
		c.fecha_docto,
		'RET'    as id_tipo_cobro,
		'999'    as numero_docto,
		''       as recibo,
		'Retencion ISR',
		(Retencion_ISR * -1) from db_inventario_pfp.dbo.Tbl_cuentas_por_cobrar c
where	id_empresa	=@Id_empresa	and
		nit			=@nit			AND
		DATEDI
