-- SP: rpt_kardex_clientes_docto
-- =============================




--set dateformat dmy
--exec rpt_kardex_clientes_docto 1,'12345','FAC',2003,'03/05/2006','31/12/2018'
CREATE procedure [dbo].[rpt_kardex_clientes_docto] 	@Id_Empresa	int,
						@Nit		char(20),
						@Tipo		char(3),
						@Numero_docto	numeric(10),
						@fecha_inicial	datetime,
						@fecha_final	datetime  as

	
/*set @Id_Empresa	=	1
set @Nit='341536-8'
set @fecha_inicial	='01/01/2000'
set @fecha_final	='15/01/2006'*/
Declare @Nombre_Empresa	char(80),@nombre_proveedor char(150)
select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa

select @Nombre_proveedor=nombre from tbl_proveedores	 where id_empresa=@Id_empresa and nit=@nit
SELECT
	@Nombre_empresa 	as nombreempresa,
	@nombre_proveedor 	as nombre_proveedor,
	@fecha_inicial as fecha,
	' ' as id_tipo,
	0 as numero,
	'Saldo Inicial '	as concepto,
	(select  dbo.saldo_inicial_por_factura(@Id_empresa,@nit,@tipo,@numero_docto,@fecha_inicial)) as total_envio
union all
SELECT 	@Nombre_empresa as nombreempresa,
	@Nombre_proveedor as  nombre_proveedor,
	c.Fecha,--seleccionando los envioscorrespondientes al periodo
	c.Id_Tipo,
	c.Numero,
	c.concepto,
	(select sum(total) as total  from tbl_detalle_movimientos d 
	where 	d.Id_empresa	=c.Id_Empresa 	and
		d.Periodo	=c.Periodo	and
		d.Id_bodega	=c.Id_bodega	and
		d.Id_tipo	=c.Id_tipo	and
		d.Numero	=c.Numero	and
		d.Nit		=c.Nit) as total_envio
	FROM TBL_CABECERA_MOVIMIENTOS c
where 	c.Id_empresa	=@Id_Empresa	and
	c.Nit		=@Nit		and
	c.Id_Tipo	=@Tipo		and
	c.Numero	=@numero_docto	and
	datediff(day,c.fecha,@fecha_final)	between	0	and datediff(day,@fecha_inicial,@fecha_final)
union all
select @Nombre_empresa 		as nombreempresa,
	@Nombre_proveedor 	as nombre_proveedor,
	Fecha_docto 		as fecha,--seleccionando los cargos correspondientes al perido
	Tipo_docto		as Id_Tipo,
	Numero_docto		as Numero,
	descripcion 		as concepto,
	valor_docto from tbl_cuentas_por_cobrar
where	Id_empresa	=@Id_Empresa	and
	Nit		=@Nit		and
	Tipo_docto	=@Tipo		and
	numero_docto	=@numero_docto	and
	datediff(day,fecha_docto,@fecha_final)	between 0	and datediff(day,@fecha_inicial,@fecha_final)
union all--seleccinando los cobros correspondientes al periodo
select @Nombre_empresa 		as nombreempresa,
	@Nombre_proveedor 	as  nombre_proveedor,
	c.Fecha_docto		as fecha,
	c.Id_Tipo_cobro		as id_tipo,
	c.num_docto_cobro	as numero,
	c.Descripcion		as concepto,
	(d.Valor_aplicado*-1) 	as total_envio
from tbl_cobros c	inner join tbl_det_cobros d	on
					c.Id_empresa		=d.Id_empresa		and
					c.Id_Tipo_cobro		=d.Id_Tipo_cobro	and
					c.Num_docto_cobro	=d.num_docto_cobro
where	c.Id_Empresa	=@Id_Empresa	and
	c.nit		=@nit		and
	datediff(day,c.fecha_docto,@fecha_final)	between	0	and datediff(day,@fecha_inicial,@fecha_final) and
	Id_Tipo		=@Tipo		and
	Numero		=@Numero_docto	and
	d.Valor_aplicado<>0
union all --seleccionando los anticipos
select 	@Nombre_empresa 		as nombreempresa,
	@Nombre_Proveedor		as nombre_proveedor,
	c.fecha_anticipo		as fecha_docto,
	'ANT'				as id_tipo_cobro,
	c.Id_Numero_anticipo		as numero,
	c.descripcion as concepto,
	(d.valor_aplicado*-1)		as total_envio FROM TBL_ANTICIPOS_CLIENTES c	left join tbl_detalle_anticipos_clientes d
							on	c.id_Empresa		=d.Id_Empresa	and
								c.Id_Numero_Anticipo	=d.Id_Numero_Anticipo
where	c.Id_Empresa	=@Id_Empresa	and
	c.Id_cliente	=@Nit		and
	datediff(day,c.fecha_anticipo,@fecha_final)	between 0	and datediff(day,@fecha_inicial,@fecha_final) and
	d.tipo_docto	=@Tipo		and
	d.numero_docto	=@Numero_docto
union all
select @Nombre_Empresa  as nombreempresa,
		@nombre_proveedor as nombre_proveedor,
		c.fecha  ,
		'RET'     as id_tipo_cobro,
		c.numero_docto,
		'Retención IVA',
		(Valor_retencion_iva * -1) as total from dbo.Tbl_cuentas_por_cobrar_retencion_iva  c
where	c.id_empresa	=@Id_Empresa	and
		c.Nit
-- =============================
-- SP: rpt_kardex_vales
-- =============================
CREATE procedure rpt_kardex_vales	@Id_empresa int,
									@Id_cliente_vale varchar(20),
									@Del datetime as

set dateformat dmy		




select
 ( select Nombre_Empresa from empresas where Id_Empresa=@Id_empresa ) AS NOMBRE_EMPRESA,
'INI' as serie,
0 as numero_factura,
@Id_cliente_vale as id_cliente_vale,
(select nombre from Tbl_Proveedores where Id_Empresa=@Id_empresa and Nit=@Id_cliente_vale) as nombrecliente,
0 as id_vale,
dateadd( day,-1,@Del) as fecha,
 isnull(SUM(x.debe) ,0) as debe,
 0 AS haber
	
from
(
select 
sum(D.CANTIDAD_VALES*d.VALOR_VALES)  as debe
		 from dbo.TBL_CABECERA_VENTAS_VALE c, dbo.TBL_DETALLE_CANTIDAD_VALES_VENDIDOS d
where c.ID_EMPRESA=d.ID_EMPRESA and
c.SERIE=d.SERIE and
c.NUMERO=d.NUMERO_FACTURA AND
C.ID_CLIENTE_VALE =@Id_cliente_vale and
DATEDIFF(day,@Del,c.FECHA_FACTURA  ) <0
group by d.SERIE,d.NUMERO_FACTURA ,c.id_cliente_vale,c.FECHA_FACTURA 
union all
select 
		(VALOR_VALE*-1) as debe
		from dbo.TBL_DETALLE_VENTAS_VALES
where ID_EMPRESA=@Id_empresa and
DATEDIFF(day,@Del,fecha_vale) <0 and
ID_CLIENTE_VALE_DETALLE =@Id_cliente_vale) x

union all 

select 
( select Nombre_Empresa from empresas where Id_Empresa=@Id_empresa ) AS NOMBRE_EMPRESA,
		D.SERIE,
		D.NUMERO_FACTURA ,
		c.ID_CLIENTE_VALE ,
		(select nombre from Tbl_Proveedores where Id_Empresa=@Id_empresa and Nit=@Id_cliente_vale) as nombrecliente,
		0 as id_vale,
		c.FECHA_FACTURA ,
		sum(D.CANTIDAD_VALES*d.VALOR_VALES)  as debe,
		0 as haber from dbo.TBL_CABECERA_VENTAS_VALE c, dbo.TBL_DETALLE_CANTIDAD_VALES_VENDIDOS d
where c.ID_EMPRESA=d.ID_EMPRESA and
c.SERIE=d.SERIE and
c.NUMERO=d.NUMERO_FACTURA AND
C.ID_CLIENTE_VALE =@Id_cliente_vale and
DATEDIFF(day,@Del,c.FECHA_FACTURA ) >=0
group by d.SERIE,d.NUMERO_FACTURA ,c.id_cliente_vale,c.FECHA_FACTURA 
union all

select 
( select Nombre_Empresa from empresas where Id_Empresa=@Id_empresa ) AS NOMBRE_EMPRESA,
SERIE,
		NUMERO_FACTURA ,
		id_cliente_vale_detalle,
		(select nombre from Tbl_Proveedores where Id_Empresa=@Id_empresa and Nit=@Id_cliente_vale) as nombrecliente,
		ID_VALE_POST_PAGO  as id_vale,
		FECHA_VALE ,
		0 as debe,
		VALOR_VALE as haber
		from dbo.TBL_DETALLE_VENTAS_VALES
where ID_EMPRESA=@Id_empresa and
ID_CLIENTE_VALE_DETALLE =@Id_cliente_vale
order by fecha  

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: rpt_Listado_inventario
-- =============================




--SET DATEFORMAT DMY


--SELECT *FROM TBL_EXISTENCIA WHERE PERIODO='02/2006' AND ID_PRODUCTO='1493'
--EXEC rpt_Listado_inventario 1,'31/03/2006',1
CREATE procedure rpt_Listado_inventario @Id_Empresa int,@Fecha_fin datetime,@incluye_ptransito int as
--@incluye_ptransito=1= incluye productos en transito
--@incluye_ptransito=2	no incluye productos en transito

Declare @Periodo 	char(7),
	@Periodo_Anterior char(7),
	@Fecha_Ini	datetime,
	@Nombre_empresa char(150)

set dateformat dmy

set @Periodo	=Replicate('0',2-len( ltrim(rtrim(cast(Month(@Fecha_Fin) as char))) ))+ltrim(rtrim(cast(Month(@Fecha_Fin) as char)))+'/'+cast(year(@Fecha_Fin) as char)

SET @Fecha_ini='01/'+@Periodo


Declare @fecha_Inicial datetime
set @fecha_inicial=dateadd(month,-1, cast('01/'+@Periodo as datetime))
set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_inicial) as char)))))+ltrim(rtrim(str(month(@fecha_inicial))))+'/'+cast( year(@fecha_inicial) as char)

Declare @Id_Producto 	char(15),
	@Existencia	numeric(12,5)

create table #temporal(Id_Producto 		char(15)COLLATE Modern_Spanish_CI_AS  ,
			Existencia		numeric(10),
			Existencia_transito	numeric(10))
	
--insertando saldo inicial
insert #temporal
select 	e.Id_Producto,
	SUM(e.Existencia)		as existencia,
	
	0,
	0
	from tbl_existencia e,tbl_productos p
		WHERE 	e.Id_Empresa	=p.Id_Empresa		and
			e.Id_Producto	=p.Id_Producto		and
			e.Id_Empresa	=@Id_Empresa		and 
			e.Periodo	=@Periodo_Anterior	
		group by e.Id_Empresa,e.Id_producto



Declare productos cursor for
select Id_Producto from tbl_productos where Id_Empresa=@Id_Empresa and es_servicio=2 
Open productos
fetch productos into @Id_Producto
while @@fetch_status=0
begin
--insertando las facturas
	insert #temporal
	select 	d.Id_Producto,
		SUM(Case when d.Id_Tipo='FAC'
			THEN (d.cantidad*-1)
			ELSE (d.cantidad) end),
		
		0,
		0
		from tbl_det_facturacion	d	left join	tbl_cab_facturacion	c
							on	d.Id_Empresa	=c.Id_Empresa	and
								d.Id_Caja	=c.Id_Caja	and
								d.Autorizacion	=c.Autorizacion	and
								d.serie		=c.serie	and
								d.Id_Tipo	=c.Id_Tipo	and
								d.Numero	=c.Numero
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.Id_empresa	and
								d.Id_Producto	=p.Id_producto
	Where	d.Id_Empresa		=@Id_Empresa	and
		d.Id_Producto		=@Id_Producto	and
		d.rebaja_existencias	=1		and
		datediff(day,c.fecha_factura,@Fecha_Fin)	between 0	and datediff(day,@Fecha_Ini,@Fecha_Fin)
	group by d.Id_Producto


--insertando los movimientos de inventarios
	insert #temporal
	select d.Id_producto,	
		SUM(Case when t.efecto_inv=1
			Then (d.cantidad)
			Else d.cantidad*-1 end),
		
		0,
		0
		from tbl_detalle_movimientos d	left join	tbl_cabecera_movimientos c
							on	d.Id_Empresa	=c.Id_Empresa	and
								d.Periodo	=c.Periodo	and
								d.Id_Bodega	=c.Id_Bodega	and
								d.Id_Tipo	=c.Id_Tipo	and
								d.Numero	=c.Numero
							inner join	tbl_tipos_inv		t
							on	d.Id_Empresa	=t.Id_Empresa	and
								d.Id_Tipo	=t.Id_Tipo
							inner join	tbl_productos		p
							on	d.Id_Empresa	=p.Id_empresa	and
								d.Id_Producto	=p.Id_producto

	where 	d.id_empresa	=@Id_Empresa		and
		d.Id_Producto	=@Id_Producto		and
		datediff(day,c.fecha,@Fecha_fin)		between	0	and datediff(day,@Fecha_Ini,@Fecha_Fin)
	group by d.id_producto

	If @incluye_ptransito=1
	begin
--insertando ordenes de compra unicamente que esten facturadas
		insert #temporal
		SELECT  i.id_producto,
		sum(i.cantidad*-1) as cantidad,
		
		0,
		0  from tbl_orden_servicio o	inner join tbl_orden_servicio_detalle_integracion i 
							on o.Id_Empresa=i.id_empresa and o.id_orden=i.id_orden
		where o.id_Empresa=@id_empresa and
			datediff(day,i.fecha_hora,@Fecha_Fin)	between 0	and datediff(day,@Fecha_Ini,@Fecha_Fin) and
			i.id_producto	=@Id_Producto a
-- =============================
-- SP: rpt_listado_ordenes_compras
