CREATE procedure rpt_listado_ordenes_compras @Id_empresa int,@del datetime, @al datetime, @Tipo_reporte int,@estatus int  as

--1 Sumario
--2 Detallado
select *from dbo.vw_ordenes_compra
where Id_empresa=@Id_empresa and
datediff(day,fecha_pedido, @al) between 0 and
datediff(day,@del,@al) and
orden_recibida_completa= case when @estatus=2 	--estatus=0 no recibida,1=recibida total, 2todas
				then orden_recibida_completa
				else @estatus end


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_listado_para_inventario_fisico
-- =============================


--exec rpt_listado_para_inventario_fisico 1
--select *from tbl_productos
CREATE procedure [dbo].[rpt_listado_para_inventario_fisico] @Id_Empresa int,@orden int as

Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa



select 	@nombre_empresa as nombreempresa,
	p.Id_Producto,
	p.Descripcion,
	p.Id_depto,
	d.nombre as nombredepto,
	p.Id_Linea,
	l.nombre_linea
	from tbl_productos p, tbl_departamentos d,tbl_linea l
where 	p.Id_Empresa	=@Id_empresa	and
	p.Es_servicio	=2		and
	p.Id_Empresa	=d.Id_empresa	and
	p.Id_depto	=d.Id_depto	and
	p.Id_depto	=l.Id_depto	and
	p.Id_Linea	=l.Id_linea
order by p.Id_depto,L.Id_Linea,p.id_producto	



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
