-- =============================
-- SP: rpt_movimiento
-- =============================

--select *from tbl_cabecera_movimientos
--exec rpt_movimiento 1,'09/2009','01','ENV','11'
--procedimiento que imprime el reporte de un  movimiento especifico
CREATE procedure [dbo].[rpt_movimiento] @Id_Empresa	int,
				@Periodo	char(7),
				@Id_Bodega	char(10),
				@Id_Tipo	char(3),
				@Numero		char(10) as

	
Declare @Nombre_Empresa	char(150)
select @Nombre_Empresa=Nombre_empresa from empresas where id_Empresa=@Id_Empresa

SELECT 	@Nombre_Empresa AS NOMBRE_EMPRESA,
	c.Id_Tipo,
	c.Numero,
	c.Fecha,
	c.Concepto,
	c.Nit,
	d.Id_Producto,
	p.descripcion,
	p.descripcion_corta,
	d.Cantidad,
	d.Costo,
	d.Precio,
	d.Total,
	prov.nombre 	as nombreproveedor,
	C.DIRECCION     AS direccion_entrega,
	prov.direccion 	as direccion_proveedor,
	c.usuario,
	ltrim(rtrim(deptos.id_depto))+' '+deptos.nombre as departamento,
	ltrim(rtrim(lin.id_linea))+' '+lin.nombre_linea as linea
	FROM TBL_CABECERA_MOVIMIENTOS c	left join tbl_detalle_Movimientos d
					on 	c.Id_Empresa	=d.Id_Empresa	and
						c.Periodo	=d.Periodo	and
						c.Id_Bodega	=d.Id_Bodega	and
						c.Id_Tipo	=d.Id_Tipo	and
						c.Numero	=d.numero
					left join tbl_productos		p
					on	d.Id_Empresa	=p.Id_Empresa	and
						d.Id_Producto	=p.Id_producto
					left join tbl_proveedores	prov
					on	c.Id_Empresa	=prov.Id_empresa	and
						c.Nit		=prov.Nit
					left join	tbl_departamentos	deptos
					on	p.id_empresa	=	deptos.id_empresa	and
						p.id_depto	=	deptos.id_depto
					left join	tbl_linea      lin
					on	p.id_empresa	=lin.id_empresa		and
						p.id_depto		=lin.id_depto		and
						p.id_linea	=lin.id_linea
	Where 	c.Id_Empresa	=@Id_Empresa	and
		c.Periodo	=@Periodo	and
		c.Id_Bodega	=@Id_Bodega	and
		c.Id_Tipo	=@Id_Tipo	and
		c.Numero	=@Numero

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
-- =============================
-- SP: rpt_nota_credito
-- =============================

CREATE  procedure [dbo].[rpt_nota_credito]  	@Id_Empresa	int,
				@Id_Caja	int,
				@Autorizacion	char(20),
				@Serie		char(3),
				@Id_Tipo	char(3),
				@Numero		Numeric(10) as

Declare @orden_servicio	int,
	@Num_placa	char(10),
	@lectura_actual	int,
	@proximo_servicio int,
	@marca	char(25),
	@modelo	char(4),
	@presion	int,
	@fecha_ingreso datetime
	
SELECT top 1 	@Orden_Servicio		=Id_orden,
		@Num_placa		=Num_PLaca,
		@Lectura_actual		=Lectura_actual,
		@Fecha_ingreso		=fecha,	
		@Proximo_servicio	=Proximo_servicio FROM TBL_ORDEN_SERVICIO 
WHERE 	AUTORIZACION=@Autorizacion	AND
	SERIE	=@Serie		AND
	TIPO	=@Id_Tipo		AND
	NUMERO	=@Numero

select @marca=marca,
	@modelo=modelo,
	@presion=presion_llantas from tbl_vehiculos 
where id_empresa=@Id_empresa and num_placa=@num_placa

Select @ORDEN_SERVICIO AS ORDEN_SERVICIO,
	@NUM_PLACA AS NUMERO_PLACA,
	@LECTURA_ACTUAL AS LECTURA_ACTUAL,
	@PROXIMO_SERVICIO AS PROXIMO_SERVICIO,
	@MARCA AS MARCA,
	@MODELO AS MODELO,
	@PRESION AS PRESION,
	@FECHA_INGRESO AS FECHA_INGRESO,
	(SELECT Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_empresa,
	(SELECT Nombre_comercial FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nombre_comercial,
	(SELECT Nit FROM EMPRESAS where Id_Empresa=@Id_Empresa) as nit_empresa,
	(SELECT Direccion FROM EMPRESAS where Id_Empresa=@Id_Empresa) as direccion_empresa,
	a.*,
	d.Id_Producto,
	d.Cantidad,
	d.Descripcion_Corta,
	d.Precio,
	d.precio_descuento,
	d.Total_Linea,
	p.direccion,
	p.telefono1,
	p.num_casa,
	p.apto,
	p.zona,p.ciudad,
	p.tarjeta as tbeneficio,
	'Autorizacion '+ltrim(rtrim(cast(x.del as char)))+  ' Al '+ ltrim(rtrim(cast(x.al as char))) AS rango_autorizacion,
	(select Fecha_ingreso from tbl_series
	 where id_empresa=@Id_empresa and autorizacion=a.autorizacion) as fecha_ingreso
	 from Tbl_Cab_Notas_credito a	left join Tbl_Det_Notas_credito d
				on 	a.Id_Empresa	=d.Id_Empresa	and
					a.Id_Caja		=d.Id_Caja	and
					a.Autorizacion	=d.Autorizacion	and
					a.serie			=d.Serie	and
					a.Id_Tipo		=d.Id_Tipo	and
					a.Numero		=d.Numero
							inner join Tbl_Proveedores p
				on	a.Id_Empresa	=p.Id_Empresa	and
					a.nit		=p.nit
							inner join tbl_series x
				on	a.id_empresa=x.id_empresa	and
					a.autorizacion=x.autorizacion and
					a.serie=x.serie					and
					a.id_tipo=x.id_tipo
WHERE 	a.Id_Empresa	=@Id_Empresa	and
	a.Id_Caja	=@Id_Caja	and
	a.Autorizacion	=@Autorizacion	and
	a.Serie		=@Serie		and
	a.Id_Tipo	=@Id_Tipo	and
	a.Numero	=@Numero






GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: rpt_orden_compra_proyecto
-- =============================
--select *from tbl_orden_compra_proyecto p

--exec rpt_orden_compra_proyecto 140
CREATE procedure [dbo].[rpt_orden_compra_proyecto] @Id_Orden_Compra_proyecto int as




select 
(select nombre_empresa from empresas e where id_empresa=p.id_empresa) as Nombre_Empresa,
       pr.Id_transaccion_Proyecto as codigo_proyecto,
	   pr.Descripcion_Proyecto,
	   pr.id_proyecto,
       pv.Nit,
	   pv.Nombre,
	   case when pv.Credito_o_Contado=1 then 'CONTADO' ELSE 'CREDITO'  END AS CONTADO_O_CREDITO,
	   pv.dias_credito,
	   case when pv.regimen_contribyente=1 then 'CON RETENCIÓN' else 'SIN RETENCIÓN' END AS regimen_contribuyente,

       p.[Id_Orden_Compra_Proyecto]
      ,p.[Id_transaccion_Proyecto]
      ,p.[Id_Empresa]
      ,p.[Fecha_Orden_Compra_proyecto]
      ,p.[Descripcion]
      ,p.[Usuario]
      ,p.[Fecha_hora_transaccion]
      ,p.[Estado_OC]
      ,p.[Nit]
      ,p.[Numero_Orden_Compra]
      ,p.[Orden_Facturada]
      ,p.[Id_Cuenta]
      ,p.[Id_Auxiliar]
	  ,d.[Id_Tbl_Orden_Compra_Proyecto_Detalle]
      ,d.[Id_Orden_Compra_Proyecto]
      ,d.[Id_Rubro]
      ,d.[Cantidad_Presupuesto]
      ,d.[Costo]
      ,d.[Cantidad_OC]
      ,d.[Usuario]
      ,d.[Fecha_hora_transaccion]
      ,d.[Cantidad_Comprada]
      ,d.[Id_Transaccion_Tbl_Rubro]
      ,d.[Descripcion_rubro]
      ,d.[Nivel]
      ,d.[Operativo]
      ,d.[Ejecutado]
      ,d.[Precio_Oc]
      ,d.[TotalCompraLinea]

from tbl_orden_compra_proyecto p inner join
Tbl_Orden_Compra_Proyecto_Detalle d
on p.Id_Orden_Compra_Proyecto=d.Id_Orden_Compra_Proyecto inner join
tbl_proveedores pv 
on p.Id_Empresa=pv.Id_Empresa and p.Nit=pv.Nit  
inner join Tbl_Proyecto pr
on p.Id_transaccion_Proyecto=pr.Id_transaccion_Proyecto
where p.id_orden_compra_proyecto=@Id_Orden_Compra_Proyecto and Cantidad_OC<>0 and TotalCompraLinea<>0



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
