CREATE procedure [dbo].[rpt_orden_compras]  @Id_Transaccion_Mproyecto int, @Id_transaccion_Proyecto int as
select 
(select nombre_empresa from empresas where id_empresa=m.id_empresa) as nombre_empresa,
*,
u.descripcion as descripcion_unidad_medida from tbl_mproyecto m inner join
Tbl_Proyecto p
on m.Id_Transaccion_Mproyecto=p.Id_Transaccion_Mproyecto
inner join Tbl_Rubro_Proyecto r
on p.Id_transaccion_Proyecto=r.Id_Transaccion_Proyecto
inner join Tbl_Unidad_Medida u 
on r.id_medida=u.id_medida

--where m.Id_Transaccion_Mproyecto=@Id_Transaccion_Mproyecto-- and
--p.Id_transaccion_Proyecto=@Id_transaccion_Proyecto
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
