--exec rpt_orden_servicio 1,'5047'
--select *from tbl_orden_servicio
--select *from tbl_orden_servicio_DETALLE
--exec rpt_orden_servicio 2,2,'O'
CREATE procedure [dbo].[rpt_Orden_servicio] @Id_Empresa	int,@Id_Orden	int,@tipo char(1)  as
--@@tipo='O'=Orden Servicio 'P'=resupuesto
--Procedimiento que imprime orden servicio
if @tipo='O'
Begin
select 	m.id_empresa,
	(select Nombre_Empresa from empresas where id_Empresa=@Id_Empresa) as nombre_empresa,
	m.Id_Orden,
	m.Num_Placa,
	m.Nit,
	m.Facturar_a,
	m.Recibe_Orden,
	m.Fecha,
	m.fecha_cierre,
	m.fecha_facturacion,
	(case when m.status=1
		Then 'Abierto'
		Else 'Cerrado'end) as estado,
	m.Observaciones ,
	m.Lectura_actual,
	m.Proximo_Servicio,
	d.linea as lineadedetalle,
	d.Id_Servicio,
	d.Descripcion,
	d.Id_Empleado,
	d.Fosa,
	d.Precio,
	d.Precio_descuento,
	d.Otros,
	d.Otros_descuento,
	d.Total_Linea,
	d.Cantidad,
	p.Telefono,
	p.tarjeta,
	'S' AS SE_COBRA
	 from tbl_orden_servicio m	INNER JOIN tbl_orden_servicio_detalle d
					on 	m.Id_Empresa	=d.Id_Empresa		and
						m.Id_Orden	=d.Id_Orden
					
					INNER JOIN tbl_proveedores	p
					on	m.Id_Empresa	=	p.Id_Empresa	and
						m.Nit		=	p.Nit

where	m.Id_Empresa	=@Id_Empresa	and
	m.Id_Orden	=@Id_Orden
--union all
select 	m.id_empresa,
	(select Nombre_Empresa from empresas where id_Empresa=@Id_Empresa) as nombre_empresa,
	m.Id_Orden,
	m.Num_Placa,
	m.Nit,
	m.Facturar_a,
	m.Recibe_Orden,
	m.Fecha,
	m.fecha_cierre,
	m.fecha_facturacion,
	(case when m.status=1
		Then 'Abierto'
		Else 'Cerrado'end) as estado,
	m.Observaciones,	
	m.Lectura_actual,
	m.Proximo_Servicio,
	d.linea as lineadedetalle,
	d.Id_Producto,
	d.Descripcion,
	' ',
	'',
	d.Precio,
	d.Precio_descuento,
	0.00,
	0.00,
	d.Total_Linea,
	d.Cantidad,
	p.Telefono,
	p.tarjeta,
	d.se_cobra
	 from tbl_orden_servicio m	INNER JOIN tbl_orden_servicio_detalle_integracion d
					on 	m.Id_Empresa	=d.Id_Empresa		and
						m.Id_Orden	=d.Id_Orden
					
					INNER JOIN tbl_proveedores	p
					on	m.Id_Empresa	=	p.Id_Empresa	and
						m.Nit		=	p.Nit

where	m.Id_Empresa	=@Id_Empresa	and
	m.Id_Orden	=@Id_Orden
end
else
begin
select 	m.id_empresa,
	(select Nombre_Empresa from empresas where id_Empresa=@Id_Empresa) as nombre_empresa,
	m.Id_Orden,
	m.Num_Placa,
	m.Nit,
	m.Facturar_a,
	m.Recibe_Orden,
	m.Fecha,
	m.fecha_cierre,
	m.fecha_facturacion,
	(case when m.status=1
		Then 'Abierto'
		Else 'Cerrado'end) as estado,
	m.Observaciones,	
	m.Lectura_actual,
	m.Proximo_Servicio,
	d.linea as lineadedetalle,
	d.Id_Servicio,
	d.Descripcion,
	d.Id_Empleado,
	d.Fosa,
	d.Precio,
	d.Precio_descuento,
	d.Otros,
	d.Otros_descuento,
	d.Total_Linea,
	d.Cantidad,
	p.Telefono,
	p.tarjeta,
	'S' AS SE_COBRA
	 from tbl_presupuesto_orden_servicio m	INNER JOIN tbl_presupuesto_orden_servicio_detalle d
					on 	m.Id_Empresa	=d.Id_Empresa		and
						m.Id_Orden	=d.Id_Orden
				
					INNER JOIN tbl_proveedores	p
					on	m.Id_Empresa	=	p.Id_Empresa	and
						m.Nit		=	p.Nit

where	m.Id_Empresa	=@Id_Empresa	and
	m.Id_Orden	=@Id_Orden
union all
select 	m.id_empresa,
	(select Nombre_Empresa from empresas where id_Empresa=@Id_Empresa) as nombre_empresa,
	m.Id_Orden,
	m.Num_Placa,
	m.Nit,
	m.Facturar_a,
	m.Recibe_Orden,
	m.Fecha,
	m.fecha_cierre,
	m.fecha_facturacion,
	(case when m.status=1
		Then 'Abierto'
		Else 'Cerrado'end) as estado,
	m.Observaciones,	
	m.Lectura_actual,
	m.Proximo_Servicio,
	d.linea as lineadedetalle,
	d.Id_Producto,
	d.Descripcion,
	' ',
	'',
	d.Precio,
	d.Precio_descuento,
	0.00,
	0.00,
	d.Total_Linea,
	d.Cantidad,
	p.Telefono,
	p.tarjeta,
	d.se_cobra
	 from tbl_presupuesto_orden_servicio m	INNER JOIN tbl_presupuesto_orden_servicio_detalle_integracion d
					on 	m.Id_Empresa	=d.Id_Empresa		and
						m.Id_Orden	=d.Id_Orden
				
					INNER JOIN t
