-- SP: rpt_ordenes_trabajadas
-- =============================








--set dateformat dmy
--SELECT *FROM TBL_ORDEN_SERVICIO_detalle
--select *from tbl_cab_facturacion
--select *from tbl_orden_
--exec rpt_ordenes_trabajadas 1,'TODO','01/01/2000','31/12/2006'

CREATE procedure rpt_ordenes_trabajadas  @Id_Empresa	int,
					@Id_Empleado	char(4),
					@Fecha_Inicial 	datetime,
					@Fecha_Final	datetime as
--select *from tbl_cab_facturacion
--select *from tbl_orden_servicio
Declare  @Nombre_Empresa char(150)
SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
SELECT @Nombre_empresa as nombre_empresa,
	o.Id_Orden,
	F.Fecha_FACTURA AS FECHA,
	d.Id_servicio,
	d.descripcion,
	d.Id_Empleado,
	v.nombre,
	d.Fosa,
	d.cantidad,
	d.Precio,
	d.Precio_descuento,
	f.serie,
	f.id_tipo,
	f.numero from tbl_cab_facturacion	f	inner join 	tbl_orden_servicio o	
					on	f.Id_Empresa	=o.Id_Empresa	and
						f.Autorizacion	=o.Autorizacion	and
						f.serie		=o.Serie	and
						f.id_tipo	=o.tipo		and
						f.numero	=o.numero
						inner join tbl_orden_servicio_detalle	d
					on 	o.Id_Empresa	=d.Id_empresa	and
						o.Id_Orden	=d.Id_orden
						inner join tbl_vendedores	v
					on	d.Id_empresa	=v.Id_empresa	and
						d.Id_empleado	=v.Id_empleado
	where 	f.Id_Empresa=@Id_Empresa	and
		Datediff(day,f.Fecha_factura,@Fecha_Final)	between 0	and datediff(day,@fecha_inicial,@fecha_final)	and
		d.Id_Empleado	=(case when @Id_Empleado='TODO'
						THEN d.Id_Empleado
						Else @Id_Empleado end)



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: rpt_pedidos_a_proveedores
-- =============================


--SELECT *FROM tbl_proveedores where nit='660369-6'




--exec rpt_pedidos_a_proveedores 1,3,1
--select *from tbl_proveedores
CREATE procedure [dbo].[rpt_pedidos_a_proveedores] @Id_empresa	int,@id_pedido int,@tipo_reporte int as
--@tipo_reporte=1=Pedidos
--@tipo_reporte=2=Recepcion pedidos


select 	(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombre_empresa,
	p.Id_Pedido,
	p.Nit,
	v.nombre,
	p.Fecha_Pedido,
	P.nit_cliente,
	Z.nombre as nombrecliente,
	v.contacto,
	v.telefono1,
	p.direccion_factura,
	p.direccion_entrega,
	p.recibe_orden,
	p.num_placa,
	p.observaciones,
	d.id_sproducto,
	(select descripcion from  tbl_productos a,tbl_prod_proveedores b where a.id_empresa=b.id_empresa and a.id_producto=b.id_producto and id_alterno=d.id_sproducto) as descripcion_producto,
	(select a.id_producto from  tbl_productos a,tbl_prod_proveedores b where a.id_empresa=b.id_empresa and a.id_producto=b.id_producto and id_alterno=d.id_sproducto) as Id_producto,
	(case when @tipo_reporte=1
		then d.cantidad
		else d.cantidad_recibida end) as cantidad,
	(case when @tipo_reporte=1
		then d.costo
		else d.costo_recibida end) as costo,
	p.usuario
	from tbl_pedidos p	left join tbl_detalle_pedidos d
					on	p.id_empresa	=d.id_empresa	and
						p.id_pedido	=d.id_pedido
				inner join tbl_proveedores 	v
					on	p.id_empresa	=v.id_empresa	and
						p.nit		=v.nit
				inner join tbl_proveedores 	Z
					on	p.id_empresa	=Z.id_empresa	and
						p.nit_cliente	=Z.nit

where p.id_empresa=@id_empresa	and p.id_pedido=@id_pedido









GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: RPT_PEDIDOS_SUGERIDOS
-- =============================
create  PROCEDURE [dbo].[RPT_PEDIDOS_SUGERIDOS]  @id_empresa int,
										@periodo    char(7) AS 
/*set @id_empresa =1
set @periodo = '01/2011'*/
select  @id_empresa AS ID_EMPRESA,
		(SELECT NOMBRE_EMPRESA FROM empresas WHERE Id_Empresa=@id_empresa ) AS EMPRESA,
		p.Id_Producto,
		p.Descripcion,
		P.minimo,
		P.maximo ,
		
		ISNULL(( SELECT SUM(EXISTENCIA) FROM Tbl_existencia E 
		WHERE E.Id_Empresa=P.ID_EMPRESA AND E.Id_Producto =P.ID_PRODUCTO AND E.Periodo =@periodo  ),0) AS EXISTENCIA
		  from tbl_productos p
where	p.Id_Empresa=@id_empresa  

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
