                         @Fecha_final  datetime,

                         @Tipo_reporte        int,

                         @Tipo_poliza  char(3),

                         @Numero_poliza      char(10) as

declare                           @serie_factura_aplicada char(3),

                           @numero_factura_aplicada numeric(10),

                           @fecha_nota_credito datetime,

                           @ivancr numeric(12,2),

                           @serie char(5),

                           @id_tipo char(3),

                           @numero numeric(10,0)

declare @periodo_fiscal char(4),@mes_fiscal char(2)
       declare @documento_tiene_iva int

select   @periodo_fiscal    =anio,
             @mes_fiscal       =mes from db_contabilidad_pfp.dbo.meses where   id_empresa=@id_empresa and 
                      @fecha_final between del  and al    and mes<>'00' and mes<>'13'




--si el tipo de reporte es cero es traslado preliminar si es uno es definitivo

declare @Linea      int,
       @Id_Cuenta           char(10),
       @Debe          numeric(12,2),

       @Haber                  numeric(12,2),

       @Cuenta_efectivo      char(10),   

       @Cuenta_banco       char(10),

       @cuenta_anticipo      char(10),

       @cuenta_credito               char(10),

       @cuenta_debito_cli  char(10),

       @cuenta_debito_fiscal    char(10),

       @nombre_empresa               char(200),

