       @nit               char(20),

       @id_tipo_iva      char(3),

       @facturar_a               char(100),

       @VAL_IVA           NUMERIC(12,2)



set dateformat dmy

select  @nombre_empresa   =nombre_empresa ,

       @Cuenta_efectivo           =isnull(id_cuenta_efectivo,''),

       @cuenta_banco         =isnull(id_cuenta_banco,''),

       @cuenta_anticipo           =isnull(id_cuenta_anticipo,''),

       @cuenta_credito            =isnull(id_cuenta_credito,''),

       @cuenta_debito_cli   =isnull(id_cuenta_debito,''),

       @cuenta_debito_fiscal    =isnull(id_cuenta_debito_fiscal,''),

       @porcentaje_iva_anterior=porcentaje_iva_anterior,

       @porcentaje_iva_actual  =porcentaje_iva,

       @apartirde                  =apartirde  from PITACHEFZ4.db_inventario_pfp.dbo.empresas where id_empresa=@Id_empresa



set @porcentaje_iva_anterior       =1+(@porcentaje_iva_anterior/100)

set @porcentaje_iva_actual     =1+(@porcentaje_iva_actual/100)



--si tiene instalado el modulo de contabilidad verifica que los productos a contabiizar tengan la configurada cuenta contable



If exists(

select * from 

(select (select Id_cuenta_vta from PITACHEFZ4.db_inventario_pfp.dbo.tbl_productos_configuracion_contable t

             where	t.id_empresa=d.id_empresa and
					 d.id_producto=t.id_producto) as Cuenta_Contable,

             d.id_producto as nombre_cuenta,

             'No tiene configurada cuenta contable' as descripcion,

             0 as debe,

             0 as haber

             from PITACHEFZ4.db_inventario_pfp.dbo.tbl_cab_facturacion c, 
								PITACHEFZ4.db_inventario_pfp.dbo.tbl_det_facturacion d,
								PITACHEFZ4.db_inventario_pfp.dbo.tbl_productos p

where         c.id_empresa=d.id_empresa and

                  c.id_caja=d.id_caja and

                  c.autorizacion
