--drop procedure dbo.rpt_presupuesto_proyecto
create  procedure [dbo].[rpt_presupuesto_proyecto] @Id_empresa int, @Id_transaccion_Proyecto int as
select 

	r.id_rubro_madre,
	(select nombre_empresa from empresas where id_empresa=@Id_empresa) as nombre_empresa,
	p.Descripcion_Proyecto,
	r.Operativo,
		p.Fecha_inicio,
		p.Fecha_finalizacion,

		p.moneda,
		p.Estado_Proyecto,
		r.id_rubro,
		r.Descripcion_Rubro,
		r.cantidad,
		(select descripcion from Tbl_Unidad_Medida
		where id_empresa=@id_empresa and 
		Id_medida=r.id_medida) as unidad_medida,
		r.costo,
		r.total
from tbl_proyecto p inner join
tbl_rubro_proyecto r
on p.id_transaccion_proyecto=r.id_transaccion_proyecto
where p.id_transaccion_proyecto=@Id_transaccion_Proyecto

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
