CREATE procedure [dbo].[rpt_productos_no_facturados] @Id_empresa int as

Declare @nombre_empresa char(150)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa

select @nombre_empresa as nombre_empresa,
	c.Id_Orden,
	i.id_producto,
	i.descripcion,
	i.cantidad,
	i.id_bodega,
	i.precio,
	i.precio_descuento
	from tbl_orden_servicio c INNER JOIN TBL_ORDEN_SERVICIO_DETALLE_INTEGRACION i
						on c.id_empresa	=i.id_empresa	and
							c.id_orden=i.id_orden
where c.id_Empresa=@id_empresa and c.serie='' and c.tipo='' and c.numero=0
order by i.id_producto





GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
-- =============================
-- SP: rpt_productos_vendidos_por_precio
-- =============================
--set dateformat dmy
--exec rpt_productos_vendidos_por_precio 3,'05/03/2016','05/03/2016'
create procedure [dbo].[rpt_productos_vendidos_por_precio]	@id_empresa int,
													@del		datetime,
													@al			datetime as
set dateformat dmy

		
select 
x.Id_Empresa,
x.nombreemprea ,
x.fecha_factura ,
x.Tipo,
x.Id_Producto ,
x.Descripcion ,
x.Precio_Descuento,
SUM(x.cantidad ) as cantidad
from
(

select	agrupa.id_empresa,
		agrupa.nombreemprea,
		agrupa.fecha_factura,
		agrupa.tipo,
		agrupa.id_producto,
		agrupa.descripcion,
		agrupa.Precio_Descuento,
		SUM(agrupa.cantidad) as cantidad

from (
select	d.id_empresa,
		(select nombre_empresa from empresas where Id_Empresa=@id_empresa ) as nombreemprea,
		c.numero,
		CONVERT(date,c.fecha_factura) as fecha_factura,
		p.Tipo ,
		d.Id_Producto ,
		p.Descripcion ,
		(d.Precio_Descuento- d.Valor_descuento)  as Precio_Descuento  ,
		(d.cantidad) as cantidad
		from tbl_cab_facturacion c inner join Tbl_Det_Facturacion d
					on	c.Id_Empresa =d.Id_Empresa and
						c.Autorizacion =d.Autorizacion and
						c.Id_Tipo=d.Id_Tipo and
						c.Serie=d.Serie and
						c.Numero =d.Numero 
									inner join Tbl_Productos p
					on  d.Id_Empresa=p.Id_Empresa and
						d.Id_Producto =p.Id_Producto 				
where c.Id_Empresa=@id_empresa 		and
		DATEDIFF(day,c.fecha_factura,@al ) between 0 and DATEDIFF(day,@del,@al) 			
union 
select	d.id_empresa,
		(select nombre_empresa from empresas where Id_Empresa=@id_empresa ) as nombreemprea,
		c.numero,
		CONVERT(date,c.fecha_factura) as fecha_factura,
		p.Tipo ,
		d.Id_Producto ,
		p.Descripcion ,
		(d.Precio_Descuento - d.valor_descuento)  as Precio_Descuento ,
		(d.cantidad) as cantidad
		from Tbl_Cab_Notas_Credito  c inner join Tbl_Det_Notas_Credito  d
					on	c.Id_Empresa =d.Id_Empresa and
						c.Autorizacion =d.Autorizacion and
						c.Id_Tipo=d.Id_Tipo and
						c.Serie=d.Serie and
						c.Numero =d.Numero 
									inner join Tbl_Productos p
					on  d.Id_Empresa=p.Id_Empresa and
						d.Id_Producto =p.Id_Producto 				
where c.Id_Empresa=@id_empresa 		and
		DATEDIFF(day,c.fecha_factura,@al ) between 0 and DATEDIFF(day,@del,@al) 				
		
) agrupa		
group by	agrupa .id_empresa,
			agrupa.nombreemprea ,
			convert(date,agrupa.Fecha_Factura) ,
			agrupa.Tipo ,
			agrupa.Id_Producto ,
			agrupa.Descripcion ,
			agrupa.Precio_Descuento 
								
 	) x
 	group by x.Id_Empresa ,x.nombreemprea ,x.fecha_factura ,x.Tipo,x.Id_Producto ,x.Descripcion ,x.Precio_Descuento 
 	order by x.Id_Empresa,x.Fecha_Factura ,x.Id_Producto
 	

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
