CREATE procedure rpt_proveedores @Id_empresa int,@Orden int as

Declare @Nombre_Empresa char(150)

SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa

if @orden=1
	select @nombre_empresa as nombreempresa,
	* from tbl_proveedores p where id_empresa=@Id_empresa and tipo IN ('P','A') order by p.nit
else
	select @nombre_empresa as nombreempresa,
	* from tbl_proveedores where id_empresa=@Id_empresa and tipo IN ('P','A') order by nombre

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
