create procedure rpt_proveedores_ctas @Id_empresa int as

Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa

select @nombre_empresa as nombreempresa,
* from tbl_proveedores_ctas where id_empresa=@Id_empresa


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: rpt_provision_produccion
-- =============================

create procedure rpt_provision_produccion  @id_empresa int,
											@id_orden_produccion int as
		


select 
(select nombre_empresa from empresas where Id_Empresa=@id_empresa ) as nombreempresa,
x.* ,
(select sum(existencia) from Tbl_existencia where Id_Empresa=@id_empresa and Id_Producto=x.id_sproducto) as existencia
from (
select id_empresa,
		id_sproducto,
		descripcion,
		SUM(cantidad_a_producir) as cantidad_por_producir,
		SUM(cantidad_producida) as cantidad_producida,
		sum(cantidad_a_producir-cantidad_producida) as por_producir		

		
		from vw_orden_produccion_materia_prima
where id_empresa=@id_empresa  and id_orden_produccion=@id_orden_produccion 
group by id_empresa,id_sproducto,descripcion 
) x

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
-- =============================
-- SP: rpt_rebaja_cliente
-- =============================
--exec rpt_rebaja_cliente 1,'abo',1
CREATE  PROCEDURE rpt_rebaja_cliente @Id_empresa int,@id_tipo_cobro char(3),@num_docto_cobro int as

select 
(select Nombre_Empresa from empresas where Id_Empresa=@Id_empresa) as nombreempresa,
(select Nombre from Tbl_Proveedores where Id_Empresa=@Id_empresa and Nit=c.nit) as nombreproveedor,
*
from dbo.Tbl_cobros c, dbo.Tbl_det_cobros d
where	c.Id_empresa=d.Id_Empresa and
		c.Id_tipo_cobro=d.Id_tipo_cobro and
		c.Num_docto_cobro =d.Num_docto_cobro and
		c.Id_tipo_cobro =@id_tipo_cobro  AND
		c.Id_empresa=@Id_empresa and
		C.Num_docto_cobro =	@num_docto_cobro
		

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
