-- =============================
-- SP: rpt_recibo_cobro
-- =============================

--exec rpt_recibo_cobro	1,'COB',1
CREATE procedure rpt_recibo_cobro 	@Id_empresa	int,
					@Id_Tipo_cobro	char(3),
					@Num_docto_cobro	int as

declare @nombre_empresa char(150)
SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
SELECT 	ltrim(rtrim(cast(C.iD_EMPRESA as char)))+'-'+@nombre_empresa as nombre_empresa,
	C.ID_TIPO_COBRO,
	C.NUM_DOCTO_COBRO,
	ltrim(rtrim(C.NIT))+' '+p.facturar_a as facturar_A,
	C.FECHA_DOCTO,
	C.EFECTIVO,
	C.ID_BANCO,
	C.VALOR_CHEQUE,
	C.ID_CASA,
	C.VALOR_TARJETA,
	C.DESCRIPCION,
	D.ID_TIPO,
	D.NUMERO,
	D.VALOR_APLICADO FROM TBL_COBROS C	INNER JOIN TBL_DET_COBROS D
					ON	C.ID_EMPRESA		=D.ID_EMPRESA		AND
						C.ID_TIPO_COBRO		=D.ID_TIPO_COBRO	AND
						C.NUM_DOCTO_COBRO	=D.NUM_DOCTO_COBRO
						inner join tbl_proveedores p
					on	c.id_Empresa	=p.id_empresa	and
						c.nit		=p.nit
WHERE 	c.id_empresa		=@Id_empresa	and 
	c.id_tipo_cobro		=@id_tipo_cobro	and
	c.num_docto_cobro	=@num_docto_cobro


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: rpt_reporte_comisiones_mecanicos
-- =============================




--exec sp_help tbl_vendedores
--SET DATEFORMAT DMY
--select *from tbl_vendedores
--select *from tbl_productos

--exec rpt_reporte_comisiones_mecanicos 1,'TOD','29/01/2007','29/01/2007'
CREATE procedure rpt_reporte_comisiones_mecanicos  	@Id_empresa	int,
							@Id_Empleado	char(10),
							@Fecha_inicial	datetime,
							@Fecha_final	datetime as


select *,
(SELECT NOMBRE_EMPRESA FROM EMPRESAS WHERE ID_EMPRESA=@ID_EMPRESA) AS NOMBREEMPRESA,
p.descripcion as descripcionservicio
from tbl_orden_servicio o,tbl_orden_servicio_detalle d,tbl_vendedores v,tbl_productos p
where 	o.id_empresa	=d.id_empresa	and
	o.id_orden	=d.id_orden	and
	d.id_empresa	=v.id_empresa	and
	d.id_empleado	=v.id_empleado	and
	d.id_empresa	=p.id_empresa	and
	d.id_servicio	=p.id_producto  and
	datediff(day,o.fecha_facturacion,@Fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) and
	d.id_empleado	=(case when @Id_Empleado='TOD' Then d.id_empleado
							Else @Id_empleado end) and numero<>0
ORDER BY O.ID_EMPRESA,O.fecha_facturacion






GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: rpt_resumen_entradas_salids_inventario
-- =============================
--SET DATEFORMAT DMY
--EXEC rpt_resumen_entradas_salids_inventario 99,'01/05/2019','31/05/2019',1,'MATERIA P.',2
CREATE  procedure [dbo].[rpt_resumen_entradas_salids_inventario]	@Id_Empresa	int,
													@Fecha_Ini datetime,
													@Fecha_Fin datetime,
													@AGRUPADO INT,
													@tipo char(10),
													@muestra_decimales int  as

Declare @Nombre_Empresa						char(150),
		@Fecha_ultimo_dia_mes_anterior				datetime,		
		@Fecha_periodo_anterior				datetime,
		@Periodo_anterior					char(7),
		@Saldo_inicial_ala_fecha			datetime,
		@primer_dia_mes						datetime
		
set @Saldo_inicial_ala_fecha=dateadd(day,-1,@Fecha_Ini)
PRINT @Saldo_inicial_ala_fecha


print @Saldo_inicial_ala_Fecha

set dateformat dmy

set @Fecha_ultimo_dia_mes_anterior =cast( '01'+'/'+cast(month(@Fecha_Fin)as char(2))+'/'+cast(year(@Fecha_Fin) as char(4)) as datetime)

set @primer_dia_mes  =cast( '01'+'/'+cast(month(@Fecha_Fin)as char(2))+'/'+cast(year(@Fecha_Fin) as char(4)) as datetime)


--al quitarle un dia a fecha ini fecha perioro anterior tiene el ultimo dia del mes anterior

set @Fecha_ultimo_dia_mes_anterior =dateadd(day,-1,@Fecha_ultimo_dia_mes_anterior )

set @Periodo_anterior= replicate('0',2-len( ltrim(rtrim(cast(month(@fecha_ULTIMO_DIA_MES_anterior) as char)))))+ltrim(rtrim(str(month(@Fecha_ultimo_dia_mes_anterior ))))+'/'+cast( year(@Fecha_ultimo_dia_mes_anterior ) as char)


SELECT  @Nombre_Empresa = Nombre_empresa FROM EMPRESAS where Id_Empresa = @Id_Empresa

set dateformat dmy

--- este query inserta a la tabla #temporal el saldo de movimienots(cantidades) del 1 del mes hasta un dia antes de fecha ini
create table #temporal (id_producto char(15),
						cantidad	numeric(12,4))
						
						
if  year(@Saldo_inicial_ala_fecha )= YEAR(@Fecha_Fin) and
    MONTH(@Saldo_inicial_ala_fecha)= MONTH(@Fecha_Fin)
    begin
						
	insert #temporal 		
	select *from
	(
	select d.id_producto,SUM(case when t.Efecto_Inv =1
							then d.Cantidad
							else d.Cantidad *-1 end) as cantidad from Tbl_cabecera_movimientos c inner join Tbl_Detalle_movimientos d on
							c.id_empresa=d.id_empresa and
							c.periodo=d.periodo			and
							c.id_bodega	=d.id_bodega	and
							c.id_tipo=d.id_tipo			and
							c.numero	=d.numero		and
							c.Nit		=d.Nit 
										inner join Tbl_Tipos_Inv t on
							c.Id_Empresa=t.Id_Empresa and
							c.Id_Tipo	=t.Id_Tipo 							
	where	c.Id_Empresa=@Id_Empresa 	and
			DATEDIFF(day,c.fecha,@Saldo_inicial_ala_fecha )	between
			0	and DATEDIFF(day,@primer_dia_mes  ,@Saldo_inicial_ala_fecha )			
	group by d.Id_Producto 		
	union all
	select	d.id_producto,
			sum(d.cantidad*-1) as cantidad from Tbl_Cab_Facturacion c inner join Tbl_Det_Facturacion d
							on	c.Id_Empresa=d.Id_Empresa and
								c.Id_Caja	=d.Id_Caja		and
								c.Autorizacion =d.Autorizacion and
								c.Serie=d.Serie and
								c.numero=d.Numero 	
	where	c.Id_Empresa=@Id_Empresa 	and
			DATEDIFF(day,c.Fecha_Factura ,@Saldo_inicial_ala_fecha )	between
			0	and DATEDIFF(day,@primer_dia_mes  ,@Saldo_inicial_ala_fecha ) 
	group by d.Id_Producto 							
	union all

	select	d.id_producto,
		sum(d.cantidad*-1) as cantidad from Tbl_Cab_Notas_Credito c inner join Tbl_Det_Notas_Credito  d
						on	c.Id_Empresa=d.Id_Empresa and
							c.Id_Caja	=d.Id_Caja		and
							c.Autorizacion =d.Autorizacion and
							c.Serie=d.Serie and
							c.numero=d.Numero 	
	where	c.Id_Empresa=@Id_Empresa 	and
			DATEDIFF(day,c.Fecha_Factura ,@Saldo_inicial_ala_fecha )	between
			0	and DATEDIFF(day, @primer_dia_mes  ,@Saldo_inicial_ala_fecha )							
	group by d.Id_Producto ) x
	end

select	nombre_empresa,
		ID_BODEGA,
		ARTICULO,
		DEPTO,
		LINEA,
		ID_PRODUCTO,
		medida,
		DESCRIPCION,
		SUM(INICIAL) AS INICIAL,
		SUM(ENTRADAS) AS ENTRADAS,
		SUM(SALIDA
-- =============================
-- SP: rpt_resumen_servicios_facturados
-- =============================









--set dateformat dmy
--SELECT *FROM TBL_ORDEN_SERVICIO
--select *from tbl_cab_facturacion
--SELECT *from tbl_orden_servicio_detalle where id_servicio='S1'
--exec rpt_ordenes_trabajadas 1,'TODO','01/01/2000','31/12/2006'

--EXEC rpt_resumen_servicios_facturados 1,'TODOS','01/02/2006','28/02/2006'

CREATE procedure rpt_resumen_servicios_facturados  	@Id_Empresa	int,
							@Id_Empleado	char(4),
							@Fecha_Inicial 	datetime,
							@Fecha_Final	datetime as
--select *from tbl_cab_facturacion
--select *from tbl_orden_servicio
--select *from tbl_orden_servicio_Detalle
Declare  @Nombre_Empresa char(150)
SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
SELECT @Nombre_empresa as nombre_empresa,
	d.Id_servicio,
	d.descripcion,
	SUM(D.CANTIDAD)  AS CANTIDAD,
	Sum(D.cantidad*d.Precio)   AS precio,
	Sum(D.CANTIDAD* d.Precio_descuento) As Precio_Descuento
	 from tbl_cab_facturacion	f	inner join 	tbl_orden_servicio o	
					on	f.Id_Empresa	=o.Id_Empresa	and
						f.Autorizacion	=o.Autorizacion	and
						f.serie		=o.Serie	and
						f.id_tipo	=o.tipo		and
						f.numero	=o.numero
						inner join tbl_orden_servicio_detalle	d
					on 	o.Id_Empresa	=d.Id_empresa	and
						o.Id_Orden	=d.Id_orden
						inner join tbl_vendedores	v
					on	d.Id_empresa	=v.Id_empresa	and
						d.Id_empleado	=v.Id_empleado


						
	where 	f.Id_Empresa=@Id_Empresa	and
		Datediff(day,f.Fecha_factura,@Fecha_Final)	between 0	and datediff(day,@fecha_inicial,@fecha_final)	
AND

	d.Id_Empleado	=(case when @Id_Empleado='TODO'
						THEN d.Id_Empleado
						Else @Id_Empleado end)
Group by d.Id_Servicio,d.descripcion



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: rpt_resumen_ventas_integracion_gasolina
-- =============================
CREATE  procedure [dbo].[rpt_resumen_ventas_integracion_gasolina]  @Id_empresa int,@Fechainicial datetime,@Fechafinal   datetime as
		set dateformat dmy
/*set @Id_empresa =1
set @Fechainicial ='01/05/2013'
set @Fechafinal ='08/08/2013'*/
select	det.ID_EMPRESA,
		empre.Nombre_Empresa ,
		det.ID_CLIENTE_VALE_DETALLE ,
		det.ID_PRODUCTO , 
		p.Descripcion ,
		v.Nombre ,
		SUM(det.CANTIDAD_VALE ) as cantidad,
		SUM(det.valor_vale) as valor ,
		COUNT(*) AS NUMEROVALES from dbo.TBL_DETALLE_VALES_POR_APLICAR det inner join Tbl_Productos p
			on  det.ID_EMPRESA =p.Id_Empresa and
				det.ID_PRODUCTO =p.Id_Producto 
													inner join Tbl_Proveedores v
			on det.ID_EMPRESA=v.Id_Empresa and
				det.ID_CLIENTE_VALE_DETALLE =v.Nit 
													inner join empresas empre
			on det.ID_EMPRESA=empre.Id_Empresa 										
where det.ID_EMPRESA =@Id_empresa and
datediff(day,det.FECHA_VALE ,@Fechafinal ) between 0 and DATEDIFF(day,@fechainicial,@fechafinal)				
group by
det.ID_EMPRESA,
empre.Nombre_Empresa ,
		det.ID_CLIENTE_VALE_DETALLE ,
		det.ID_PRODUCTO , 
		p.Descripcion ,
		v.Nombre 
		

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
-- =============================
-- SP: rpt_saldo_cliente_gasolina
-- =============================

--exec rpt_saldo_cliente_gasolina 1
CREATE procedure [dbo].[rpt_saldo_cliente_gasolina] @id_empresa int as

select *from
(select
e.Nombre_empresa ,
 p.Nombre ,
c.* from tbl_cliente_gasolina c inner join Tbl_Proveedores p on c.id_empresa=p.Id_Empresa and
																	c.id_cliente_vale =p.Nit 
								inner join empresas e		on c.id_empresa=e.Id_Empresa 
where c.id_empresa=@id_empresa ) x where x.Saldo<>0


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
-- =============================
-- SP: rpt_series
-- =============================

CREATE procedure rpt_series @Id_empresa int as
select s.*,
ltrim(rtrim(e.nit))+' '+ltrim(rtrim(e.nombre_empresa)) as nombreempresa from tbl_series s, empresas e
where	s.id_empresa=e.id_empresa and
		s.id_empresa=@Id_Empresa
order by fecha_ingreso
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: rpt_solicitud_envio
-- =============================
--set dateformat dmy
--exec rpt_solicitud_envio 3,'16/04/2010','16/04/2010',''
CREATE  procedure [dbo].[rpt_solicitud_envio] @Id_empresa int,@inicia datetime,@termina datetime,@status_solicitud char(10),@Id_solicitud_despacho int as

select *from dbo.vw_solicitud_envio 
where Id_empresa=@Id_empresa and 
DATEDIFF (day,fecha_solicitud,@termina) between 0 and
DATEDIFF(day,@inicia,@termina) and
Status_solicitud = case when @status_solicitud=''
								then Status_solicitud 
								else @status_solicitud 
								end					and
Id_solicitud_despacho=case when @Id_solicitud_despacho=0
									then Id_solicitud_despacho 
									else @Id_solicitud_despacho end 								

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
-- =============================
-- SP: rpt_solicitud_envio_detalle_recepcion
-- =============================
CREATE procedure [dbo].[rpt_solicitud_envio_detalle_recepcion] @Id_empresa int,@Id_solicitud_despacho int  as


select	c.fecha,
		c.numero,
		d.Id_bodega_movimiento ,
		ltrim(rtrim(d.Id_producto))+' '+	(select descripcion from Tbl_Productos p where p.Id_Empresa=d.id_empresa and p.Id_Producto = d.id_producto) as producto,
		
		d.Cantidad,
		d.Precio,
		d.total,
		
		(select j.despacho_desde  from tbl_solicitud_despacho_cliente l,tbl_solicitud_Despacho_cliente_detalle j
		where	j.id_empresa			=l.id_empresa				and
				j.Id_solicitud_despacho =l.Id_solicitud_despacho	and 
				l.Id_solicitud_despacho =@Id_solicitud_despacho     and
				j.Linea					=d.linea_solicitud  ) as origen
		
		 from tbl_cab_entrega_despacho c, tbl_det_entrega_despacho d
where	c.Id_empresa			=d.Id_empresa	and
		c.Numero				 =d.Numero      and 
		c.Id_empresa=@Id_empresa and
		c.Id_solicitud_despacho =@Id_solicitud_despacho  
		
		
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
