CREATE procedure [dbo].[rpt_solicitud_envio_orden_compras] @Id_empresa int,@id_solicitud_despacho int as

select	p.id_pedido,
		p.nit as nitproveedor,
		p.fecha_pedido,
		d.id_sproducto,
		d.cantidad,
		d.total_pedido from Tbl_pedidos p, Tbl_detalle_pedidos d
where p.Id_Empresa=d.Id_Empresa and
p.Id_Pedido =d.Id_Pedido and
p.Id_Pedido in 

(select distinct id_pedido from  tbl_solicitud_Despacho_cliente c, tbl_solicitud_Despacho_cliente_Detalle d
where c.Id_empresa=d.Id_empresa and c.Id_solicitud_despacho =d.Id_solicitud_despacho and
 d.Id_empresa=@Id_empresa  and c.Id_solicitud_despacho =@id_solicitud_despacho  and Id_pedido is not null) 
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: rpt_test_zona_calida
-- =============================
--SELECT *FROM  [db_inventario_pfp].[dbo].[TBL_ZONA_CALIDA]
--select *from tbl_zona_calida
--SELECT *FROM #ventas_zona_calida
--drop table #ventas_zona_calida
--exec rpt_test_zona_calida
CREATE procedure [dbo].[rpt_test_zona_calida] as

create table #ventas_zona_calida (fecha varchar(20),
									hora   varchar(3),
									valor     numeric(12,2))


/****** Script for SelectTopNRows command from SSMS  ******/
insert #ventas_zona_calida
SELECT 
		convert(varchar,fecha,103) as fecha,
		'H'+CAST(datepart(hour,fecha) AS CHAR) as hora,
      sum(valor) as valor
  FROM [db_inventario_pfp].[dbo].[TBL_ZONA_CALIDA]
  group by convert(varchar,fecha,103) ,datepart(hour,fecha) 

 
 

  SELECT	fecha,
			isnull([H8],0) as hora8,
			isnull([H9],0) as hora9,
			isnull([H10],0) as hora10,
			isnull([H11],0) as hora11,
			isnull([H12],0) as hora12,
			isnull([H13],0) as hora13,
			isnull([H14],0) as hora14,
			isnull([H15],0) as hora15,
			isnull([H16],0) as hora16,
			isnull([H17],0) as hora17,
			isnull([H18],0) as hora18,
			isnull([H19],0) as hora19,
			isnull([H20],0) as hora20,
			isnull([H21],0) as hora21,
			isnull([H22],0) as hora22,
			isnull([H23],0) as hora23,
			isnull([H24],0) as hora24
 
from 
   (
  SELECt 
   fecha as fecha,
    hora,
   
    valor
     from #ventas_zona_calida
   ) SOURCETABLE
PIVOT
   (SUM (valor)
    FOR Hora in ([H8],[H9],[H10],[H11],[H12],[H13],[H14],[H15],[H16],[H17],[H18],[H19],[H20],[H21],[H22],[H23],[H24]) 
   ) as pivotable
   ORDER BY PIVOTABLE.FECHA
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
