-- =============================
-- SP: rpt_Ultimo_movimiento
-- =============================





--set dateformat dmy
--select *from tbl_Orden_servicio_detalle
--select *from tbl_proveedores
--exec rpt_ltimo_movimiento 1,'02/01/2006','08/05/2006'
CREATE procedure rpt_Ultimo_movimiento	@id_empresa	int,
					@fecha 		datetime,
					@fecha_Movimiento datetime  as 
--procedimiento para genera registros de ultimo movimiento del cliente

select 	@fecha_Movimiento as fecha_Movimiento,
	p.nit,
	p.NOMBRE,
	p.DIRECCION,
	p.num_casa,
	p.COLONIA,
	p.APTO,
	p.ZONA,
	p.CIUDAD,
	p.MUNICIPIO,
	'MARCA  '+UPPER(ltrim(rtrim(v.marca)))+' MODELO  '+ltrim(rtrim(v.modelo))+' PLACA  '+ltrim(rtrim(v.num_placa)) as vehiculo
	 From tbl_proveedores p	right join tbl_vehiculos	v
					on 	p.id_empresa	=v.id_empresa	and
						p.nit		=v.nit
where 	p.id_empresa=@id_Empresa	and	
	datediff(day,p.fecha_ult_mov,@fecha)	=0 	and 
	p.tipo		='C'






GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
