-- =============================
-- SP: rpt_vale
-- =============================
--EXEC rpt_vale 1,'A',99,1,5
CREATE procedure [dbo].[rpt_vale]	@id_empresa int,
							@serie varchar(20),
							@numero_factura int,
							@del int,
							@al int as
		
declare @contador int		

create table #temporal( Id_Cliente_vale			varchar(20),
						Nombrecliente			varchar(100),
						Id_empresa				int,
						Id_transaccion_factura	int,
						Serie					varchar(15),
						Numero_factura			numeric(10),
						Cantidad_vales			int,
						valor_vales				numeric(12,2),
						total					numeric(12,2),
						Impreso					int,
						fecha_ingreso			datetime,
						del						int,
						al						int,
						Numero_vale				int,
						cantidad_letras			varchar(250),
						nombre_mes				varchar(50)
						)
						
						
/*set @id_empresa =1
set @serie='A'
SET @numero_factura =1
set @del=1
set @al=10*/
set @contador=@del
while @contador <=@al
begin
    insert  #temporal 
	select c.ID_CLIENTE_VALE ,
	(select nombre from Tbl_Proveedores p where p.Id_Empresa=c.ID_EMPRESA  and p.Nit=c.ID_CLIENTE_VALE ) as nombrecliente,
	d.*, @CONTADOR AS NUMEROVALE ,
	upper(dbo.sp_numero_a_letras2(valor_vales))  as cantidad_letras,
	DATENAME(MONTH,	FECHA_INGRESO) AS NOMBREMES

	from db_inventario_pfp .dbo.TBL_CABECERA_VENTAS_VALE c inner join 	TBL_DETALLE_CANTIDAD_VALES_VENDIDOS D 
														on c.ID_EMPRESA=d.ID_EMPRESA and
																c.SERIE=d.SERIE and
																c.NUMERO =d.NUMERO_FACTURA 
	where	 d.ID_EMPRESA=@id_empresa  and
			d.SERIE=@serie			and
			d.NUMERO_FACTURA  =@numero_factura and
			 d.Del=@del  and Al=@al
	
set @contador =@contador +1
end
		
		select *from #temporal
		
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
-- =============================
-- SP: rpt_vales_ventas_por_dia
-- =============================
create procedure rpt_vales_ventas_por_dia        @id_empresa int,
                                        @fecha_del datetime,
                                        @fecha_al  datetime as
                                       
select
(select nombre_empresa from dbo.empresas where Id_Empresa=@id_empresa) as nombreempresa,
*,
(select descripcion from Tbl_Productos p where p.Id_Empresa=@id_empresa and
p.Id_Producto=d.id_producto) as nombreproducto

from dbo.TBL_CABECERA_VENTA_POR_DIA c, dbo.TBL_DETALLE_VENTA_POR_DIA d
where c.id_empresa=d.id_empresa and
c.id_transaccion_venta=d.id_transaccion_venta and
c.id_empresa=@id_empresa and
DATEDIFF(day, c.fecha_Venta,@fecha_al) between 0 and
DATEDIFF(day,@fecha_del,@fecha_al)
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
-- =============================
-- SP: rpt_validacion_anticipo_proveedores
-- =============================

---set dateformat dmy
--exec rpt_validacion_anticipo_proveedores 1,'01/01/2000','30/12/2026'
CREATE procedure [dbo].[rpt_validacion_anticipo_proveedores] 	@Id_empresa	int,
							@Fecha_inicial	datetime,
							@Fecha_final	datetime as
select 

a.*,
e.Nombre_Empresa as nombre_empresa,
	p.nombre from tbl_abonos a ,tbl_proveedores p, empresas e
where 	a.id_Empresa	=p.id_empresa	and
	a.nit		=p.nit		and
	a.id_empresa=@Id_empresa	and
	a.id_tipo_pago='ANT'		and
	datediff(day,a.fecha_docto,@fecha_final)	between 0 and datediff(day,@fecha_inicial,@fecha_final)
order by a.fecha_docto




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
-- =============================
-- SP: rpt_validacion_anticipos
-- =============================

Create procedure rpt_validacion_anticipos @Id_empresa int,@fecha_inicial datetime,@fecha_final datetime as

select *from tbl_abonos A,TBL_PROVEEDORES P
where 	A.ID_EMPRESA=P.ID_eMPRESA AND
	A.NIT	=P.NIT 		AND
	A.Id_Empresa=1		and
	A.id_tipo_pago='ANT' 	and
	datediff(day,a.fecha_docto,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final)


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_validacion_facturas_pcobrar
-- =============================
--set dateformat dmy
--drop procedure rpt_validacion_facturas_pcobrar 
--exec [dbo].[rpt_validacion_facturas_pcobrar] 1,'01/01/2020','25/06/2020'
create procedure [dbo].[rpt_validacion_facturas_pcobrar]  	@Id_Empresa	int,
							@Fecha_inicial	datetime,
							@Fecha_final	datetime as


declare	@Nombre_Empresa	char(80)



set dateformat dmy
select @Nombre_Empresa=Nombre_Empresa from empresas where id_Empresa=@Id_empresa
select c.Id_empresa,
	@Nombre_empresa	as nombre_empresa,
	c.Nit,
	p.facturar_a,
	c.serie,
	c.Tipo_docto,
	c.Numero_docto,
	c.descripcion,
	c.fecha_docto,
	c.valor_docto,
	c.Saldo_docto,
	c.iva,
	c.Status ,
	c.Retencion_iva  from tbl_cuentas_por_cobrar c	inner join tbl_proveedores p
					on 	c.id_empresa	=p.id_empresa	and
						c.nit		=p.nit
where 	c.Id_empresa=@Id_Empresa		and
	datediff(day,fecha_docto,@fecha_final) between 0	and datediff(day,@fecha_inicial,@fecha_final)
ORDER by c.fecha_docto,numero_docto




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
-- =============================
-- SP: rpt_Validacion_Movimientos_inv
-- =============================



--DROP PROCEDURE [dbo].[rpt_Validacion_Movimientos_inv]

/*
SET DATEFORMAT DMY
exec rpt_validacion_movimientos_inv 99,'COM','01/07/2019','30/07/2019','DETALLADO',0
SELECT *FROM TBL_CABECERA_MOVIMIENTOS
*/
CREATE    procedure [dbo].[rpt_Validacion_Movimientos_inv]	@Id_Empresa	int,
						@Id_Tipo 	char(3),
						@fecha_inicial 	datetime,
						@fecha_final 	datetime,
						@Tipo_reporte	char(10),
						@Numero			numeric(10) as
--si tipo_reporte='SUMARIO',DETALLADO
set dateformat dmy



Declare @Coef_anterior	numeric(12,2),
		@Coef_actual	numeric(12,2),
		@apartir		datetime
set dateformat dmy
select	@coef_actual	=Porcentaje_iva,
		@coef_anterior	=Porcentaje_iva_anterior,
		@apartir		=apartirde
from empresas where id_empresa=1
set @coef_actual	=1+round(@coef_actual/100,2)
set @coef_anterior	=1+round(@coef_anterior/100,2)



select 	c.Id_Empresa,
	(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombre_empresa,
	(select Descripción from Tbl_Tipos_Inv where id_empresa=@Id_empresa and id_tipo=@id_tipo) as nombre_titulo,
	c.Id_Tipo,
	(SELECT EFECTO_INV FROM TBL_TIPOS_INV WHERE ID_EMPRESA=C.Id_empresa and id_tipo=C.Id_tipo) AS EFECTO_INVENTARIO,
	case when c.credito_o_contado=1
		then 'CREDITO'
		else 'CONTADO' END AS CREDITOCONTADO,
	c.Numero,
	c.fecha,
	c.Nit,
	p.nombre,
	c.Concepto,
	c.impreso,
	(select SUM(e.TOTAL) from  tbl_detalle_MOVIMIENTOS e
	where e.Id_Empresa	=c.Id_Empresa and e.nit=c.nit and e.id_tipo=c.Id_Tipo	and	e.numero=c.numero) as total,
	d.id_producto,
	(select descripcion from tbl_productos where id_empresa=D.ID_EMPRESA and id_producto=D.Id_Producto) as nombreproducto,
	d.cantidad,
	d.precio,
	d.costo,
	d.total as totallinea ,
	0 AS Orden_compra
	from tbl_cabecera_movimientos	c 	inner join tbl_proveedores	p	on
							c.Id_Empresa		=p.Id_Empresa	and
							c.nit			=p.nit
						inner join tbl_detalle_movimientos d	on
								c.id_empresa	=d.id_empresa	and
								c.periodo	=d.periodo	and
								c.id_bodega	=d.id_bodega	and
								c.id_tipo	=d.id_tipo	and
								c.numero	=d.numero	and
								c.nit		=d.nit
where 	c.Id_Empresa		=@ID_EMPRESA				And
	c.Id_Tipo		=@ID_TIPO							And
	DATEDIFF(DAY,c.fecha,@Fecha_Final)   between 
	0 						and
	datediff(day,@Fecha_Inicial,@Fecha_Final)	And
	c.numero		=case when @Numero=0 then c.numero else @Numero end
union all

select 	C.Id_Empresa,
	(select nombre_empresa from empresas where id_empresa=1) as nombre_empresa,
	(select Descripción from Tbl_Tipos_Inv where id_empresa=@Id_empresa and id_tipo=@id_tipo) as nombre_titulo,
	C.ID_TIPO AS Id_tipo,
	(SELECT EFECTO_INV FROM TBL_TIPOS_INV WHERE ID_EMPRESA=C.Id_empresa and id_tipo=C.Id_tipo) AS EFECTO_INVENTARIO,
	case when c.credito_o_contado=1
		then 'CREDITO'
		else 'CONTADO' END AS CREDITOCONTADO,
	c.Numero,
	C.Fecha,
	C.NIT,
	P.Nombre,
	C.Concepto,
	C.IMPRESO,	
	(select sum(cantidad_por_recibir*precio_compra) from tbl_recepcion_pedidos_detalle s where s.id_empresa=r.id_empresa and s.id_recepcion=r.id_recepcion and s.id_pedido=r.id_pedido) AS TOTAL,
	(select id_producto from tbl_prod_proveedores
	where id_empresa=@Id_empresa and id_alterno=w.Id_sproducto ) as id_producto,

	(select p.descripcion from tbl_prod_proveedores a, tbl_productos p
	where a.id_empresa=p.id_empresa and
	a.id_producto=p.id_producto and
	a.id_alterno=w.Id_sproducto) as nombreproducto,
	W.CANTIDAD_POR_RECIBIR as cantidad,
	W.PRECIO_COMPRA as precio,
	ROUND(W.PRECIO_COMPRA/ (case when @apartir<=c.fecha then @coef_actual else @coef_anterior end  )      ,4) as costo,
	(W.CANTIDAD_POR_RECIBIR*W.PRECIO_COMPRA) AS totallinea,
	R.ID_PEDIDO AS orden_compra
	from tbl_cabecera_movimientos c, tbl_detalle_generacion_compra d, TBL_PROVEEDORES P, TBL_RECEPCION_PEDIDOS R, TBL_RECEPCION_PEDIDOS_DETALLE W
where	c.Id_Empresa	=d.Id_empresa		and
		c.
-- =============================
-- SP: rpt_vehiculos
-- =============================

CREATE procedure rpt_vehiculos @Id_Empresa int as

Declare @Nombre_Empresa char(150)
SELECT 	@Nombre_Empresa=Nombre_empresa  FROM EMPRESAS where Id_Empresa=@Id_Empresa

select @nombre_empresa as nombreempresa,
 *from tbl_vehiculos where Id_Empresa=@Id_Empresa and marca = 'honda' and color = 'azul'

