-- =============================
-- SP: rpt_venta_vale
-- =============================
--exec rpt_venta_vale 1,'A',1

CREATE procedure rpt_venta_vale @id_empresa int,@serie varchar(15),@numero_factura numeric(10) as
--declare @id_Empresa int

select 
(select Nombre_empresa from empresas where Id_Empresa=@id_empresa ) as nombreempresa,
(SELECT NOMBRE FROM Tbl_Proveedores WHERE A.ID_EMPRESA=@ID_EMPRESA AND Nit=A.ID_CLIENTE_VALE ) AS NOMBREPROVEEDOR,
A.ID_CLIENTE_VALE  AS CODIGOCLIENTE,
d.* from dbo.TBL_CABECERA_VENTAS_VALE a,dbo.TBL_DETALLE_CANTIDAD_VALES_VENDIDOS  d
where a.SERIE  =d.SERIE  and
a.NUMERO= d.NUMERO_FACTURA and
a.ID_EMPRESA =1 AND
A.SERIE=@serie AND
A.NUMERO =@numero_factura 



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
-- =============================
-- SP: rpt_ventas_al_credito
-- =============================

--select *	FROM TBL_CAB_FACTURACION	where contado_o_credito=2
--exec rpt_ventas_al_credito 1,'01/03/2006','31/03/2006'

CREATE procedure rpt_ventas_al_credito @ID_EMPRESA INT,	@FECHA_INICIAL	DATETIME,@FECHA_FINAL	DATETIME as


SELECT ID_EMPRESA,
	ID_CAJA,
	AUTORIZACION,
	SERIE,
	ID_TIPO,
	NUMERO,
	NIT,
	FACTURAR_A,
	FECHA_FACTURA,
	TCREDITO,
	total
	FROM TBL_CAB_FACTURACION
WHERE ID_EMPRESA=@ID_EMPRESA	AND
	DATEDIFF(DAY,FECHA_FACTURA,@FECHA_FINAL) BETWEEN 0 AND DATEDIFF(DAY,@FECHA_INICIAL,@FECHA_FINAL) AND
	CONTADO_O_CREDITO=2
ORDER BY ID_CAJA,NUMERO



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
