-- =============================
-- SP: rpt_ventas_gasolina
-- =============================
--SELECT *FROM TBL_CABECERA_VENTAS_VALE 

--exec rpt_ventas_gasolina 1,'01/01/2013','31/12/2013'
CREATE procedure [dbo].[rpt_ventas_gasolina] @id_empresa int,@De_Fecha_corte datetime,@A_fecha_corte datetime as

select e.nombre_empresa,
c.id_cliente_vale,
c.TIPO_VALE ,
p.nombre,

sum(c.vales_total) as total from tbl_cabecera_ventas_vale c 
inner join dbo.empresas e
		on c.ID_EMPRESA=e.Id_Empresa 
inner join dbo.Tbl_Proveedores p
		on c.ID_EMPRESA=p.Id_Empresa and
			c.ID_CLIENTE_VALE =p.Nit 	
where c.ID_EMPRESA =@id_empresa and
DATEDIFF(day,c.fecha_corte,@a_fecha_corte) between 0 and DATEDIFF (day,@de_fecha_corte,@A_fecha_corte)
group by e.nombre_empresa,c.TIPO_VALE , c.ID_CLIENTE_VALE ,p.Nombre

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: rpt_ventas_modulo_pcobrar
-- =============================

--SET DATEFORMAT DMY
--EXEC RPT_VENTAS_MODULO_PCOBRAR 1,'01/01/2000','30/12/2006'


CREATE procedure rpt_ventas_modulo_pcobrar @Id_Empresa INT, @Fecha_inicial datetime,@Fecha_final datetime as

select 'A' AS TIPO,
	C.ID_EMPRESA,
	(select nombre_empresa from empresas where id_empresa=@Id_Empresa) as nombre_empresa,
	C.NIT,
	(SELECT FACTURAR_A FROM TBL_PROVEEDORES WHERE ID_EMPRESA=@ID_EMPRESA AND NIT=C.NIT) AS FACTURAR_A,
	C.SERIE,
	C.TIPO_DOCTO,
	C.NUMERO_DOCTO,
	C.DESCRIPCION,
	C.FECHA_DOCTO,
	C.VALOR_DOCTO,
	(select sum(d.valor_aplicado) from tbl_cobros cob,tbl_det_cobros d 
	where 		cob.id_empresa		=d.id_empresa		and
			cob.id_tipo_cobro		=d.id_tipo_cobro	and
			cob.num_docto_cobro	=d.num_docto_cobro 		and
	datediff(day,cob.fecha_docto,@fecha_final) between 	0	and datediff(day,@fecha_inicial,@fecha_final)	and
	cob.Id_Tipo_cobro='ABO') AS Total_rebajas_dev

 from tbl_cuentas_por_cobrar C
where id_empresa=@Id_Empresa	and 
	datediff(day,fecha_docto,@fecha_final)	between 0	and datediff(day,@fecha_inicial,@fecha_final)



GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
-- =============================
-- SP: rpt_ventas_por_centro_costo
-- =============================
create procedure rpt_ventas_por_centro_costo @id_empresa int,@fecha_inicial datetime as
select * from dbo.vw_ventas_por_centro_costo
where id_empresa=@id_empresa and
month(fecha_Factura)=month(@fecha_inicial) and day(fecha_factura)=day(@fecha_inicial)
 and year(fecha_factura)=year(@fecha_inicial)
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: rpt_ventas_por_departamento
-- =============================



/*select *from tbl_det_facturacion where numero=5002
set dateformat dmy
exec rpt_ventas_por_departamento 3,'01/11/2009','30/11/2009',1
*/
CREATE procedure [dbo].[rpt_ventas_por_departamento]   	@Id_empresa	int,
						@Fecha_inicial	datetime,
						@Fecha_final	datetime,
						@Tipo_reporte int as

--@tipo_reporte=1 =Detallado;2=Resumen

Declare @coeficiente			numeric(12,2),
	@coeficiente1				numeric(12,2),	
	@Porcentaje_iva_anterior 	numeric(12,2),
	@Porcentaje_iva				numeric(12,2),
	@apartirde					datetime
SELECT 		@Porcentaje_iva_anterior		=Porcentaje_iva_anterior,
			@Porcentaje_iva					=Porcentaje_iva,
			@apartirde						=apartirde
FROM EMPRESAS where id_empresa=@Id_empresa

set @Coeficiente1		=1+round(@Porcentaje_iva_anterior/100,2)
set @Coeficiente		=1+Round(@Porcentaje_iva/100,2)

SELECT	Z.Id_Empresa,
		Z.Nombre_Empresa,
		Z.Id_Depto,
		Z.Nombre,
		Z.Id_Producto,
		Z.Descripcion,
		SUM(Sub_total) as Sub_total,
		SUM(Descuento) as descuento,
		SUM(Total)     as total,
		SUM(totalneto) as totalneto FROM 

(select  v.Id_empresa,
	Nombre_empresa ,
	v.id_depto,
	v.nombre,
	v.id_producto,
	v.descripcion,
	Sum((v.Cantidad*v.Precio)) 	as Sub_total,
	Sum((v.Cantidad*v.Precio)-(v.Cantidad*v.Precio_Descuento))	as Descuento,
	Sum((v.Cantidad*v.Precio)-((v.Cantidad*v.Precio)-(v.Cantidad*v.Precio_Descuento))) as total,
	sum(((v.Cantidad*v.Precio)-((v.Cantidad*v.Precio)-(v.Cantidad*v.Precio_Descuento)))/  (case when v.apartirde<= v.fecha_factura  then @coeficiente else @coeficiente1 end)     ) as totalneto

from vw_ventas_por_departamento_detallado v
where	v.id_empresa=@Id_Empresa				and
		datediff(day,Fecha_factura,@Fecha_final)	between
		0 				and datediff(day,@Fecha_inicial,@Fecha_final)    and
		v.id_producto<>'GAS' 
	Group by v.Id_empresa,
	v.Nombre_empresa ,
	v.id_depto,
	v.nombre,
	v.id_producto,
	v.descripcion
union all

SELECT	d.Id_Empresa,--este query tiene facturas que tienen descuento por valor
		(select nombre_empresa from empresas where id_empresa=@id_empresa) as nombre_empresa,
		t.Id_depto ,
		t.Nombre,
		d.ID_PRODUCTO,
		p.Descripcion,
		(d.Cantidad *d.Precio) as Sub_total,
		round( ((D.CANTIDAD*D.Precio)*C.DESCUENTO)/C.SUBTOTAL,2) as Descuento,
		(d.Cantidad *d.Precio)  -   	round( ((D.CANTIDAD*D.Precio)*C.DESCUENTO)/C.SUBTOTAL,2) as totalvta_neta,
		round( ((d.Cantidad *d.Precio)  -   	round( ((D.CANTIDAD*D.Precio)*C.DESCUENTO)/C.SUBTOTAL,2))		/
		case when datediff(day,c.fecha_Factura,@apartirde) <=0 
			then @coeficiente
			else @coeficiente1 end ,2) as totalneto
			
		FROM Tbl_Cab_Facturacion C, Tbl_Det_Facturacion D,Tbl_departamentos t,Tbl_Linea l,Tbl_Productos p
		WHERE	C.Id_Empresa	=D.Id_Empresa	AND
				C.Id_Caja		=D.Id_Caja		AND
				C.Autorizacion	=D.Autorizacion AND
				C.Serie			=D.Serie		AND
				C.Id_Tipo		=D.Id_Tipo		AND
				C.Numero		=D.Numero		AND
				p.Id_Empresa	=d.Id_Empresa   and
				p.Id_Producto	=d.Id_Producto  and
				p.Id_Empresa	=t.Id_Empresa   and
				p.Id_Depto		=t.Id_depto     and
				p.Id_Empresa	=l.Id_Empresa   and
				p.Id_Depto		=l.Id_Depto		and
				p.Id_Linea		=l.Id_Linea     and 
				c.Id_Empresa	=@Id_empresa    and
				C.Descuento>0					AND -- si tiene descuento por valor
				
				(select SUM(Cantidad*Precio)	-sum (Cantidad*Precio_Descuento )	from
				Tbl_Det_Facturacion  j
				where	j.Id_Empresa	=c.id_empresa	and
						j.Id_Caja		=c.Id_Caja		and 
						j.Autorizacion	=C.Autorizacion and
						j.Serie         =C.Serie        and
						j.Id_Tipo       =C.Id_Tipo      and
						j.Numero		=C.Numero ) =0  and
				datediff(day,Fecha_factura,@Fecha_final )	between
					0	and datediff(day,@Fecha_inicial,@Fecha_final )    and
				D.id_producto<>'GAS' 	) Z
group by Z.Id_Empresa,
		Z.Nombre_Empresa,
		Z.Id_Depto,
		Z.Nombre,
		Z.Id_Producto,
		Z.Descripcion				
	
GO
               
-- =============================
-- SP: rpt_ventas_por_fechas
-- =============================









--select *from tbl_Cab_facturacion where CAJERO='DEVELOPER' AND LCORTE_CAJA=2 
--SET DATEFORMAT DMY
--EXEC rpt_ventas_por_fechas 2,2,'20/04/2011','20/04/2015'
--EXEC db_inventario_pfp.dbo.rpt_ventas_por_fechas 1,1,'01/01/2015','06/05/2015'
CREATE  procedure [dbo].[rpt_ventas_por_fechas] 	@Id_Empresa	int,
						@Id_caja	int,
						@Fecha_Inicial	datetime,
						@Fecha_Final	datetime as


declare @dias 			int
declare @Nombre_empresa		char(100)

SELECT @Nombre_Empresa=Nombre_empresa FROM EMPRESAS where Id_Empresa=@Id_Empresa
select	@Nombre_Empresa as nombre_empresa,
	fecha_factura,
	Id_caja,
	serie,
	id_tipo,
	numero,
	contado_o_credito,
	facturar_a,
	case when status=3 AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else  subtotal	END AS subtotal,
	case when status=3 AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else descuento END AS descuento,
	case when status=3 AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else total		END AS total,

case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***' THEN 0 else efectivo			END AS efectivo,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'     THEN 0 else vuelto			END AS vuelto,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'     THEN 0 else valor_Cheque		END AS valor_cheque,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'     THEN 0 else Valor_tarjeta		END AS valor_tarjeta,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else Valor_Anticipo	END AS anticipos_pagados,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else Round(Valor_Dolares *tasa_cambio,2) 	END AS Moneda_Extranjera_pagados,
case when status=3  AND SUBSTRING(FACTURAR_A,1,13)='***ANULADA***'  THEN 0 else Valor_OtraFormaPago 	END AS Valor_otraformadepago,

	
	'S'	AS ORIGEN,
	Status
 from tbl_cab_Facturacion
where 	Id_Empresa		=@Id_Empresa		and
	Id_Caja				=case when @Id_Caja=0 then Id_caja else @Id_caja end		and
	DATEDIFF(DAY,fecha_factura,@FECHA_FINAL) between 0 and datediff(day,@Fecha_Inicial,@Fecha_Final)	
union all
select	@Nombre_Empresa as nombre_empresa,
	C.fecha_factura,
	C.id_caja,
	C.serie,
	C.id_tipo,
	C.numero,
	C.contado_o_credito,
	C.facturar_a,
	--(SELECT sum(D.cantidad*D.precio) FROM  TBL_DET_NOTAS_CREDITO D WHERE D.ID_EMPRESA=C.ID_EMPRESA AND D.ID_CAJA=C.ID_cAJA AND
	--D.AUTORIZACION=C.AUTORIZACION AND D.SERIE=C.SERIE AND D.ID_TIPO=C.ID_TIPO AND D.NUMERO=C.NUMERO  ) AS  subtotal,
C.subtotal,
	c.descuento as descuento,
--	(SELECT sum((D.cantidad*D.precio)-(D.cantidad*D.precio_descuento)) FROM  TBL_DET_NOTAS_CREDITO D WHERE D.ID_EMPRESA=C.ID_EMPRESA AND D.ID_CAJA=C.ID_cAJA AND
--	D.AUTORIZACION=C.AUTORIZACION AND D.SERIE=C.SERIE AND D.ID_TIPO=C.ID_TIPO AND D.NUMERO=C.NUMERO  ) AS 	descuento,

	--(SELECT sum( (D.cantidad*D.precio)	- ( (D.cantidad*D.precio)-(D.cantidad*D.precio_descuento)) ) FROM  TBL_DET_NOTAS_CREDITO D WHERE D.ID_EMPRESA=C.ID_EMPRESA AND D.ID_CAJA=C.ID_cAJA AND
	--D.AUTORIZACION=C.AUTORIZACION AND D.SERIE=C.SERIE AND D.ID_TIPO=C.ID_TIPO AND D.NUMERO=C.NUMERO  ) AS 	total,

	--(SELECT sum( (D.cantidad*D.precio)	 ) FROM  TBL_DET_NOTAS_CREDITO D WHERE D.ID_EMPRESA=C.ID_EMPRESA AND D.ID_CAJA=C.ID_cAJA AND
	--D.AUTORIZACION=C.AUTORIZACION AND D.SERIE=C.SERIE AND D.ID_TIPO=C.ID_TIPO AND D.NUMERO=C.NUMERO  )-c.descuento AS 	total,
c.total,

	C.Efectivo,
	C.vuelto,
	C.Valor_Cheque,
	C.Valor_Tarjeta,
	Valor_Anticipo  as anticipos_pagados,
	Round(c.Valor_Dolares *c.tasa_cambio,2) AS Moneda_Extranjera_pagados,
	case when status=3 and upper(facturar_a)='ANULADA' THEN 0 else C.Valor_otraformapago 	END AS Valor_otraformadepago,

	'S'	AS ORIGEN,
	status
 from tbl_cab_notas_credito C
where 	C.Id_Empresa		=@Id_Empresa		and
	C.Id_Caja				=case when @Id_Caja=0 then Id_caja else @Id_caj
-- =============================
-- SP: rpt_ventas_por_mes_anual
-- =============================
--exec rpt_ventas_por_mes_anual  1, '2011','DICIEMBRE'
CREATE procedure [dbo].[rpt_ventas_por_mes_anual]
				 @id_empresa  int,
				 @año		  char(4),
				 @mes_final   char(10),
				 @tasa_cambio	numeric(12,2) as	 


DECLARE @MES INT 
set dateformat dmy
IF @mes_final='ENERO'
	SET @mes=1
	ELSE IF @mes_final='FEBRERO'
			SET @MES=2 
				ELSE IF @mes_final='MARZO'
						SET @MES=3
						ELSE IF @mes_final='ABRIL'
								SET @MES=4
								ELSE IF @mes_final='MAYO'
										SET @MES=5
										ELSE IF @mes_final='JUNIO'
												SET @MES=6
												ELSE IF @mes_final='JULIO'
														SET @MES=7
														ELSE IF @mes_final='AGOSTO'
																SET @MES=8
																ELSE IF @mes_final='SEPTIEMBRE'
																		SET @MES=9
																		ELSE IF @mes_final='OCTUBRE'
																				SET @MES=10
																				ELSE IF @mes_final='NOVIEMBRE'
																						SET @MES=11
																						ELSE IF @mes_final='DICIEMBRE'
																						SET @MES=12
																						ELSE SET @MES=01



declare @nombre_empresa varchar(100)
set @nombre_empresa = (select nombre_empresa from empresas  where id_empresa = @id_empresa)
select 
@nombre_empresa as nombre_empresa,
p.Nombre,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='01')/@tasa_cambio enero,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='02')/@tasa_cambio febrero,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='03')/@tasa_cambio marzo,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='04')/@tasa_cambio abril,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='05')/@tasa_cambio mayo,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='06')/@tasa_cambio junio,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='07')/@tasa_cambio julio,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='08')/@tasa_cambio agosto,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='09')/@tasa_cambio septiembre,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='10')/@tasa_cambio octubre,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='11')/@tasa_cambio noviembre,
(SELECT ISNULL(SUM(cc.Valor_docto),0) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and month(fecha_docto)='12')/@tasa_cambio diciembre,
(SELECT SUM(cc.Valor_docto) from Tbl_cuentas_por_cobrar cc where cc.id_empresa = @id_empresa and cc.nit = c.nit and year(fecha_docto) = @año and month(fecha_docto) <= @mes) as total
--SUM(c.Valor_docto) as total
from Tbl_cuentas_por_cobrar c
inner join Tbl_Proveedores p
on  c.id_empresa = p.id_empresa			and
	c.nit		 = p.nit
where  c.Id_Empresa		 =  @id_empresa and
	   YEAR(Fecha_docto) =  @año			   
group by  p.Nombre, c.id_empresa, c.Nit 
GO
                                                                                     
