CREATE procedure [dbo].[rpt_ventas_por_producto]  @Id_empresa int,
		@Fecha_inicial datetime,
		@Fecha_final	datetime as
set dateformat dmy
/*set @id_empresa=2
set @fecha_inicial='08/02/2009'
set @fecha_final='12/02/2009'*/
select	vp.Nombre_Empresa,

		   vp.Id_Producto as producto,
		vp.Descripcion as descripcion,
		sum(vp.Cantidad) as cantidad,
		sum((vp.Cantidad*vp.Precio)-vp.Descuento) as total,
		sum(vp.descuento) as descuento,
		
		
		case @Id_empresa when 1
		then 'Restaurante PITACHEF 4 Grados'
		                 when 2
		then 'Restaurante PITACHEF Cayala'
				else vp.Nombre_Empresa end as tienda
		from dbo.ventas_por_producto vp 

where vp.Id_Empresa=@Id_empresa	and
		datediff(day,vp.Fecha_Factura,@fecha_final) between 0 and
		datediff(day,@fecha_inicial,@fecha_final)
	group by nombre_empresa,vp.Id_Producto,vp.Descripcion

		

		


		




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
