CREATE  procedure [dbo].[rpt_ventas_por_producto_eventos]  @Id_empresa int,
		@Fecha_inicial datetime,
		@Fecha_final	datetime as
set dateformat dmy
/*set @id_empresa=2
set @fecha_inicial='08/02/2009'
set @fecha_final='12/02/2009'*/
select	nombre_empresa,
		replicate('0',2-len( ltrim(rtrim(cast( day(fecha_factura) as char)))  ) )+
		ltrim(rtrim(cast( day(fecha_factura) as char)))+'/'+
		ltrim(rtrim(cast(month(fecha_factura)as char)))+'/'+
		ltrim(Rtrim(cast(year(fecha_factura) as char))) as fecha,
		ltrim(rtrim(id_producto))+' '+ltrim(rtrim(descripcion)) as producto,
		sum(cantidad) as cantidad,
		sum((cantidad*precio)-descuentazo) as total
		from dbo.ventas_por_producto_EVENTOS 
where id_empresa=@Id_empresa	and
		datediff(day,fecha_factura,@fecha_final) between 0 and
		datediff(day,@fecha_inicial,@fecha_final)
	group by nombre_empresa,day(fecha_factura),
		month(fecha_factura),
		year(fecha_factura),id_producto,descripcion




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
