-- SP: rpt_ventas_por_vendedor
-- =============================


CREATE  PROCEDURE [dbo].[rpt_ventas_por_vendedor]  
	@id_empresa int,
	@Id_vendedor char(10), 
	@Fecha_inicial datetime,
    @Fecha_final	datetime as
set dateformat dmy
select fac.id_empresa,
		(select nombre_empresa from empresas where id_empresa=@Id_empresa) as Nombre_Empresa,
		@Fecha_inicial as fecha_inicial,
		@Fecha_Final  as fecha_final,
		fac.id_empleado as id_vendedor,
		(select nombre from Tbl_Vendedores ven where fac.Id_Empresa=ven.id_empresa and fac.id_empleado=ven.Id_Empleado ) as vendedor,
		fac.nit,
		fac.facturar_a,
		fac.tarjeta_beneficio,
		fac.contado_o_credito ,
		fac.id_empleado ,
		fac.Total,
		fac.Fecha_Factura,
		fac.Subtotal,
		fac.Fecha_hora,
		fac.Id_Tipo,
		fac.Descuento
		from Tbl_Cab_Facturacion fac
where	fac.Id_Empresa=@id_empresa and
		fac.id_empleado = case when @Id_vendedor='TODOS'
								THEN fac.id_empleado
								else @Id_vendedor
								
		 end and
		 datediff(day,fac.fecha_factura,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) and
		 fac.status <>3


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
-- =============================
-- SP: rpt_ventas_producto_promedio
-- =============================
--exec rpt_ventas_producto_promedio 1,'05/2009','06/2009','07/2009','08/2009'

CREATE procedure [dbo].[rpt_ventas_producto_promedio] @ID_EMPRESA INT,@mes1 char(7),@mes2 char(7),@mes3 char(7),@mes4 char(7)  as


--DROP TABLE #resumen_vtas
--DEALLOCATE #RESUMEN_VTAS
create table #resumen_vtas(id_empresa int,
Id_producto char(15) COLLATE Modern_Spanish_CI_AS, 
Periodo     char(7)  COLLATE Modern_Spanish_CI_AS, 
cantidad numeric(12,2))


--set QUOTED_IDENTIFIER ON 



insert  #resumen_vtas 
 select D.id_empresa,
	d.id_producto,
	D.PERIODO,
	sum(d.cantidad) as cantidad from tbl_det_facturacion d,TBL_CAB_FACTURACION C 
where 	d.id_empresa=c.id_empresa 	and 
	d.id_caja=c.id_caja 		and 	
	d.autorizacion=c.autorizacion 	and 
	d.serie=c.serie 		and 
	d.id_tipo=c.id_tipo 		and 
	 d.numero=c.numero 		and 
	d.id_empresa=@ID_EMPRESA 	and 
	(D.PERIODO=@MES1 OR D.PERIODO=@MES2 OR D.PERIODO=@MES3 or d.periodo=@mes4) 
	AND status<>3 group by D.ID_EMPRESA,d.periodo,d.id_producto ORDER BY d.id_producto 




create table #resumen_vtas_prod (id_empresa	int,
				Nombre_empresa  char(80),	
				Id_depto	varchar(50),
				Id_linea	varchar(50),
				Id_producto 	char(15) COLLATE Modern_Spanish_CI_AS, 
				
				descripcion	varchar(80) COLLATE Modern_Spanish_CI_AS, 
				mes01     	numeric(12,2), 
				mes02     	numeric(12,2), 
				mes03 		numeric(12,2),
				mes04		numeric(12,2),
				nombremes1	varchar(15),
				nombremes2      varchar(15),
				nombremes3	varchar(15),
				nombremes4	varchar(15),
				cantidad numeric(12,2))
insert #resumen_vtas_prod
select p.id_empresa,
(select nombre_empresa from empresas where id_empresa=@Id_empresa) as nombreempresa,
ltrim(rtrim(p.id_depto))+' '+ltrim(rtrim(d.nombre)),
ltrim(rtrim(p.id_linea))+' '+l.nombre_linea,
p.id_producto,
p.descripcion,
ISNULL((select sum( t.cantidad ) from #resumen_vtas t where t.id_empresa=p.id_empresa and ltrim(rtrim(t.id_producto))=ltrim(rtrim(p.id_producto)) and t.periodo=@mes1 ),0)  as cantidad1,
ISNULL((select sum( t.cantidad ) from #resumen_vtas t where t.id_empresa=p.id_empresa and t.id_producto=p.id_producto and PERIODO=@mes2 ),0)  as cantidad2,
ISNULL((select sum( t.cantidad ) from #resumen_vtas t where t.id_empresa=p.id_empresa and t.id_producto=p.id_producto and PERIODO=@mes3),0)  as cantidad3,
ISNULL((select sum( t.cantidad ) from #resumen_vtas t where t.id_empresa=p.id_empresa and t.id_producto=p.id_producto and PERIODO=@mes4),0)  as cantidad4,
dbo.nombre_mes(@id_empresa,substring(@mes1,4,4),substring(@mes1,1,2)) as nombre1,
dbo.nombre_mes(@id_empresa,substring(@mes2,4,4),substring(@mes2,1,2)) as nombre2,
dbo.nombre_mes(@id_empresa,substring(@mes3,4,4),substring(@mes3,1,2)) as nombre3,
dbo.nombre_mes(@id_empresa,substring(@mes4,4,4),substring(@mes4,1,2)) as nombre4,
(select sum(e.existencia) 
  from tbl_existencia e where e.id_empresa=p.id_empresa and e.id_producto=p.id_producto and e.periodo=@mes4 ) as existencia
 from tbl_productos p 	inner join tbl_departamentos d on p.id_empresa=d.id_empresa and p.id_depto=d.id_depto
			inner join tbl_linea 	l	on p.id_empresa=l.id_empresa and p.id_depto=l.id_depto and   p.id_linea=l.id_linea	
drop table #resumen_vtas

select *from #resumen_vtas_prod where mes01+mes02+mes03+mes04<>0

drop table #resumen_vtas_prod
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: sp_abc_proveedores
-- =============================
CREATE PROCEDURE sp_abc_proveedores @Id_empresa int as
declare @nit char(20)
set @Id_empresa =3
declare eliminaproveedores cursor for
select nit from Tbl_Proveedores where Id_Empresa=3
open eliminaproveedores
fetch eliminaproveedores into @nit
while @@FETCH_STATUS=0
begin
	delete from tbl_proveedores where id_empresa=@Id_empresa and nit=@nit and Nit<>'XXXXXXXXXXXXXXXXXXXX'
	fetch eliminaproveedores into @nit
end

close eliminaproveedores
deallocate eliminaproveedores

--eliminando proveedor interno
alter table tbl_proveedores disable trigger all
delete from Tbl_Proveedores where Id_Empresa=3 and Nit='XXXXXXXXXXXXXXXXXXXX'
alter table tbl_proveedores enable trigger all
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
