-- SP: sp_actualiza_cxp
-- =============================






--exec sp_actualiza_cxp 1
CREATE   procedure [dbo].[sp_actualiza_cxp] @Id_Empresa int as
-- este procedimiento actualiza las compras del modulo de inventarios al modulo de cuentas por pagar
begin
Begin Transaction t1
	Declare @NIT		CHAR(20),
		@Id_Tipo	char(3),
		@Serie      char(15),
		@Numero		Numeric(10),
		@Concepto	char(200),
		@Fecha		datetime,
		@Valor_Factura	Numeric(12,2),
		@Saldo_factura  Numeric(12,2),
		@porcentaje_iva	numeric(12,2),		
		@porcentaje_iva_anterior	numeric(12,2),
		@Valor_Iva	numeric(12,2),
		@apartirde	datetime,
		@Dias_credito	int,
		@tipo_iva	int,
	        @error_number    INT,
        	@error_message   VARCHAR(255)
	

	select 	@porcentaje_iva		=porcentaje_iva,
		@porcentaje_iva_anterior=porcentaje_iva_anterior,
		@apartirde		=apartirde from empresas where id_empresa=@Id_empresa

	set @porcentaje_iva		=Round(@porcentaje_iva/100,2)
	set @porcentaje_iva_anterior	=Round(@porcentaje_iva_anterior/100,2)

--trasladando todas las facturas que no tienen orden de compra al modulo de cuentas por pagar
	Declare Facturas  cursor For
/*	select 	c.Nit,
		c.Id_Tipo,
		c.Numero,
		c.Concepto,
		c.Fecha,
		ISNULL((Select Sum(d.Total) from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo		=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  as valor_factura,
		ISNULL( (Select Sum(d.Total)  as saldo_factura from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo	=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  
	from tbl_cabecera_movimientos c
	where 	c.Id_Empresa	=	@Id_Empresa	and
		c.id_tipo	=	'COM'		AND
		C.credito_o_contado	=	1		and
		c.Flag				=0			and
		c.ltiene_orden_compra=0*/
select 		c.Nit,
		c.Id_Tipo,
		c.serie,
		c.Numero,
		c.Concepto,
		c.Fecha,
		ISNULL((Select Sum(d.Total)  as total_compra from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo		=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  as valor_factura,
		ISNULL((Select Sum(d.Total)  as total_compra from tbl_Detalle_movimientos d
		Where 	d.Id_Empresa	=c.Id_Empresa	and
			d.Periodo		=c.Periodo	and
			d.Id_Bodega	=c.Id_Bodega	and
			d.Id_Tipo	=c.Id_Tipo	and
			d.Numero	=c.Numero	and
			d.NIT		=c.Nit ),0)  as valor_factura

	from tbl_cabecera_movimientos c,tbl_proveedores p
	where 	c.Id_Empresa	=	@Id_Empresa	and
		c.id_tipo	=	'COM'		AND
		C.credito_o_contado=	1		and
		c.Flag		=0			and
		c.id_empresa	=p.id_empresa		and
		c.nit		=p.nit			and

		ltrim(rtrim(cast(c.id_empresa as char)))+
		ltrim(rtrim(c.periodo))+
		ltrim(rtrim(c.id_bodega))+
		ltrim(rtrim(c.nit))+
		ltrim(rtrim(c.numero)) not in 
		(select distinct	ltrim(rtrim(cast(c.id_empresa as char)))+
				ltrim(rtrim(c.periodo))+
				ltrim(rtrim(c.id_bodega))+
				ltrim(rtrim(c.nit))+
				ltrim(rtrim(c.numero)) from  tbl_detalle_generacion_compra c)
----


	Open Facturas
	Fetch Facturas into 	@NIT,
				@Id_Tipo,
				@Serie,
				@Numero,
				@Concepto,
				@Fecha,
				@Valor_Factura,
				@Saldo_Factura	
	While @@Fetch_status=0
	begin
		select 	@dias_credito	=dias_credito,
			@tipo_iva	=tipo_iva from tbl_proveedores where id_empresa=@Id_empresa and nit=@nit
		if not exists(select *from tbl_cargos where id_empresa=@Id_Empresa	and nit=@nit and numero_factura=@Numero)
		begin
			if datediff(day,@apartirde,@fecha)>0
				set @valor_iva=@valor_Factura- ( @Valor_Factura/(@porcentaje_iva+1))
			else
				set @valor_iva=@valor_Factura- ( @valor_factura/(@porcentaje_iva_anterior+1))
			
			insert tbl_cargos
			select 	@Id_Empresa,
				@NIT,
				'FAC',
				@Serie,
				@Numero,
	
