CREATE procedure [dbo].[sp_anticipos_recibos]	@id_empresa	int,
					@Id_caja	int,
					@fecha_inicial	datetime,
					@fecha_final	datetime as
begin

	declare @valor_anticipo	numeric(12,2)
	select id_anticipo,
		nit,
		facturar_a,
		valor as anticipos from tbl_anticipos_pos
	where	id_empresa=@id_empresa and
			id_caja=@Id_caja		and
	datediff(day,fecha_anticipo,@fecha_final) between 0 	and
	datediff(day,@fecha_inicial,@fecha_final)	

end



