create procedure sp_calcula_precio_moneda_local @Id_empresa int as

Declare @Tasa_Cambio Numeric(12,5)

select @Tasa_cambio= tasa_CAMBIO  from empresas where id_empresa=@iD_EMPRESA 

 UPDATE  tbl_productos set PRECIOA= PRECIOC*@Tasa_cambio 
 where id_empresa=@Id_empresa 
