--EXEC SP_COMPARA_INV_VRS_SISTEMAS 1
CREATE PROCEDURE sp_compara_inv_vrs_sistemas  @ID_TRANSAC INT as
--este procedimiento devuelve la existencia reportada al  momento de hacer el inventario
--vrs la existencia segun db

SELECT *FROM

(
SELECT INV.ID_PRODUCTO,
	   INV.EXISTENCIA	AS EXISTENCIA_SEGUN_SISTEMA_EN_INV,
ISNULL (  (	   SELECT EXISTENCIA FROM DBO.Tbl_existencia EXIST
WHERE EXIST.ID_EMPRESA=99 AND
EXIST.PERIODO='06/2019'  AND
EXIST.ID_PRODUCTO=INV.ID_PRODUCTO) ,0) AS EXISTENCIA_SEGUNDB

 FROM tbl_inventario_fisico_detalle INV 
WHERE INV.ID_EMPRESA=99 AND
ID_TRANSAC=@ID_TRANSAC
) X WHERE X.EXISTENCIA_SEGUN_SISTEMA_EN_INV<>X.EXISTENCIA_SEGUNDB

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: sp_compone_envios
-- =============================

create procedure sp_compone_envios as

DECLARE @NIT	CHAR(20),@ID_BODEGA CHAR(10),@ID_TIPO CHAR(3),@NUMERO NUMERIC(12,2),@VALOR_aPLICADO NUMERIC(12,2),@TOTAL_ENVIO NUMERIC(12,2),@ID_EMPRESA INT
DECLARE @PERIODO CHAR(7),@TOTAL_ENV	NUMERIC(12,0)
SET @ID_EMPRESA=1
DECLARE ENVIOS CURSOR FOR
SELECT 	PERIODO,
	ID_BODEGA,
	ID_TIPO,
	NUMERO,
	NIT,
	SUM(TOTAL) AS TOTAL FROM TBL_DETALLE_MOVIMIENTOS
WHERE ID_EMPRESA=@ID_EMPRESA AND ID_TIPO='ENV' GROUP BY ID_EMPRESA,PERIODO,ID_BODEGA,ID_TIPO,NUMERO,NIT
OPEN ENVIOS
FETCH ENVIOS INTO @PERIODO,@ID_BODEGA,@ID_TIPO,@NUMERO,@NIT,@TOTAL_ENV
WHILE @@FETCH_STATUS=0
BEGIN
	UPDATE TBL_CABECERA_MOVIMIENTOS SET SALDO_ENVIO=@TOTAL_ENV
	WHERE 	ID_EMPRESA	=@ID_EMPRESA	AND
		PERIODO		=@PERIODO	AND
		ID_BODEGA	=@ID_BODEGA	AND
		ID_TIPO		=@ID_TIPO 	AND
		NUMERO		=@NUMERO	AND
		NIT		=@NIT
FETCH ENVIOS INTO @PERIODO,@ID_BODEGA,@ID_TIPO,@NUMERO,@NIT,@TOTAL_ENV
	
END
CLOSE ENVIOS
DEALLOCATE ENVIOS


--REBAJANDO ABONOS DE LOS ENVIOS
declare abonos cursor for
select nit,id_bodega,
id_tipo,
numero,
sum(valor_aplicado) as valor_aplicado
from tbl_det_cobros where valor_aplicado>0
group by nit,id_bodega,id_tipo,numero
order by nit

open abonos
fetch abonos into @nit,@id_bodega,@id_tipo,@numero,@valor_aplicado
while @@fetch_status=0
begin
	PRINT @NIT
	PRINT @ID_TIPO
	PRINT @NUMERO
	if @id_tipo='ENV'
	BEGIN
		SELECT  @TOTAL_ENVIO=SUM(TOTAL )FROM TBL_DETALLE_MOVIMIENTOS
		WHERE 	ID_EMPRESA=@ID_EMPRESA AND
			NIT		=@NIT	AND
			 ID_TIPO=@ID_TIPO	AND
			NUMERO=@NUMERO

		PRINT 'TOTAL ENVIO'
		PRINT @TOTAL_ENVIO
		UPDATE TBL_CABECERA_MOVIMIENTOS SET SALDO_ENVIO=ISNULL(@TOTAL_ENVIO,0)-@VALOR_aPLICADO
		WHERE ID_EMPRESA=@ID_EMPRESA	AND
			NIT=@NIT	AND
			ID_TIPO='ENV'	AND
			NUMERO=@NUMERO		
		
	END	
fetch abonos into @nit,@id_bodega,@id_tipo,@numero,@valor_aplicado

end
close abonos
deallocate abonos


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
-- =============================
-- SP: sp_consulta_entradas
-- =============================

--exec sp_consulta_entradas 1,'12/2005'

CREATE procedure sp_consulta_entradas @Id_Empresa	int,@periodo char(7) as
select 	c.id_tipo,
	c.id_bodega,
	c.nit,
	c.Numero ,
	p.nombre,
	(case when c.status=1
		then 'Abierto'
		else 'Cerrado' end) as status from tbl_cabecera_movimientos c
				inner join tbl_tipos_inv 	t
				on	c.Id_empresa	=t.Id_Empresa	and
					c.Id_Tipo	=t.id_tipo
				inner join tbl_proveedores	p
				on	c.Id_empresa	=p.Id_Empresa	and
					c.Nit		=p.nit
where c.id_empresa=@Id_Empresa and c.periodo=@periodo and
	t.efecto_inv=1	and c.status=1
order by numero

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
