EXEC SP_CONTABILIZA_COBROS_en_bancos 1,'01','31/12/2006','31/12/2006'
*/
CREATE procedure sp_contabiliza_cobros_en_bancos 	@Id_empresa int,
							@Id_banco char(2),
							@fecha_inicial datetime,
							@fecha_final datetime as

begin transaction t1

declare @Id_tipo_cobro			char(3),
	@Num_docto_cobro		int,
	@Id_cuenta_cxc			char(10),
	@Id_cuenta_efectivo_cxc		char(10),
	@Id_cuenta_transitoria		char(10),
	@Numero_deposito		char(10),
	@Efectivo			numeric(12,2),
	@Valor_cheque			numeric(12,2),
	@Valor_tarjeta			numeric(12,2),
	@valor_deposito			numeric(12,2),
	@descripcion			char(200),
	@fecha_docto			datetime,
	@ejercicio_fiscal		char(4),
	@mes_fiscal			char(2)

select @id_cuenta_cxc=id_cuenta_cxc,
	@id_cuenta_transitoria	=id_cuenta_dep_transito_cxc  from empresas where id_empresa=@id_empresa



Declare depositos cursor for
select 	Id_tipo_cobro,
	Num_docto_cobro,
	Id_banco_DEPOSITO,
	Numero_deposito,
	descripcion,
	fecha_docto,
	Efectivo,
	Valor_cheque,
	valor_tarjeta,
	valor_deposito from tbl_cobros
where id_empresa=@id_empresa 	and 
	id_banco_DEPOSITO=@Id_banco	and
	datediff(day,fecha_docto,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) and
	contabilizado=2

open depositos
fetch depositos into 	@Id_tipo_cobro,
			@num_docto_cobro,
			@Id_banco,
			@numero_deposito,
			@descripcion,
			@fecha_docto,
			@efectivo,
			@valor_cheque,
			@valor_tarjeta,
			@valor_deposito
while @@fetch_status=0
begin

	select @ejercicio_fiscal=anio,
		@mes_fiscal=mes from db_contabilidad_pfp.dbo.meses where id_empresa=@id_empresa and @fecha_docto between del and al and MES<>'13' AND MES<>'00'

	insert db_bancos_pfp.dbo.tbl_mov_bancos(Id_empresa,
						Id_banco,
						Id_tipo,
						Numero,
						Descripcion,
						BENEFICIARIO,
						Valor,
						Fecha,
						Anio,
						Mes) values
						
	( 	@Id_empresa,
		@Id_banco,
		'DEP',
		@Numero_deposito,
		@descripcion,
		'',
		@valor_Deposito,
		@Fecha_docto,
		@ejercicio_fiscal,
		@mes_fiscal		)

	if @@error<>0
	begin
		rollback tran t1
		return
	end

	insert db_contabilidad_pfp.dbo.detalle_transacciones(Id_empresa,
								anio,
								mes,
								id_banco,
								tipo,
								numero,
								linea,
								descripcion,
								debe,
								haber,
								id_cuenta,
								id_auxiliar,
								id_departamento,
								ldetalle_iva)	values
								(@Id_empresa,
								@ejercicio_fiscal,
								@mes_fiscal,
								@id_banco,
								'DEP',
								@Numero_deposito,
								2,
								@descripcion,
								0,
								@valor_deposito,
								@Id_cuenta_cxc,
								'',
								'',
								0)				
	if @@error<>0
	begin
		rollback tran t1
		return
	end
--	Si el cobro fue pagado con deposito yy con (efectivo o cheque o tarjeta) el sistema genera el registror a una cuenta temporal
	if @efectivo+@valor_cheque+@valor_tarjeta<>0
	begin
--		insertando cuenta transitoria para registrar		
		insert db_contabilidad_pfp.dbo.detalle_transacciones(Id_empresa,
								anio,
								mes,
								id_banco,
								tipo,
								numero,
								linea,
								descripcion,
								debe,
								haber,
								id_cuenta,
								id_auxiliar,
								id_departamento,
								ldetalle_iva)	values
								(@Id_empresa,
								@ejercicio_fiscal,
								@mes_fiscal,
								@id_banco,
								'DEP',
								@Numero_deposito,
								3,--linea de deposito
								@descripcion,
								(@efectivo+@valor_cheque+@valor_tarjeta),
								0,	
								@Id_cuenta_transitoria,
								'',
								'',
								0)				
		if @@error<>0
		begin
			rollback tran t1
			return
		end

	end
--	registrando la rebaja de las cuentas por cobr
