/*
set dateformat dmy
EXEC SP_CONTABILIZA_COBROS_en_contabilidad 1,'03/01/2007','03/01/2007','PD','1'
*/
CREATE procedure [dbo].[sp_contabiliza_cobros_en_contabilidad] 	@Id_empresa int,
							@fecha_inicial datetime,
							@fecha_final datetime,
							@Tipo_contable char(3),
							@Numero_poliza char(10) as

begin transaction t1

declare @Id_tipo_cobro			char(3),
	@Num_docto_cobro		int,
	@Id_cuenta_cxc			char(10),
	@Id_cuenta_efectivo_cxc		char(10),
	@Id_cuenta_transitoria		char(10),
	@Numero_deposito		char(10),
	@Efectivo			numeric(12,2),
	@Valor_cheque			numeric(12,2),
	@Valor_tarjeta			numeric(12,2),
	@valor_deposito			numeric(12,2),
	@descripcion			char(200),
	@fecha_docto			datetime,
	@ejercicio_fiscal		char(4),
	@mes_fiscal			char(2),
	@Diatransaccion			int

select @id_cuenta_cxc=id_cuenta_cxc,
	@id_cuenta_transitoria	=id_cuenta_dep_transito_cxc  from empresas where id_empresa=@id_empresa

Declare @Cobro_inicial 	int,
	@Cobro_final	int
select  @Cobro_inicial	=min(num_docto_cobro),
	@Cobro_final	=max(num_docto_cobro),
	@Diatransaccion	=day(max(fecha_docto)) from tbl_cobros
where 	Id_Empresa=@Id_empresa	and 
	datediff(day,fecha_docto,@fecha_final) between 0 and
				datediff(day,@fecha_inicial,@fecha_final) and
	contabilizado=2

set @descripcion=	'Registro de cobros del Recibo No '+ltrim(rtrim(cast(@cobro_inicial as char)))+ 'Al '+ltrim(rtrim(cast(@cobro_final as char)))+','+
			'Correspondiente al periodo del '+cast(@fecha_inicial as char)+ ' al'+cast(@fecha_final as char)

IF EXISTS(select *from tbl_cobros where id_empresa=@id_empresa 						and 
	datediff(day,fecha_docto,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) 	and
	contabilizado=2)
BEGIN
	Declare cobros_aconta cursor for
	select 	
		ISNULL(Sum(Isnull(Efectivo,0)),0) 	as efectivo,
		ISNULL(Sum(Isnull(Valor_cheque,0)),0) 	as valor_cheque,
		ISNULL(Sum(Isnull(valor_tarjeta,0)),0)  as valor_tarjeta,
		ISNULL(Sum(Isnull(valor_deposito,0)),0) as valor_deposito from tbl_cobros
	where id_empresa=@id_empresa 		and 
		datediff(day,fecha_docto,@fecha_final) between 0 and datediff(day,@fecha_inicial,@fecha_final) and
		contabilizado=2 and
		efectivo<>0

	open cobros_aconta
	fetch cobros_aconta into 	@efectivo,
					@valor_cheque,
					@valor_tarjeta,
					@valor_deposito
	while @@fetch_status=0
	begin
		select @ejercicio_fiscal=anio,
			@mes_fiscal=mes from db_contabilidad_pfp.dbo.meses 
		where id_empresa=@id_empresa and @fecha_FINAL between del and al and MES<>'13' AND MES<>'00'

		insert db_contabilidad_pfp.dbo.cabecera_movimientos(Id_empresa,
							Anio,
							Mes,
							Tipo,
							Numero,
							dia,
							Descripcion,
							sistema,
							conciliado,
							Id_Banco)
							values
		( 	@Id_empresa,
			@Ejercicio_fiscal,
			@Mes_fiscal,
			@Tipo_Contable,
			@Numero_Poliza,
			@diatransaccion,
			'Registro de depositos por realizar segun cobro(s) del'+cast(@fecha_inicial as char)+'Al '+cast(@fecha_final as char),
			7,
			0,
			'XX')

		if @@error<>0
		begin
			rollback tran t1
			return
		end
--	insertando la cuenta transitoria en el detalle de la poliza
		insert db_contabilidad_pfp.dbo.detalle_transacciones(Id_empresa,
									anio,
									mes,
									id_banco,
									tipo,
									numero,
									linea,
									descripcion,
									debe,
									haber,
									id_cuenta,
									id_auxiliar,
									id_departamento,
									ldetalle_iva)	values
									(@Id_empresa,
									@ejercicio_fiscal,
									@mes_fiscal,
									'XX',
									@Tipo_contable,
									@Numero_poliza,
									1,
									@descripcion,
									(@efectivo+@valor_cheque+@valor_tarjeta+@valor_deposito),
									0,
									@Id_cuenta_transitoria,
									'',
									'',
									0)
		if @@er
