			Sum(Debe-HABER)
			 From tbl_contabiliza_Cargos
			where 	Id_Empresa=@Id_Empresa	and
				CAST(Id_Empresa AS CHAR)+NIT+Id_Tipo_Cargo+Serie +CAST(numero_factura AS CHAR) IN (SELECT CAST(iD_EMPRESA AS CHAR)+NIT+TIPO_CARGO+Serie +CAST(NUMERO_FACTURA AS CHAR) FROM TBL_CARGOS WHERE ID_EMPRESA=@id_empresa AND contabilizado=2 and sistema=@sistema)
				GROUP BY ID_CUENTA,ID_AUXILIAR,ID_dEPARTAMENTO)
BEGIN
	insert db_contabilidad_pfp.dbo.cabecera_movimientos
	select @Id_Empresa,@Periodo_fiscal,@Mes_Fiscal,'XX','PD',@numero,@dia,'Registro de Provision Cuentas Por Pagar',5,getdate(),suser_sname(),2,0,0
	if @@error<>0
	begin
		rollback transaction t1
		return
	end
END

