-- SP: sp_contabiliza_provision_cxc
-- =============================


/*SELECT *FROM TBL_CONTABILIZA_CUENTAS_POR_COBRAR where nit='1187565-8' and numero_docto='11'
DELETE FROM TBL_CONTABILIZA_CUENTAS_POR_COBRAR
select *from tbl_cuentas_por_cobrar*/
--exec sp_contabiliza_provision_cxc 1,'12345','XXX','FAC','566'
CREATE procedure [dbo].[sp_contabiliza_provision_cxc] 	@Id_empresa 	int,
						@Nit		char(20),
						@Serie		char(3),
						@Tipo_docto	char(3),
						@Numero_docto	numeric(10) as

Declare @Id_cuenta_cxc	char(10),
		@Id_cuenta_vtas	char(10),
		@Id_depto_vtas	char(3),
		@Id_cuenta_iva	char(10),
		@Id_cuenta_retencion_iva_clientes char(10),
		@Id_cuenta_retencion_ISR_clientes char(10),
		@Valor_docto	numeric(12,2),
		@Valor_iva		numeric(12,2),
		@Retencion_IVA	numeric(12,2),
		@Retencion_ISR  numeric(12,2)

select 	@Id_cuenta_cxc	=Id_cuenta_cxc,
		@Id_cuenta_vtas	=Id_cuenta_vtas,
		@Id_cuenta_retencion_iva_clientes=Id_cuenta_retencion_iva_clientes,
		@Id_depto_vtas	=Id_depto_vtas,
		@Id_cuenta_retencion_ISR_clientes=Id_Cuenta_Retencion_ISR_clientes  from empresas where id_empresa=@Id_empresa



select @Id_cuenta_iva=Id_cuentadebitofis from db_contabilidad_pfp.dbo.empresas where id_empresa=@Id_empresa

select	@Valor_docto	=valor_docto,
		@Retencion_IVA	=Retencion_IVA,
		@Retencion_ISR  =Retencion_ISR,
		@Valor_iva		=iva from tbl_cuentas_por_cobrar
	where 	id_empresa	=@Id_empresa		and
			nit			=@Nit			and
			Serie		=@Serie			and
			Tipo_docto	=@Tipo_docto	and
			Numero_docto=@Numero_docto



begin transaction t1

--insertando la cuenta de cuentas por cobrar
insert TBL_CONTABILIZA_CUENTAS_POR_COBRAR(Id_empresa,
					Nit,
					Serie,
					Tipo_docto,
					numero_docto,
					Linea,
					Id_cuenta,
					Id_auxiliar,
					Id_departamento,
					Debe,
					Haber) values
					(@Id_empresa,
					@nit,
					@Serie,
					@Tipo_docto,
					@Numero_docto,
					1,
					@Id_cuenta_cxc,
					'',--auxiliar contable
					'',
					@Valor_docto - @Retencion_IVA -@Retencion_ISR,

					0)	
if @@error<>0
	rollback transaction t1

--insertando la cuenta de retencion IVA solo si el cliente es agente retenedor de iva
if (select  es_agente_retenedor_iva from db_inventario_pfp.dbo.Tbl_Proveedores  where Id_Empresa=@Id_empresa and Nit=@Nit )=1
begin
insert TBL_CONTABILIZA_CUENTAS_POR_COBRAR(Id_empresa,
					Nit,
					Serie,
					Tipo_docto,
					numero_docto,
					Linea,
					Id_cuenta,
					Id_auxiliar,
					Id_departamento,
					Debe,
					Haber) values
					(@Id_empresa,
					@nit,
					@Serie,
					@Tipo_docto,
					@Numero_docto,
					2,
					@Id_cuenta_retencion_iva_clientes ,
					'',--auxiliar contable
					'',
					@Valor_iva*0.05,
					0)	
if @@error<>0
	rollback transaction t1
end


--insertando la cuenta de retencion de ISR que nos hace el cliente
IF Exists(	select Regimen_fiscal_isr 
			from empresas where id_empresa=@Id_Empresa and regimen_fiscal_isr='PAGO MENSUAL')
Begin

	insert TBL_CONTABILIZA_CUENTAS_POR_COBRAR(Id_empresa,
						Nit,
						Serie,
						Tipo_docto,
						numero_docto,
						Linea,
						Id_cuenta,
						Id_auxiliar,
						Id_departamento,
						Debe,
						Haber) values
						(@Id_empresa,
						@nit,
						@Serie,
						@Tipo_docto,
						@Numero_docto,
						3,--numero de linea en el detalle contable
						@Id_cuenta_retencion_ISR_clientes,
						'',--auxiliar contable
						'',
						@Retencion_ISR,
						0)	
	if @@error<>0
		rollback transaction t1
	
END


--insertando la cuenta del iva	
insert TBL_CONTABILIZA_CUENTAS_POR_COBRAR(Id_empresa,
					Nit,
					Serie,
					Tipo_docto,
					numero_docto,
					Linea,
					Id_cuenta,
					Id_auxiliar,
					Id_departamento,
					Debe,
					Haber) values
					(@Id_empresa,
					@nit,
					@Serie,
					@Tipo_docto,
					@Numero_docto,
					4,--numero de linea en el detalle contable
					@
