Declare @Id_Cuenta_cxp	char(10),
	@Valor_Aplicado	numeric(12,2)



select @Valor_Aplicado=Valor_Aplicado from tbl_det_abonos Where id_empresa=@Id_empresa and Id_Tipo_Pago=@Id_Tipo_Pago and Numero_pago=@Numero_Pago and nit=@nit and Tipo_cargo=@Tipo_cargo and Numero_Factura=@Numero_Factura 

select @Id_Cuenta_cxp=Id_Cuenta_cxp from tbl_proveedores where id_empresa=@Id_empresa and nit=@nit
begin transaction t1
insert tbl_contabiliza_abonos
select @Id_empresa,@Id_tipo_pago,@Numero_pago,@nit,@serie_factura,@Tipo_cargo,@Numero_factura,@Id_Cuenta_cxp,'','','Rebaja Cuentas por Pagar según docto'+@tipo_cargo+ltrim(rtrim(@numero_factura)),@Valor_aplicado,0
if @@error<>0
	rollback transaction t1
else 	commit transaction t1

