--exec sp_copia_cotizacion 1,1
CREATE procedure sp_copia_cotizacion @Id_empresa int,@Id_cotizacion int as

declare @Id_cotizacion_new int


select @Id_cotizacion_new=MAX(Id_Cotizacion)+1 from Tbl_cotizacion_clientes where Id_Empresa=@Id_empresa 
print @id_cotizacion_new
insert dbo.Tbl_cotizacion_clientes 
select 
	Id_Empresa,
	@Id_cotizacion_new ,
	Nit,
	Fecha_cotizacion ,
	null,
	1 as estado,
	GETDATE(),
	 suser_name(),
	 Tasa_cambio ,
	 Atencion_a ,
	 Linea1,
	 Linea2,
	 Linea3,
	 linea4,
	 credito_o_contado
from Tbl_cotizacion_clientes where Id_Empresa=@Id_empresa and Id_Cotizacion =@Id_cotizacion 

insert Tbl_cotizacion_clientes_detalle 
select id_empresa,
@Id_cotizacion_new ,

Id_Producto ,
Cantidad,
Precio,
Total_linea 
		from Tbl_cotizacion_clientes_detalle 
where Id_Empresa=@Id_empresa  and Id_Cotizacion =@Id_cotizacion 

select id_empresa,
@Id_cotizacion_new ,

Id_Producto ,
Cantidad,
Precio,
Total_linea 
		from Tbl_cotizacion_clientes_detalle 
where Id_Empresa=@Id_empresa  and Id_Cotizacion =@Id_cotizacion 
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
