			@Costo_Promedio numeric(12,2),
			@Tipo			char(10),
			@Propiedad1		char(15),
			@Propiedad2     char(15),
			@Propiedad3     char(15),
			@Propiedad4     char(15),
		    @propiedad5     char(15),
			@propiedad6     char(15),
		    @Cantidad_Equivalente numeric(12,4),
		    @Id_Articulo    char(5),
			@Id_medida      char(3),
			@Id_medida1      char(3),
			@Fecha_Alta      datetime,
			@fotoproducto    varchar(200),
