			@maximo			int,
			@Id_Depto		char(3),
			@Id_Linea		char(2),
			@Descripcion_Corta char(100),
			@ultimo_costo      numeric(18,5),
			@Precioa			numeric(18,2),
			@Preciob			numeric(18,2),
			@Precioc			numeric(18,2),
			@Fecha_Ult_Mov		datetime,
