		    @Es_servicio       int,
			@Aplicar_Descuento int,
			@Porcentaje_Utilidad numeric(18,2),
			@Precio_sugerido     numeric(18,2),
			@Usuario			char(80),
			@Fecha_hora			datetime,
			@ubicacion			char(20),
			@Porc_Max_descuento numeric(5,2),
			@estado				char(15),
		    @Permite_modificar_precio int

			

declare productos cursor for
	select 	[Id_Empresa]
		  ,[Id_Producto]
		  ,[Descripcion]
		  ,[Codigo_Barras]
		  ,[Costo_Promedio]
		  ,[Tipo]
		  ,[Propiedad1]
		  ,[Propiedad2]
		  ,[Propiedad3]
		  ,[Propiedad4]
		  ,[propiedad5]
		  ,[propiedad6]
		  ,[Cantidad_Equivalente]
		  ,[Id_Articulo]
		  ,[Id_medida]
		  ,[Id_medida1]
		  ,[Fecha_Alta]
		  ,[fotoproducto]
		  ,[minimo]
		  ,[maximo]
		  ,[Id_Depto]
		  ,[Id_Linea]
		  ,[Descripcion_Corta]
		  ,[ultimo_costo]
		  ,[Precioa]
		  ,[Preciob]
		  ,[Precioc]
		  ,[Fecha_Ult_Mov]
