-- SP: sp_corte_gasolinera
-- =============================
--exec sp_corte_gasolinera 1, '31/07/2013'
CREATE procedure [dbo].[sp_corte_gasolinera] @id_empresa int, @Fecha_corte datetime as
begin

declare  @error_number    	INT,
	@error_message  	VARCHAR(255)
	
begin transaction t1
update tbl_cabecera_ventas_vale set fecha_corte=@fecha_corte where id_empresa=@id_empresa and fecha_corte is null

	if @@error<>0
	begin
			rollback tran t1
			return
	end
	commit tran t1
end	
return

error:
      RAISERROR @error_number @error_message
      ROLLBACK TRANSACTION
      
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
-- =============================
-- SP: sp_costo_ventas
-- =============================

create procedure sp_costo_ventas 
 @Id_empresa int,
		@Fecha_inicial datetime,
		@Fecha_final   datetime  as

set @Id_empresa =1
set @Fecha_inicial ='01/01/2013'
set @Fecha_final   ='31/01/2013'

select *from Tbl_Cab_Facturacion c inner join Tbl_Det_Facturacion d
			on	c.Id_Empresa=d.Id_Empresa and
				c.Id_Caja	=d.Id_Caja		and
				c.Serie		=d.Serie		and
				c.Numero	=d.numero 	
									inner join Tbl_productos  p
			on  d.Id_Empresa=p.Id_Empresa	and
			    d.Id_Producto =p.Id_Producto 			
									inner join Tbl_departamentos deptos
			on	p.id_empresa	=	deptos.id_empresa and						
				p.id_depto		=   deptos.id_depto
									inner join empresas empre
			on  c.Id_Empresa	=   empre.id_empresa						
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
