-- =============================
-- SP: sp_crea_proveedores_nuevos
-- =============================

--select *from tbl_proveedores where id_empresa=1 and nit not in (select nit from db_contabilidad_pfp.dbo.clientes_proveedores)
-- exec sp_crea_proveedores_nuevos 1

CREATE procedure [dbo].[sp_crea_proveedores_nuevos] @Id_Empresa int as
Declare @Nit char(20), @Nombre char(100),@Direccion char(100),@num_casa char(5),@Tipo_retencion int,@concepto_isr char(2)
--si no existe el proveedor en el modulo de contabilidad lo crea antes de pasar las facturas al modulo de credito fiscal
if exists(select nit from tbl_proveedores where id_empresa=@Id_empresa and  
		nit not in (select nit from db_contabilidad_pfp.dbo.clientes_proveedores))
begin
	Declare proveedores_nuevos cursor for
	select nit,
		nombre,
		direccion,
		num_casa,
		(case when Retiene_isr='SI'
			Then 1
			Else 2 end),
		Id_Concepto_servicio
			 from tbl_proveedores where id_empresa=@Id_Empresa and  
		nit not in (select nit from db_contabilidad_pfp.dbo.clientes_proveedores)
	Open Proveedores_nuevos
	fetch proveedores_nuevos into 	@NIT,
					@Nombre,
					@Direccion,
					@Num_casa,
					@Tipo_retencion,
					@Concepto_isr
	while @@fetch_status=0
	begin
		insert db_contabilidad_pfp.dbo.clientes_proveedores(NIT,Nombre_Proveedor,calle_o_avenida,numero_casa,tipo_retencion,metodo)
		select @nit,@nombre,ltrim(rtrim(@Direccion)),@num_casa,@Tipo_retencion,@concepto_isr
		fetch proveedores_nuevos into 	@NIT,
						@Nombre,
						@Direccion,
						@Num_casa,
						@Tipo_retencion,
						@Concepto_isr
	end	

close proveedores_nuevos
deallocate proveedores_nuevos
	
end

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
-- =============================
-- SP: sp_crea_tipos_nuevos
-- =============================

--exec sp_crea_tipos_nuevos 1
CREATE procedure sp_crea_tipos_nuevos @Id_Empresa int as
--este procedimiento crea registros en la tabla tipos de documentos de los 
--movimientos captados en cxp. para generar el credito fiscal
Declare @tipo_cargo char(3)
if  exists(select distinct tipo_cargo from tbl_cargos
		 where 	id_empresa=@Id_Empresa	and
			tipo_cargo	not in (select TIPO FROM db_contabilidad_pfp.dbo.TIPOS_DOCUMENTOS WHERE ID_EMPRESA=@Id_empresa))
BEGIN
	Declare tipos_documentos cursor for
	select distinct tipo_cargo from tbl_cargos
		where id_empresa=@Id_empresa	and
			tipo_cargo	not in (select TIPO FROM db_contabilidad_pfp.dbo.TIPOS_DOCUMENTOS WHERE ID_EMPRESA=1)
	open tipos_documentos
	fetch tipos_documentos into @tipo_cargo
	while @@fetch_status=0
	begin
		insert db_contabilidad_pfp.dbo.tipos_documentos(Id_empresa,
								tipo,
								descripcion,
								correlativo,
								inicializacion,
								numero,
								modulo,
								tipo_operacion)
		select 	@Id_Empresa,
			@tipo_cargo,
			'DOCUMENTO CREADO EN CXP',
			2,
			3,--INICIALIZACIN
			0,
			'03',--MODULO
			1--TIPOOPERACION
		fetch tipos_documentos into @tipo_cargo		
	end
	close tipos_documentos
	deallocate tipos_documentos
END




GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: sp_creatediagram
-- =============================

	CREATE PROCEDURE dbo.sp_creatediagram
	(
		@diagramname 	sysname,
		@owner_id		int	= null, 	
		@version 		int,
		@definition 	varbinary(max)
	)
	WITH EXECUTE AS 'dbo'
	AS
	BEGIN
		set nocount on
	
		declare @theId int
		declare @retval int
		declare @IsDbo	int
		declare @userName sysname
		if(@version is null or @diagramname is null)
		begin
			RAISERROR (N'E_INVALIDARG', 16, 1);
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID(); 
		select @IsDbo = IS_MEMBER(N'db_owner');
		revert; 
		
		if @owner_id is null
		begin
			select @owner_id = @theId;
		end
		else
		begin
			if @theId <> @owner_id
			begin
				if @IsDbo = 0
				begin
					RAISERROR (N'E_INVALIDARG', 16, 1);
					return -1
				end
				select @theId = @owner_id
			end
		end
		-- next 2 line only for test, will be removed after define name unique
		if EXISTS(select diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @diagramname)
		begin
			RAISERROR ('The name is already used.', 16, 1);
			return -2
		end
	
		insert into dbo.sysdiagrams(name, principal_id , version, definition)
				VALUES(@diagramname, @theId, @version, @definition) ;
		
		select @retval = @@IDENTITY 
		return @retval
	END
	
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: sp_cubos
-- =============================
CREATE procedure sp_cubos  @Id_empresa int as


insert db_estadisticas_pfp.dbo.Tbl_ventas_producto_mes 
select	LTRIM(RTRIM(CAST(D.id_empresa as CHAR)))+' '+
(select nombre_empresa from db_inventario_pfp.dbo.empresas where id_empresa=@Id_empresa)   AS EMPRESA,
		d.id_producto,
		d.Id_Producto+ ''+LTRIM(RTRIM(	p.descripcion)) AS Producto,
		replicate('0',2- len ( ltrim(rtrim( cast( month( c.Fecha_Factura ) as CHAR))))) +
		LTRIM(RTRIM(cast( MONTH(c.fecha_factura) as char))) as mes,
		YEAR(  c.fecha_factura ) as anio,
		SUM(d.Cantidad) as unidades,
		SUM(d.precio_descuento*d.cantidad) as total_venta
		from Tbl_Cab_Facturacion c, Tbl_Det_Facturacion d, Tbl_Productos p
where	c.id_empresa	=@Id_empresa		and
		c.Id_Empresa	=	d.Id_Empresa	and
		c.Id_Caja		=d.Id_Caja			and
		c.Autorizacion	=d.autorizacion		and
		c.Serie			=d.Serie			and
		c.Id_Tipo		=d.Id_Tipo			and
		c.Numero		=d.Numero			and
		d.Id_Empresa	=p.Id_Empresa		and
		d.Id_Producto	=p.Id_Producto 
	--	datediff(day, c.Fecha_Factura ,	DATEADD(month,1,@fecha1)-1 ) 
	--	between 0 and  DATEDIFF(day,@fecha1,   DATEADD(month,1,@fecha1)-1 )
group by d.Id_Empresa,d.id_producto,p.descripcion,c.Fecha_Factura 
		

		

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
-- =============================
-- SP: sp_detalle_a_Facturar
-- =============================

--exec sp_detalle_a_Facturar 2,'1232628-3',74
--select *from tbl_orden_servicio_Detalle
---select *from tbl_orden_servicio_Detalle_integracion
CREATE procedure [dbo].[sp_detalle_a_Facturar] 	@Id_Empresa	int,
					@Nit		char(20),
					@Id_Orden	int as

-- Este procedimiento selecciona el detalle de productos que se jalaran en el formulario de facturacion y estam disponibles para facturar
--el primer selec son datos de ordenes de servicio de trabajo
--el segundo select son datos de ordenes de servicio de trabajo
--tercer select solicitud de despacho con ordenes de entrega
--cuarto select solicitud de despach sin ordenes de entrega				
select c.Id_Empresa,
	c.Id_Orden,
	c.Num_Placa,
	c.Tarjeta,
	c.Fecha,
 	d.Linea,
	d.Id_Servicio as id_producto,
	d.Descripcion,
	d.cantidad,
	d.Precio,
	(d.Cantidad*d.Precio) as Total_Linea,
	(d.Cantidad*d.precio_descuento) as Total_con_Descuento,
	d.precio_descuento, 
	(select id_bodega_facturacion from empresas where id_empresa=@Id_Empresa) as id_bodega,
	0 AS PORCENTAJE_DESCUENTO
	 from tbl_orden_servicio c	Left Join Tbl_Orden_Servicio_detalle d	on
						c.Id_Empresa	=d.Id_Empresa	and
						c.Id_Orden	=d.Id_Orden	
where 	c.Id_Empresa	=@Id_Empresa	and
	c.nit				=@Nit 		and
	c.Id_Orden			=@Id_orden	and
	c.status			=2			and
	c.Autorizacion		=''			and
	c.Serie				=''			and
	c.Tipo				=''			and
	c.Numero			=0
union all
select 	c.Id_Empresa,
	c.Id_Orden,
	c.Num_Placa,
	c.Tarjeta,
	c.Fecha,	
	d.linea,
	d.Id_Producto as id_producto,
	d.Descripcion,
	d.Cantidad,
	d.Precio,
	d.Total_Linea,
	(d.Cantidad*d.precio_descuento) as Total_con_Descuento,
	d.precio_descuento,
	d.Id_Bodega as id_bodega,
	0 AS PORCENTAJE_DESCUENTO
	from tbl_Orden_Servicio c	Left	Join tbl_orden_servicio_Detalle_integracion d
					on 	c.Id_Empresa	=d.Id_Empresa	and
						c.Id_Orden	=d.Id_orden	
					inner join Tbl_Productos p
					on	d.Id_Empresa	=p.Id_Empresa	and
						d.Id_Producto	=p.Id_Producto
where	c.Id_Empresa	=	@Id_Empresa	and
	c.Nit				=	@Nit		and
	c.Id_Orden			=	@Id_Orden	and
	c.Status			=	2		and
	d.Se_Cobra			=	'S'		and
	c.Autorizacion		=''			and
	c.Serie				=''			and
	c.Tipo				=''			and
	c.Numero			=0
union all  --solicitud de despahco
select	c.id_empresa,
		c.id_solicitud_despacho,
		'XXXXX' AS NUM_PLACA,
		K.Tarjeta ,
		s.Fecha_solicitud,
		1 as Linea ,
		D.Id_producto,
		' ' AS Descripcion,
		sum(d.Cantidad) as cantidad,
		sum(d.Cantidad *d.Precio)/SUM(d.Cantidad) as precio,
		sum(d.Cantidad *d.Precio)	as Total_Linea,
		sum(d.Cantidad *d.Precio)	as Total_con_Descuento,
		sum(d.Cantidad *d.Precio)/SUM(d.Cantidad)				as precio_descuento			,
		d.id_bodega_movimiento, 
		0 AS PORCENTAJE_DESCUENTO
from tbl_cab_entrega_despacho c,tbl_det_entrega_despacho d,Tbl_solicitud_despacho_cliente s, Tbl_Proveedores K
where	c.Id_empresa			=d.Id_empresa				and
		c.Numero				=d.Numero					and
		c.Id_empresa			=s.id_empresa				and
		c.Id_solicitud_despacho =s.Id_solicitud_despacho	and
		k.Id_Empresa			=s.Id_empresa				AND
		k.Nit					=s.Nit_cliente				and
		c.Id_empresa			=@Id_empresa				and
		c.Id_solicitud_despacho	=@Id_Orden  				and
		s.Serie					is null						and
		s.Id_tipo				is null						and
		s.Numero				is null						and
		s.ltiene_Orden_Entrega  =1
Group by c.Id_empresa,d.Id_bodega_movimiento,d.Id_producto,k.tarjeta,s.Fecha_solicitud,c.Id_solicitud_despacho  		
union all
select	s.id_empresa,
		s.id_solicitud_despacho,
		'XXXXX' AS NUM_PLACA,
		'' as Tarjeta,
		s.Fecha_Solicitud,
		1 as Linea,
		D.ID_PRODUCTO,
		' ' as Descripcion,
		Sum(D.cantidad) as cantidad,
		Sum(D.cantidad * d.Precio_vta) /Sum(d.cantidad) as precio,
		Sum(d.cantidad * d.Precio_vta) as Total_Linea,
		Sum(d.cantidad * d.Precio_vta) as Total_con_Descuento,
