CREATE procedure [dbo].[sp_detalle_a_Facturar] 	@Id_Empresa	int,
					@Id_mesa	int,
					@Id_comanda int as


				
select	c.Id_Empresa,
		d.id_producto,
		d.cantidad,
		d.precio,
		d.total,
		'01' as id_bodega
	--(select id_bodega_facturacion from empresas where id_empresa=@Id_Empresa) as id_bodega
	 from db_restaurante.dbo.Tbl_comanda c	Left Join db_restaurante.dbo.Tbl_comanda_detalle  d	on
						c.Id_Empresa	=d.Id_Empresa	and
						c.Id_comanda	=d.id_comanda   
where 	c.Id_Empresa	=@Id_Empresa	and
		c.id_mesa		=@Id_mesa		and
		c.id_comanda	=@Id_comanda 	
		

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
