create  procedure [dbo].[sp_existencia_por_producto] @Id_empresa int,@id_producto char(15),@periodo char(7) as
select existencia, minimo from db_inventario_pfp.dbo.tbl_productos p,
db_inventario_pfp.dbo.tbl_existencia e
where e.Id_Empresa=p.Id_Empresa and
