-- SP: sp_genera_ajustes_inv
-- =============================
--set dateformat dmy
--select *from tbl_inventario_fisico where id_transac=2
--select *from tbl_inventario_fisico_detalle where id_transac=2 order by id_producto
--delete from Tbl_cabecera_movimientos where id_empresa=2 and id_tipo='ini' and Periodo='06/2019' and numero=2
--select * from Tbl_cabecera_movimientos where id_empresa=2 and id_tipo='ini' and Periodo='06/2019'
--select *from Tbl_Detalle_movimientos where id_empresa=2 and id_tipo='ini' and Periodo='06/2019'
--select *from tbl_productos where id_producto='500'

---exec dbo.sp_genera_ajustes_inv 2,2

CREATE procedure [dbo].[sp_genera_ajustes_inv] @Id_empresa int,@Id_inventario int as

Declare @NUMERO NUMERIC(10),@periodo char(7),@Id_bodega char(2),@linea int,@diferencia numeric(12,2),@Id_producto char(15),@costo numeric(12,4)
select @periodo=periodo from empresas where id_empresa=@Id_empresa

if exists(select *from tbl_inventario_fisico c, tbl_inventario_fisico_detalle d
where c.id_empresa=d.id_empresa and
	c.id_inventario=d.id_inventario and
	c.Id_transac=@Id_inventario     and
	Existencia<>Existencia_fisica	and
	c.id_empresa=@Id_empresa		and
	c.id_transac=d.Id_transac		and
	c.Id_transac=@Id_inventario)
begin
	declare cabecera cursor for	
	select distinct id_bodega from 
	(
	select c.*, 
		d.id_producto,
		d.existencia,
		d.existencia_fisica
		from tbl_inventario_fisico c, tbl_inventario_fisico_detalle d
	where	c.id_empresa	=d.id_empresa		and
			c.id_inventario	=d.id_inventario	and
	Existencia<>Existencia_fisica	and
	c.id_empresa=@Id_empresa		and
	c.id_transac= d.Id_transac      and
	c.Id_transac=@Id_inventario) j

	open cabecera
	fetch cabecera into @Id_bodega
	while @@fetch_status=0
	begin

		SELECT @NUMERO=isnull(MAX(NUMERO),0)+1 FROM TBL_CABECERA_MOVIMIENTOS 
		WHERE ID_EMPRESA=@iD_EMPRESA AND PERIODO=@PERIODO AND ID_TIPO='INI'
		
--insertando la cabeceara de movimientos de ajuste positivo
		insert tbl_cabecera_movimientos
		select 
		@Id_empresa,
		@Periodo,
		@Id_bodega,
		'INI',
		@NUMERO,
		GETDATE(),
		'Ajuste Positivo, Electronico',
		0,
		'XXXXXXXXXXXXXXXXXXXX',
		@Id_bodega,
		'',
		0,
		suser_sname(),
		getdate(),
		' ',
		2,
		getdate(),
		1,
		0,
		0,
		'' as serie

		SET @LINEA=0		
		declare detalle_ajustes cursor for
		select d.Id_producto,sum(existencia_fisica-existencia) as diferencia 
		from tbl_inventario_fisico c,tbl_inventario_fisico_detalle d
		where	c.id_empresa	=d.id_empresa		and
				c.Id_inventario	=d.id_inventario	and
				c.Id_transac    =d.id_transac       and
				c.Id_transac	=@Id_inventario
		group by d.id_producto
		open detalle_ajustes
		fetch detalle_ajustes into @Id_producto,@diferencia
		while @@fetch_status=0
		begin
			print @id_producto
			print @diferencia
			print @costo
			SET @LINEA=@LINEA+1
			
			select @costo=costo_promedio from tbl_productos where id_empresa=@Id_empresa and id_producto=@Id_producto
			print @costo
			If @diferencia<>0
				insert tbl_detalle_movimientos
				select @diferencia,
				0,
				@costo,
				@id_empresa,
				@periodo,
				@Id_bodega,
				'INI',
				@NUMERO,
				'XXXXXXXXXXXXXXXXXXXX',
				@LINEA,
				@Id_producto,
				round(@diferencia*@costo,2),
				suser_sname(),
				getdate(),
				0,
				@Id_bodega,
				0 as cantidad_novalid,
				0 as validado
				
			

		fetch detalle_ajustes into @Id_producto,@diferencia
		end
		close detalle_ajustes
		deallocate detalle_ajustes

	fetch cabecera into @Id_bodega
	end
	close cabecera
	deallocate cabecera

	
end



GO
                                                                                                                                                                                                                                                                                                                                       
