-- este procedimiento genera compra desde las importaciones
CREATE  procedure [dbo].[sp_genera_compra] @Id_empresa int, @Id_importacion int,@Fecha_inv datetime as
Begin
Begin Transaction T1
Declare @nit			char(20),
		@fecha_pedido	datetime,
		@cantidad		int,
		@CANTIDADMP		INT,
		@total_compra	numeric(12,2),
		@Id_bodega		char(2),
		@Periodo_inv	char(7),
		@Precio			numeric(12,2),
		@Id_producto	char(15),
		@Id_sproducto   char(15),
		@Numero_compra	numeric(10),
		@Linea			int,
		@Porcentaje     numeric(12,2),
		@Credito_o_contado int

select @Numero_compra=numero from tbl_importacion where id_empresa=@Id_empresa and id_pedido=@Id_importacion
Select @Id_bodega=Id_bodega_facturacion from empresas where id_empresa=@Id_empresa
Select @Periodo_inv=periodo from empresas where id_empresa=@Id_empresa
set @linea=0


--insertando cabecera de movimientos
insert tbl_cabecera_movimientos
select @Id_empresa,
		@Periodo_inv,
		@Id_bodega,
		'IMP',
		@Numero_compra,
		@Fecha_inv ,
		'Importaciòn al proveedor '+ltrim(rtrim(i.nit))+ 
		ISNULL((select nombre from tbl_proveedores where id_empresa=@id_empresa and nit=@nit),'')+
		'Segùn poliza de importaciòn '+isnull(i.poliza_importacion,''),
		1,
		nit,
		@Id_bodega,
		'',   --referencia
		1,   --impreso
		suser_sname(),
		getdate(),
		'',
		credito_o_contado,
		getdate(),
		2,--estatus del pedido
		0,
		1,
		'' AS SERIE from tbl_importacion i
		where i.Id_empresa	=@Id_empresa		and
				i.Id_pedido		=@Id_importacion

If @@error<>0
begin
rollback transaction t1
return
end

select @Id_bodega=Id_bodega_facturacion from empresas where Id_empresa=@Id_empresa

If @@error<>0
begin
rollback transaction t1
return
end

select	@Nit=nit from tbl_importacion 
		where	id_empresa=@Id_empresa and
				 Id_pedido=@Id_importacion
If @@error<>0
begin
rollback transaction t1
return
end



Declare detalle_importacion cursor for
select	i.nit,
		i.fecha_pedido,
		p.Id_producto,
		d.cantidad_recibida,
		Round((d.total_importacion+d.flete_dolares+d.valor_soporte)*i.tasa_cambio,2)+d.Gastos_locales+d.Impuesto_importacion
		from tbl_importacion i,tbl_detalle_importacion d,  tbl_prod_proveedores p
where	i.Id_empresa	=d.id_empresa		and
		i.Id_pedido		=d.id_pedido		and
		d.Id_Empresa	=p.id_empresa		and
		d.Id_sproducto	=p.Id_alterno		and	
		i.Id_empresa	=@Id_empresa		and
		i.Id_pedido		=@Id_importacion
Open detalle_importacion
Fetch detalle_importacion into	@nit,
								@fecha_pedido,
								@Id_producto,
								@cantidad,
								@total_compra
While @@fetch_status=0
begin
	/* Si el producto que se importa es producto terminado entra en el siguiente if*/
	if (select tipo from tbl_productos where id_empresa=@Id_empresa and id_producto=@Id_producto )='TERMINADO'
	begin

			declare subproductos cursor for
			select	sub.id_Sproducto,
					sub.cantidad,
					sub.porcentaje/100 from tbl_productos PROD INNER JOIN TBL_SPRODUCTOS SUB ON
			PROD.ID_EMPRESA		=SUB.ID_EMPRESA	AND
			PROD.ID_PRODUCTO	=SUB.ID_PRODUCTO				AND
			SUB.ID_PRODUCTO		=@Id_producto
	
			open subproductos
			fetch subproductos into @Id_Sproducto,@CantidadMP,@Porcentaje
			while @@fetch_status=0
			begin
			set @linea=@linea+1 
			print 'producto'+@id_producto
			
			print 'subproducto'
			print @Id_sproducto
			print @cantidad
			print @cantidadmp
			print @Id_sproducto
			Insert tbl_detalle_movimientos(Cantidad,
											Precio,
											costo,
											Id_empresa,
											Periodo,
											Id_bodega,
											Id_tipo,
											Numero,
											Nit,
											Linea,
											Id_producto,
											total,
											precio_compra,
									
-- =============================
-- SP: sp_genera_detalle_compra
-- =============================





--SET DATEFORMAT DMY
--EXEC SP_GENERA_DETALLE_COMPRA 1,' 32573-2','G',1248621,'25/09/2008',2

CREATE  procedure [dbo].[sp_genera_detalle_compra] @Id_empresa int,@nit char(20),@Serie char(10),@numero numeric(10),@fecha_Factura datetime,@credito_o_Contado int as
--este proceso genera el movimiento compra originado en las ordenes de compra
--insertando en la cabecera de m ovimientos la compra
DECLARE @DESCRIPCION VARCHAR(100)
SET @DESCRIPCION ='Segun detalle de ordenes de compra'
declare @id_recepcion int,@Id_pedido int,@total_recepcion numeric(12,2),@Id_bodega char(10),@periodo char(7)
--begin transaction t1

if exists(
select	d.periodo,
		p.nit,
		r.Id_recepcion,
		r.Id_pedido,
		d.id_bodega,
		sum(d.cantidad_por_recibir*d.precio_compra) as total
		from tbl_recepcion_pedidos r, tbl_recepcion_pedidos_Detalle d, tbl_pedidos p
where		r.id_empresa	=d.id_empresa	and
			r.id_recepcion	=d.id_recepcion	and
			p.id_empresa	=r.id_empresa	and
			p.id_pedido		=r.id_pedido	and
			r.recepcion_aplicada=0			AND
			r.status		=2				and
			r.id_empresa	=@Id_empresa	and
			(CASE WHEN p.FORMA_PAGO='CONTADO' THEN 2 ELSE 1 END)=@Credito_o_contado and
			ltrim(rtrim(cast(r.id_empresa as char)))+
			ltrim(rtrim(d.periodo))+
			ltrim(rtrim(d.id_bodega))+
			'COM'+
			ltrim(rtrim(cast(@numero as char)))+
			ltrim(rtrim(p.nit))+
			LTRIM(RTRIM(CAST(D.ID_PEDIDO AS CHAR)))+
			LTRIM(RTRIM(CAST( D.ID_RECEPCION  AS CHAR)))
			not in
			(select	ltrim(rtrim(cast(r.id_empresa as char)))+
					ltrim(rtrim(periodo))+
					ltrim(rtrim(Id_bodega))+
					ltrim(rtrim(Id_tipo))+
					ltrim(rtrim(cast(numero as char)))+
					ltrim(Rtrim(nit))+
					ltrim(rtrim(cast(r.Id_pedido as char)))+
					ltrim(rtrim(cast(r.Id_recepcion as char)))
					 from dbo.tbl_detalle_compras
			where	Id_empresa=@Id_empresa	)
group by d.periodo,P.NIT,r.Id_recepcion,r.id_pedido,r.numero,d.id_bodega

)

begin

insert dbo.tbl_cabecera_movimientos
select	@Id_empresa,
		(select periodo from empresas where id_empresa=@Id_empresa) as periodo,
		(select top 1 id_bodega from tbl_bodega where id_empresa=@Id_empresa),
		'COM',	
		@Numero,
		@Fecha_factura,
		@Descripcion,
		0, --indica que no est trasladado a cxp
		@nit,
		(select top 1 id_bodega from tbl_bodega where id_empresa=@Id_empresa),
		'', --referencia
		1,-- impreso		
		suser_sname(),
		getdate(),
		'',
		@credito_o_contado,
		getdate(),
		2, --status
		0,
		1
if @@error<>0
	BEGIN
	rollback transaction t1	
	return
END
-- insertando al detalle de compras las recepciones de las ordenes que no tiene factura asignada
-- el campo que determina es recepcion_aplicada=0

--declare @periodo char(7)
declare detalle_compra cursor for
select	d.periodo,
		p.nit,
		r.Id_recepcion,
		r.Id_pedido,
		d.id_bodega,
		sum(d.cantidad_por_recibir*d.precio_compra) as total
		from tbl_recepcion_pedidos r, tbl_recepcion_pedidos_Detalle d, tbl_pedidos p
where		r.id_empresa	=d.id_empresa	and
			r.id_recepcion	=d.id_recepcion	and
			p.id_empresa	=r.id_empresa	and
			p.id_pedido		=r.id_pedido	and
			r.recepcion_aplicada=0			AND
			r.status		=2				and
			r.id_empresa	=@Id_empresa	and
			(CASE WHEN p.FORMA_PAGO='CONTADO' THEN 2 ELSE 1 END)=@Credito_o_contado and
			ltrim(rtrim(cast(r.id_empresa as char)))+
			ltrim(rtrim(d.periodo))+
			ltrim(rtrim(d.id_bodega))+
			'COM'+
			ltrim(rtrim(cast(@numero as char)))+
			ltrim(rtrim(p.nit))+
			LTRIM(RTRIM(CAST(D.ID_PEDIDO AS CHAR)))+
			LTRIM(RTRIM(CAST( D.ID_RECEPCION  AS CHAR)))
			not in
			(select	ltrim(rtrim(cast(r.id_empresa as char)))+
					ltrim(rtrim(periodo))+
					ltrim(rtrim(Id_bodega))+
					ltrim(rtrim(Id_tipo))+
					ltrim(rtrim(cast(numero as char)))+
					ltrim(Rtrim(nit))+
					ltrim(rtrim(cast(r.Id_pedido as char)))+
					ltrim(rtrim(cast(r.Id_recepcion as char)))
					 from dbo.tbl_detal
