close clientes
deallocate clientes
*/
--SET DATEFORMAT DMY
--SELECT *FROM Tbl_cuentas_por_cobrar WHERE numero=6491
--exec sp_genera_factura_automatica 2,'01/03/2013','POR SERVICIO DE SEGURIDAD EN SUS INSTALACIONES, CORRESPONDIENTE AL MES FEBRERO/2013',10100

CREATE procedure [dbo].[sp_genera_factura_automatica] @Id_empresa int,@Fecha_factura datetime,@Descripcion_factura varchar(200) ,@siguiente_factura numeric(10) as
set dateformat dmy
Declare @NIT CHAR(20),
		@SERIE CHAR (3),
		@NOMBRE CHAR(100),
		@VALOR_FACTURA NUMERIC(12,2),
		@VALOR_BASE    NUMERIC(12,2),
		@IVA NUMERIC (12,2),
		@ID_GRUPO_CLIENTE CHAR(10) ,
		@Id_ente_facturador int ,
		@Regimen_Fiscal_ISR varchar(15),
		@Valor_Retencion_ISR NUMERIC(12,2)

declare   @valor_retencion_iva  numeric(12,2)

--SET @FECHA_FACTURA ='04/11/2012'
--SET @SIGUIENTE_FACTURA = 100
---SET @Descripcion_factura = 'Servicio de Vigilancia, correspondiente al mes de noviemre'

select @Regimen_fiscal_isr=Regimen_fiscal_isr 
from empresas where id_empresa=@Id_empresa


SELECT @SERIE= SERIE FROM Tbl_Series 
WHERE Id_Empresa=@Id_empresa AND Id_Tipo='FAC'

DECLARE CLIENTES CURSOR FOR
select	P.Nit,
Prov.Nombre,
		P.id_ente_facturador,
		
		ISNULL((select SUM(total) from Tbl_Cliente_plantilla 
		where Id_empresa=@Id_empresa AND Nit=P.NIT and id_ente_facturador=p.id_ente_facturador ),0) AS VALORFACTURA
		 from dbo.Tbl_Cliente_plantilla p inner join Tbl_Proveedores prov 
												on p.Id_empresa=prov.Id_Empresa and
													p.Nit=prov.Nit 
where P.Id_Empresa=@Id_empresa 
group by p.nit, prov.Nombre , p.Id_ente_facturador 


begin transaction t1



OPEN CLIENTES
FETCH CLIENTES INTO @NIT,@NOMBRE,@Id_ente_facturador,@valor_factura
while @@FETCH_STATUS =0
begin
	Set @Valor_Retencion_ISR=0



	
	
	SELECT  @IVA= ( @valor_factura- ROUND( @valor_factura/1.12,2))
	SET @Valor_Base=@valor_factura-@iva 

	IF @Regimen_Fiscal_ISR ='PAGO MENSUAL'
	BEGIN
		SET @Valor_Retencion_ISR= dbo.calcula_isr_cxc(@Id_empresa,@valor_factura,'FAC',getdate())
		
	END

	
	set @valor_retencion_iva  =0
			select	@Id_grupo_cliente=p.id_grupo_cliente,
					@valor_retencion_iva =(isnull(Porcentaje_retencion,0) * @IVA)/100  from Tbl_Proveedores p, 
			Tbl_configuracion_agente_retenedor_iva c
			where	p.Id_Empresa=c.Id_empresa and
					p.Tipo_agente_retenedor_iva =c.Id_agente_retencion_iva  and
					p.Id_Empresa=@Id_empresa  and Nit=@NIT 
					
		
		
	IF @VALOR_FACTURA >0
	BEGIN	
		insert dbo.Tbl_cuentas_por_cobrar 
		select	@Id_empresa AS EMPRESA,
				@Nit AS NIT,
				@Serie AS SERIE,
				'FAC' AS TIPO_DOCTO,
				@SIGUIENTE_FACTURA AS NUMERO_DOCTO,
				@Descripcion_factura AS DESCRIPCION,
				@Fecha_factura AS FECHA_DOCTO,
				@valor_factura AS VALOR_DOCTO,
				@valor_factura - @valor_retencion_iva - @valor_retencion_isr AS SALDO_DOCTO,
				@fecha_factura AS FECHA_TENTATIVA_COBRO,
				GETDATE() AS FECHA_OPERACION,
				USER_NAME() AS USUARIO,
				2 AS CONTABILIZADO, --CONTABBILOZADO
				7 AS SISTEMA, --sistema
				@IVA  AS IVA,
				1 AS STATUS,
				2 AS PROVISIONADO,  --PROVISIONADO 
				'' AS ANIO,
				'' AS MES,
				''  AS ID_BANCO,
				'' AS TIPO,
				'' AS NUMERO,
				@Id_ente_facturador  AS ID_ENTE_FACTURADOR,
				@valor_retencion_iva  ,  --RETENCION IVA
				(select Id_grupo_cliente from Tbl_Proveedores 
				where Id_Empresa=@Id_empresa and nit=@NIT),
				@Valor_Retencion_ISR as Retencion_ISR
	
		if @@ERROR <>0 
		begin
			rollback transaction t1 
			return 
		end		
			
		Insert db_inventario_pfp.dbo.Tbl_cuentas_por_cobrar_integracion_plantilla
		select @Id_empresa,
				@NIT,
				@SERIE,
				'FAC'
