--exec sp_genera_oc 3,48

CREATE procedure [dbo].[sp_genera_oc]  @Id_empresa		int,@Id_solicitud_despacho int as
--Este procedimiento genera orden de compra
declare @nit_proveedor char(20),@nit_cliente char(20),@direccion_factura varchar (80),@direccion_entrega varchar(80),@Id_alterno char(20),@cantidad_solicitada numeric(12,2),@precio_compra numeric(12,2)
declare @id_tipo_ocompra char(1),@Id_pedido int,@costo_promedio numeric(12,5),@Id_producto char(20)


begin transaction t1
Declare cabecera cursor for
select	distinct 
		d.nit,
		c.Nit_cliente  from Tbl_solicitud_despacho_cliente  c,tbl_solicitud_Despacho_cliente_detalle d
where	c.Id_empresa			=d.Id_empresa				and
		c.Id_solicitud_despacho =d.Id_solicitud_despacho	and
		c.Id_solicitud_despacho	=@Id_solicitud_despacho		and
		d.Cantidad >d.Cantidad_entregada					and
		c.Status_solicitud NOT IN ('ENTREGADA','RECHAZADA') and
		d.nit<>'XXXXXXXXXXXXXXXXXXXX'
open cabecera
fetch cabecera into @nit_proveedor,@nit_cliente		
while @@FETCH_STATUS =0
begin
	select top 1 @id_tipo_ocompra=id_tipo_ocompra from Tbl_tipo_ocompra where id_empresa=@id_empresa 
	select @Id_pedido=max(isnull(id_pedido,0))+1 from db_inventario_pfp.dbo.Tbl_pedidos where Id_Empresa=@id_empresa 
 
	if @@ERROR<>0
	begin
		rollback transaction t1
		return
	end

	select	@direccion_factura=Direccion_factura,
			@direccion_entrega=direccion_entrega
			from Tbl_solicitud_despacho_cliente
			 where id_empresa=@id_empresa and Id_solicitud_despacho =@id_solicitud_despacho
--  INSERTANDO LA CABECERA DE PEDIDOS			 
	INSERT dbo.Tbl_pedidos 
	SELECT	ID_EMPRESA,
			@Id_pedido,
			@nit_proveedor,
			GETDATE(),
			SUSER_NAME(),
			getdate(),
			0,
			@nit_cliente ,
			@direccion_factura,
			@direccion_entrega,
			'recibe orden',
			'numplac',
			'observaciones',
			@id_tipo_ocompra,
			'CONTADO',
			0,
			'' FROM Tbl_solicitud_despacho_cliente 
	where Id_empresa=@Id_empresa and Id_solicitud_despacho=@Id_solicitud_despacho 					
	if @@ERROR<>0
	begin
		rollback transaction t1
		return
	end
		
--   INSERTANDO EL DETALLE DE PEDIDOS
		declare detalle_despacho cursor for
		select	S.Id_producto,
				s.cantidad-s.cantidad_entregada from Tbl_solicitud_despacho_cliente  c,tbl_solicitud_Despacho_cliente_detalle s
		where c.Id_empresa		=s.Id_empresa					and
		c.Id_solicitud_despacho =s.Id_solicitud_despacho		and
		s.Cantidad				>s.Cantidad_entregada			and
		c.Status_solicitud NOT IN ('ENTREGADA','RECHAZADA')		and
		s.Nit<>'XXXXXXXXXXXXXXXXXXXX'							and
		s.nit					=@nit_proveedor					and
		c.Nit_cliente			=@nit_cliente 
		
		open detalle_despacho
		fetch detalle_despacho into @Id_producto,@cantidad_solicitada
		while @@FETCH_STATUS =0
		begin 
		
			SELECT	@Id_alterno		=Id_Alterno,
					@Precio_compra	=Precio FROM Tbl_Prod_Proveedores WHERE Id_Empresa=@Id_empresa AND Id_Producto=@ID_PRODUCTO AND  Nit=@Nit_proveedor
			select @Costo_promedio=Costo_Promedio from tbl_productos where Id_Empresa=@Id_empresa and Id_Producto=@Id_producto
		
			INSERT dbo.Tbl_detalle_pedidos 
			select @Id_empresa,@Id_pedido,@Id_alterno,@cantidad_solicitada,@precio_compra,0,0,(@cantidad_solicitada*@precio_compra),0,suser_sname(),GETDATE(),0
			
			if @@ERROR<>0
			begin
				rollback transaction t1
				return
			end

			update tbl_solicitud_Despacho_cliente_detalle set Id_pedido=@Id_pedido where Id_empresa=@Id_empresa and Id_solicitud_despacho =@Id_solicitud_despacho And Id_producto=@Id_producto 
			
			If @@ERROR <>0
			begin
				rollback transaction t1
				return
			end
			
			fetch detalle_despacho into @Id_producto,@cantidad_solicitada
		end
		close detalle_despacho
		deallocate detalle_Despacho	
fetch cabecera into @nit_proveedor,@nit_cliente		
end
close cabecera
deallocate cabecera



if @@
