CREATE procedure [dbo].[sp_genera_orden_servicio] 	@Id_empresa 		int,
					  	@Id_Presupuesto 	int ,
						@Id_orden		int	as

 
declare @Linea			int,
	@Id_servicio		char(15),
	@Descripcion		char(100),
	@Id_empleado		char(4),
	@fosa			char(3),
	@precio			numeric(18,2),
	@otros			numeric(18,2),
	@total_linea		numeric(18,2),
	@cantidad		numeric(18,2),
	@Precio_descuento	numeric(18,2),
	@Total_Linea_descuento	numeric(18,2),
	@otros_descuento	 numeric(18,2),
	@costo			numeric(18,5),
	@valor_comision		numeric(12,2),	
	@Porcentaje_comision	numeric(12,2),
	@Linea_det		int,
	@Id_producto		char(15),
	@Id_bodega		char(2),
	@Se_cobra		char(1),
	@Rebaja_existencias	int,
	@periodo		char(7)
	

	
begin transaction t1



insert db_inventario_pfp.dbo.tbl_orden_servicio
select Id_empresa,@Id_orden,Num_Placa,Facturar_a,
observaciones,Recibe_orden,Encargado,tarjeta,fecha,status,nit,lectura_actual,Proximo_servicio,null,null,0,'','','',0
From tbl_presupuesto_orden_servicio
where Id_empresa=@Id_empresa and Id_orden=@Id_presupuesto
if @@error<>0
begin
	rollback transaction t1
	return
end


Declare servicios cursor for
select 	Linea,
	Id_servicio,
	Descripcion,
	Id_Empleado,
	Fosa,
	Precio,
	otros,
	Total_linea,
	cantidad,
	precio_descuento,
	total_linea_descuento,
	otros_descuento,
	costo,
	valor_comision,
	porcentaje_comision
From tbl_presupuesto_orden_servicio_detalle
where Id_empresa=@Id_empresa and Id_orden=@Id_presupuesto and autorizado=1
open servicios
fetch servicios into 	@Linea,
			@Id_servicio,
			@Descripcion,
			@Id_Empleado,
			@Fosa,
			@Precio,
			@otros,
			@Total_linea,
			@cantidad,
			@precio_descuento,
			@total_linea_descuento,
			@otros_descuento,
			@costo,
			@valor_comision,
			@porcentaje_comision
while @@fetch_status=0
begin
	insert tbl_orden_servicio_detalle
	select @Id_empresa,
		@Id_orden,
		@Linea,
		@Id_servicio,
		@Descripcion,
		@Id_Empleado,
		@Fosa,
		@Precio,
		@otros,
		@Total_linea,
		@cantidad,
		@precio_descuento,
		@total_linea_descuento,
		@otros_descuento,
		@costo,
		@valor_comision,
		@porcentaje_comision
	if @@error<>0
	begin
		rollback transaction t1
		return
	end
fetch servicios into 	@Linea,
			@Id_servicio,
			@Descripcion,
			@Id_Empleado,
			@Fosa,
			@Precio,
			@otros,
			@Total_linea,
			@cantidad,
			@precio_descuento,
			@total_linea_descuento,
			@otros_descuento,
			@costo,
			@valor_comision,
			@porcentaje_comision
end
close servicios
deallocate servicios



declare insumos cursor for
select 	Linea,
	Linea_det,
	Id_producto,
	Descripcion,
	Cantidad,
	Precio,
	Id_bodega,
	Se_cobra,
	Total_Linea,
	Precio_descuento,
	Total_linea_descuento,
	Rebaja_existencias,
	Costo,
	Periodo 
	from tbl_presupuesto_orden_servicio_detalle_integracion
	where Id_empresa=@Id_empresa and Id_orden=@Id_presupuesto and autorizado=1	
open insumos
fetch insumos into 	@Linea,
			@Linea_det,
			@Id_producto,
			@Descripcion,
			@Cantidad,
			@Precio,
			@Id_bodega,
			@Se_cobra,
			@Total_Linea,
			@Precio_descuento,
			@Total_linea_descuento,
			@Rebaja_existencias,
			@Costo,
			@Periodo 
while @@fetch_status=0
begin
	insert tbl_orden_servicio_detalle_integracion
	select @Id_empresa,
		@Id_orden,
		@Linea,
		@Linea_det,
		@Id_producto,
		@Descripcion,
		@Cantidad,
		@Precio,
		@Id_bodega,
		@Se_cobra,
		@Total_Linea,
		@Precio_descuento,
		@Total_linea_descuento,
		@Rebaja_existencias,
		@Costo,
		@Periodo,
		getdate()

	if @@error<>0
	begin
		rollback transaction t1
		return
	end
fetch insumos into 	@Linea,
			@Linea_det,
			@Id_producto,
			@Descripcion,
			@Cantidad,
			@Precio,
			@Id_bodega,
			@Se_cobra,
			@Total_Linea,
			@Precio_descuento,
			@Total_linea_descuento,
			@Rebaja_ex
