		@id_sproducto char(15),
		@id_tipo		char(3)
		set dateformat dmy
SET @ID_TIPO='PTE'
IF NOT EXISTS( SELECT *FROM Tbl_Tipos_Inv where ID_EMPRESA=@ID_EMPRESA AND Id_Tipo='PTE')
BEGIN
	print 'Debe crear tipo de documento de producto terminado PTE'
	
