		@cantidad numeric(12),
		@SIGUIENTE_DOCTO INT,
		@COSTO_PROMEDIO_PRODUCTO_TERMINADO NUMERIC(12,5)
set @cantidad_producida =0		


begin transaction t1
DECLARE MOVIMIENTOS CURSOR FOR
select ID_PRODUCTO,
CANTIDAD_PRODUCIDA
  from Tbl_produccion_diaria 
where Id_Empresa=@ID_EMPRESA and Id_Orden_produccion =@id_orden_produccion and
