if @@ERROR <>0
begin
	rollback transaction t1
	return
end


OPEN MOVIMIENTOS
FETCH MOVIMIENTOS INTO @ID_PRODUCTO,@CANTIDAD_PRODUCIDA
WHILE @@FETCH_STATUS =0
BEGIN
	PRINT 'PRODUCTO TERMINADO'
	PRINT @ID_PRODUCTO
	PRINT 'CANTIDAD PRODUCIDA'
	PRINT @CANTIDAD_PRODUCIDA
	select @SIGUIENTE_DOCTO=SIGUIENTE_DOCTO
	 from Tbl_Tipos_Inv where id_empresa=@id_empresa  and Id_Tipo=@ID_TIPO 

	INSERT Tbl_cabecera_movimientos 
	SELECT	@id_empresa,
			(SELECT Periodo FROM empresas WHERE Id_Empresa=@id_empresa ) AS PERIODO,
			@Id_bodega AS BODEGA,
			@Id_tipo AS TIPO,
			@SIGUIENTE_DOCTO ,
			@fecha_produccion AS FECHA,
			'Producción del dia ',
			0 as flag,
			'XXXXXXXXXXXXXXXXXXXX' AS NIT,
