						SUSER_SNAME(),
						GETDATE() AS FECHA_HORA,
						0 AS PRECIO_COMPRA,
						@Id_bodega */
				SET @LINEA=@LINEA +1
				INSERT Tbl_Detalle_movimientos 
				SELECT	@cantidad_producida ,
						0 AS PRECIO,
						@COSTO_PROMEDIO_PRODUCTO_TERMINADO ,
												
						@id_empresa ,
						(SELECT Periodo FROM empresas WHERE Id_Empresa=@id_empresa ) AS PERIODO,
						@Id_bodega ,
						@Id_tipo ,
						@SIGUIENTE_DOCTO ,						
						'XXXXXXXXXXXXXXXXXXXX' ,
						@LINEA,
						@id_producto ,
						@COSTO_PROMEDIO_PRODUCTO_TERMINADO * @can
