--procedimiento para generar cheques desde el modulo de cuentas por pagar
CREATE procedure [dbo].[sp_generacion_cheques_cxp] @Id_Empresa int ,@Id_banco char(2),@Fecha_movimiento datetime as
--selecciona el siguiente número de cheque que toca de un determinado banco
--selecciona el mes y año fiscal a trasladar
