CREATE procedure [dbo].[sp_generacion_cheques_cxp_agrupados] @Id_Empresa int ,@Id_banco char(2),@Fecha_movimiento datetime as

Declare @Nit char(20),@Serie char(15),@tipo_cargo char(3),@Numero_Factura numeric(15),@valor_aplicado numeric(12,2),@numero_cheque char(8),@descripcion char(500),@beneficiario char(100),@periodo_fiscal char(4),@mes_fiscal char(2),@valor_aplicado_detalle	numeric(12,2)
Declare @Id_Cuenta_Por_Pagar 	char(10),
		@Descripcion_detalle	char(500)

select 	@Numero_cheque=Sig_cheque from db_bancos_pfp.dbo.tbl_bancos
where Id_Empresa=@Id_Empresa and id_Banco=@Id_Banco

select 	@mes_fiscal	=ltrim(rtrim(cast(mes_proceso as char))),
	@periodo_fiscal	=ltrim(rtrim(cast(anio_proceso as char)))from db_bancos_pfp.dbo.tbl_empresas
where id_empresa=@Id_empresa

select @Id_Cuenta_Por_Pagar=Id_Cuenta_Cxp from empresas where id_empresa=@Id_Empresa

set @mes_fiscal=replicate('0',2-len(@mes_fiscal))+@mes_fiscal

begin transaction t1
Declare pagos cursor for
select 	d.Nit,
	Sum(d.Valor_Aplicado) as valor_Aplicado from db_inventario_pfp.dbo.tbl_det_abonos d inner join tbl_proveedores p
									on 	d.Id_Empresa	=p.Id_Empresa	and
										d.nit		=p.nit
where 	d.Id_Empresa	=@Id_Empresa	and
		d.Anio		=''	and
		d.Mes		=''	and
		d.Id_Banco	=''	and
		d.Tipo		=''	and
		d.Numero		=''	and
		d.Valor_Aplicado	<>0
Group by d.Nit
Open Pagos
Fetch Pagos into @nit,@Valor_Aplicado
while @@fetch_status=0
begin
print 'entro'
print @numero_cheque
	select @Id_Cuenta_Por_Pagar=Id_cuenta_cxp from tbl_proveedores where id_empresa=@Id_empresa 	and nit=@nit	

	if not exists(select *from db_bancos_pfp.dbo.tbl_mov_bancos where Id_Empresa=@Id_empresa and id_Banco=@Id_Banco and Id_Tipo='CHE' and numero=@Numero_cheque)
	begin

