		select Tipo_Cargo+'-'+rtrim(ltrim(serie))+'-'+ltrim(rtrim(cast(Numero_factura as char))) from db_inventario_pfp.dbo.tbl_det_abonos
		where Id_Empresa=@Id_Empresa	and Nit=@nit and Anio='' and Mes='' and Id_Banco='' and Tipo='' and Valor_Aplicado<>0
		order by tipo_cargo,numero_factura
		Open armadetalle
		fetch armadetalle into @Descripcion_detalle
		While @@Fetch_status=0
