			set @Descripcion=ltrim(rtrim( @Descripcion))+Ltrim(rtrim(@Descripcion_detalle))+' '
			fetch armadetalle into @Descripcion_detalle
		end
		close armadetalle
		deallocate armadetalle
		insert db_bancos_pfp.dbo.tbl_mov_bancos
		select @Id_Empresa,
		@Id_Banco,
		'CHE',
		@Numero_cheque,
