--exec sp_generacion_cheques_cxp_anticipos 1,'80','01/01/2006'
--procedimiento para generar cheques desde el modulo de cuentas por pagar por concepto de anticipos
CREATE procedure [dbo].[sp_generacion_cheques_cxp_anticipos] @Id_Empresa int ,@Id_banco char(2),@Fecha_movimiento datetime as
--selecciona el siguiente número de cheque que toca de un determinado banco
--selecciona el mes y año fiscal a trasladar
--selecciona la cuenta de anticipos
--insta el cheque en el modulo de bancos
--rebaja el saldo del banco
--actualiza los registros de la tbl_det_abonos asignandole el numero de cheque correspondiente
Declare @Nit char(20),@tipo_cargo char(3),@Numero_anticipo numeric(9),@valor_aplicado numeric(12,2),@numero_cheque char(8),@descripcion char(200),@beneficiario char(100),@periodo_fiscal char(4),@mes_fiscal char(2)
Declare @Id_Cuenta_anticipo_proveedores char(10)

select 	@Numero_cheque=Sig_cheque from db_bancos_pfp.dbo.tbl_bancos
where Id_Empresa=@Id_Empresa and id_Banco=@Id_Banco

select 	@mes_fiscal	=ltrim(rtrim(cast(mes_proceso as char))),
	@periodo_fiscal	=ltrim(rtrim(cast(anio_proceso as char)))from db_bancos_pfp.dbo.tbl_empresas
where id_empresa=@Id_empresa

select @Id_Cuenta_anticipo_proveedores=Id_Cuenta_anticipo_proveedores from empresas where id_empresa=@Id_Empresa

set @mes_fiscal=replicate('0',2-len(@mes_fiscal))+@mes_fiscal
--seleccionando todos las facturas aplicadas

select *from  db_inventario_pfp.dbo.tbl_abonos d 
begin transaction t1
Declare pagos cursor for--SELECCIONANDO LOS ANTICIPOS QUE ESTAN PENDIENTES DE GENERAR CHEQUE
select 	d.Nit,
	d.Id_Tipo_Pago,
	d.Numero_Pago,
	d.Total_abono from db_inventario_pfp.dbo.tbl_abonos d inner join tbl_proveedores p
									on 	d.Id_Empresa	=p.Id_Empresa	and
										d.nit		=p.nit
where 	d.Id_Empresa	=@Id_Empresa	and
	d.Id_Banco	='XX'		and
	d.Id_Tipo	='XXX'		and
	d.Numero	='XXX'		and
	d.Total_abono	<>0	and
	d.Id_Tipo_pago	='ANT'
Open Pagos
Fetch Pagos into @nit,@tipo_cargo,@Numero_anticipo,@Valor_Aplicado
while @@fetch_status=0
begin
	
	if not exists(select *from db_bancos_pfp.dbo.tbl_mov_bancos where Id_Empresa=@Id_empresa and id_Banco=@Id_Banco and Id_Tipo='CHE' and numero=@Numero_cheque)
	begin
	
		select @beneficiario=beneficiario  from tbl_proveedores where id_empresa=@id_empresa and nit=@nit
		select @Descripcion='Anticipo de pago'
		insert db_bancos_pfp.dbo.tbl_mov_bancos
		select @Id_Empresa,@Id_Banco,'CHE',@Numero_cheque,@Beneficiario,@Descripcion,@Valor_Aplicado,1,@Fecha_Movimiento,0,0,@periodo_fiscal,@mes_fiscal
		if @@error<>0
		begin
			rollback tran t1
			return
		end
	
		insert db_contabilidad_pfp.dbo.detalle_transacciones
		select @Id_Empresa,@periodo_fiscal,@mes_fiscal,@id_banco,'CHE',@Numero_cheque,2,'Anticipo a proveedor',@Valor_Aplicado,0,@Id_Cuenta_anticipo_proveedores,'','',0
		if @@error<>0
		begin
			rollback tran t1
			return
		end
		--actualizando los anticipos con el numero de cheque que fueron creados
		update  tbl_abonos set Id_Banco=@Id_Banco,Id_Tipo='CHE',Numero=@Numero_cheque
		
		where Id_Empresa=@Id_Empresa	and	Id_Tipo_Pago='Ant'	and 	Numero_pago=@Numero_anticipo
		if @@error<>0
		begin
			rollback tran t1
			return
		end
	end
	set @numero_cheque=ltrim(rtrim(cast(cast(@numero_cheque as int)+1 as char)))
Fetch Pagos into @nit,@tipo_cargo,@Numero_anticipo,@Valor_Aplicado
end
close pagos
deallocate pagos

commit tran t1

GO
                                                                                                                                                                                                                                                                                                                                                                                                                                           
