		select @Id_Empresa,@Id_Banco,'NDE',@Numero_cheque,@Beneficiario,substring(@Descripcion,1,180),@Valor_Aplicado,1,@Fecha_Movimiento,0,0,@periodo_fiscal,@mes_fiscal
		if @@error<>0
