-- SP: sp_generacion_rebajas_cxp
-- =============================




--EXEC sp_generacion_rebajas_cxp 1,'2011','10',30,'40','660369-6','FAC','A','998877','88','NCR'
CREATE procedure [dbo].[sp_generacion_rebajas_cxp] 	@Id_Empresa		int,
						@Periodo		char(4),
						@Mes			char(2),
						@Dia			int,
						@Numero			char(10),
						@Nit			char(20),
						@tipo_cargo		char(3),
						@serie_cargo    char(15),
						@numero_factura	 	char(15),
						@numero_nota_credito 		CHAR(15),
						@tipo_nota_credito		char(3) as

declare    @row_count       INT,
           @null_row_count  INT,
           @error_number    INT,
           @error_message   VARCHAR(255)


--se contabilizan todos los documentos que esten autorizados que tengan detalle contable
--y que no tengan documento contable asignado

declare @Linea	int,@Id_Cuenta	char(10),@Id_Auxiliar char(4),@Id_Departamento char(3), @Debe Numeric(12,2),@Haber Numeric(12,2),@descripcion char(150),@valor_aplicado numeric(12,2)
declare @Tipo_iva	int,@iva		numeric(12,2),@periodo_iva char(7),@fecha_docto datetime
declare @Total_nota	numeric(18,2)
--determinando la cuenta del creidot fiscal
declare @id_cuenta_credito_fiscal char(10)
select @id_cuenta_credito_fiscal= id_cuentacreditofis from db_contabilidad_pfp.dbo.empresas where id_empresa=@id_empresa

select @periodo_iva=periodo_iva  from db_contabilidad_pfp.dbo.empresas where id_empresa=@id_empresa

select @Tipo_iva=isnull(tipo_iva,1) from tbl_proveedores where id_empresa=@Id_Empresa and nit=@nit
--determinando la fecha de la rebaja

select  top 1 	@FECHA_DOCTO	=B.FECHA_DOCTO,
		@Total_Nota	=b.Total_Abono from tbl_det_abonos A INNER JOIN TBL_ABONOS B
					ON 	A.ID_EMPRESA	=B.ID_EMPRESA	AND
						A.ID_TIPO_PAGO	=B.ID_TIPO_PAGO AND
						A.NUMERO_PAGO	=B.NUMERO_PAGO						
where 	a.id_empresa	=@Id_empresa 		and 
		a.tipo_cargo	=@tipo_cargo 		AND
		A.Serie			=@serie_cargo		and 
		a.NUMERO_FACTURA=@numero_factura 	AND
		a.Anio			=''			and
		a.Mes			=''			and
		a.Id_banco		=''			and
		a.Tipo			=''			and
		a.numero		=''	


select @valor_aplicado=valor_aplicado from tbl_det_abonos where nit=@nit and tipo_cargo=@tipo_cargo and Serie=@serie_cargo  and numero_factura=@numero_factura and valor_aplicado<>0
begin transaction t1

if not exists( SELECT     * FROM         DB_CONTABILIDAD_PFP.DBO.TIPOS_DOCUMENTOS
		WHERE     (ID_EMPRESA = @Id_Empresa) AND (MODULO = '03') and tipo=@tipo_nota_credito)
begin

	SELECT @error_number=30001,
               @error_message='Tipo de documento no existe en modulo credito fiscal.'
	rollback transaction t1
	return
end
PRINT 'POR ACAVA'
insert db_contabilidad_pfp.dbo.cabecera_movimientos
select @Id_Empresa,@Periodo,@Mes,'XX','PD',@Numero,@Dia,'Para contabilizar rebaja Cuentas Por Pagar a: NIT' +@nit +' '+@serie_cargo +' '+@tipo_cargo+@numero_factura,5,getdate(),suser_sname(),2,0.00,0
if @@error<>0
begin
	rollback transaction t1
	return
end


declare detalle_poliza cursor for
select 	c.Id_cuenta,
	c.Id_Auxiliar,
	c.Id_Departamento,
	c.descripcion,
	Sum(c.debe) as debe,
	Sum(c.haber) as haber
	 from tbl_det_abonos d	inner join tbl_contabiliza_abonos c	
					on 	d.Id_empresa	=c.Id_empresa		and
						d.Id_tipo_pago	=c.Id_tipo_pago 	and
						d.Numero_Pago	=c.Numero_pago		and
						d.nit			=c.nit				and
						d.serie			=c.serie			and
						d.Tipo_cargo	=c.Tipo_cargo		and
						d.Numero_factura=c.Numero_factura
where	d.Id_Empresa	=@Id_Empresa	and
	d.Anio			=''				and
	d.Mes			=''				and
	d.Id_banco		=''				and
	d.Tipo			=''				and
	d.numero		=''				and
	d.valor_aplicado<>0				and
	c.nit			=@nit			and
	c.serie			=@serie_cargo	and
	c.tipo_cargo	=@tipo_cargo	and
	c.numero_factura=@numero_factura
	
group by c.id_cuenta,c.id_auxiliar,c.id_departamento,c.descripcion

set @Linea=0
open detalle_poliza
fetch detalle_poliza into @Id_cuenta,@Id_auxiliar,@Id_Departamento,@descripcion,@debe,@haber
while 
-- =============================
-- SP: sp_generacion_rebajas_solocxp
-- =============================




CREATE procedure [dbo].[sp_generacion_rebajas_solocxp] 	@Id_Empresa	int,
						@Periodo	char(4),
						@Mes		char(2),
						@Dia		int,
						@id_banco	char(2),
						@Tipo_contable	char(3),
						@Numero		char(10),
						@Nit		char(20),
						@tipo_cargo	char(3),
						@numero_factura	 char(15),
						@serie     char(15) ,
						@fecha_rebaja datetime as


--se contabilizan todos los documentos que esten autorizados que tengan detalle contable
--y que no tengan documento contable asignado

declare @Linea	int,@Id_Cuenta	char(10),@Id_Auxiliar char(4),@Id_Departamento char(3), @Debe Numeric(12,2),@Haber Numeric(12,2),@descripcion char(150),@valor_aplicado numeric(12,2)

select @valor_aplicado=valor_aplicado from tbl_det_abonos where nit=@nit and tipo_cargo=@tipo_cargo and numero_factura=@numero_factura and valor_aplicado<>0
begin transaction t1
	if exists(select *from tbl_det_abonos where 	id_Empresa	=@Id_empresa		and 
							nit		=@nit			and 
							tipo_cargo	=@tipo_cargo 		and 
							numero_Factura	=@numero_factura		and
							Serie			=@serie					and
							Anio		=''			and
							Mes		=''			and
							Id_banco	=''			and
							Tipo		=''			and
							numero		=''			and
							valor_aplicado	<>		0)
	begin

--registrando en el cargo del proveedor el documento con que fue contabillizado
	update tbl_det_abonos set anio=@periodo,
						mes	=@mes,
						id_banco=@id_banco,
						tipo	=@Tipo_Contable,
						numero	=@Numero,
						fecha_de_pago =@fecha_rebaja
	where 	id_Empresa	=@Id_empresa		and 
		nit		=@nit			and 
		tipo_cargo	=@tipo_cargo 		and 
		Serie=@serie and
		numero_Factura=@numero_factura	and
		Anio		=''			and
		Mes		=''			and
		Id_banco	=''			and
		Tipo		=''			and
		numero		=''			and
		valor_aplicado	<>		0	

	if @@error<>0
		begin
			rollback tran t1
			return
		end
	update tbl_cargos set saldo_factura=saldo_factura+(@valor_aplicado*-1)
		where id_Empresa=@Id_empresa	and nit=@nit	and numero_Factura=@numero_factura and
		Serie=@serie 
		if @@error<>0
		begin
			rollback tran t1
			return
		end

	if @@error=0
		commit transaction t1
	end


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: sp_helpdiagramdefinition
-- =============================

	CREATE PROCEDURE dbo.sp_helpdiagramdefinition
	(
		@diagramname 	sysname,
		@owner_id	int	= null 		
	)
	WITH EXECUTE AS N'dbo'
	AS
	BEGIN
		set nocount on

		declare @theId 		int
		declare @IsDbo 		int
		declare @DiagId		int
		declare @UIDFound	int
	
		if(@diagramname is null)
		begin
			RAISERROR (N'E_INVALIDARG', 16, 1);
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID();
		select @IsDbo = IS_MEMBER(N'db_owner');
		if(@owner_id is null)
			select @owner_id = @theId;
		revert; 
	
		select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname;
		if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId ))
		begin
			RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
			return -3
		end

		select version, definition FROM dbo.sysdiagrams where diagram_id = @DiagId ; 
		return 0
	END
	
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
-- =============================
-- SP: sp_helpdiagrams
-- =============================

	CREATE PROCEDURE dbo.sp_helpdiagrams
	(
		@diagramname sysname = NULL,
		@owner_id int = NULL
	)
	WITH EXECUTE AS N'dbo'
	AS
	BEGIN
		DECLARE @user sysname
		DECLARE @dboLogin bit
		EXECUTE AS CALLER;
			SET @user = USER_NAME();
			SET @dboLogin = CONVERT(bit,IS_MEMBER('db_owner'));
		REVERT;
		SELECT
			[Database] = DB_NAME(),
			[Name] = name,
			[ID] = diagram_id,
			[Owner] = USER_NAME(principal_id),
			[OwnerID] = principal_id
		FROM
			sysdiagrams
		WHERE
			(@dboLogin = 1 OR USER_NAME(principal_id) = @user) AND
			(@diagramname IS NULL OR name = @diagramname) AND
			(@owner_id IS NULL OR principal_id = @owner_id)
		ORDER BY
			4, 5, 1
	END
	
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
