CREATE procedure [dbo].[sp_inserta_conversion] 

@Id_empresa int,
@id_conversion char(4),
@fecha_transaccion datetime,
@cantidad_salida int,
@cantidad_entrada int,
@estado_transaccion bit as

if not exists( select *from Tbl_det_explosion 
where Id_empresa=@Id_empresa and
Id_conversion =@id_conversion )
begin
insert Tbl_det_explosion 
select	@Id_empresa,
		@id_conversion ,
		@fecha_transaccion ,
		@cantidad_salida ,
		@cantidad_entrada ,
		@estado_transaccion ,
		getdate(),
		suser_sname()
		
end
else begin
	update Tbl_det_explosion set Estado_transaccion =@estado_transaccion 
	where Id_empresa =@Id_empresa and
	Id_conversion =@id_conversion 
end
		
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
