-- =============================
-- SP: sp_lista_despacho_afacturar
-- =============================

--select *from Tbl_solicitud_despacho_cliente where id_cliente='4426641-6'            
--exec sp_lista_despacho_afacturar 3,'4426641-3'

CREATE procedure [dbo].[sp_lista_despacho_afacturar] @id_empresa int,@nit char(20) as
--procedimiento que lista el total de solicitudes de despacho entregadas no facturadas
SELECT  X.ID_EMPRESA,
		X.ID_SOLICITUD_DESPACHO,
		X.NIT_CLIENTE,
		X.Fecha_solicitud,
		X.TOTAL FROM 
(select	ID_EMPRESA,
		ID_SOLICITUD_DESPACHO,
		NIT_CLIENTE,
		FECHA_SOLICITUD,
		(select SUM(D.Cantidad_entregada * d.precio_vta) from tbl_solicitud_Despacho_cliente_detalle d
		where d.Id_empresa=C.Id_empresa and d.Id_solicitud_despacho =C.id_solicitud_despacho)  as TOTAL
		from Tbl_solicitud_despacho_cliente c
WHERE	c.Id_empresa			=@id_empresa	AND
		c.Nit_cliente			=@nit				AND
		c.Autorizacion			IS NULL			AND
		c.Serie					IS NULL			AND
		c.Numero				IS NULL			AND
		C.Status_solicitud		='ENTREGADA') X		
WHERE	X.TOTAL					<>0
UNION ALL
--procedimiento que lista el total de solicitudes de despacho que no tienen ordenes de despacho
SELECT  X.ID_EMPRESA,
		X.ID_SOLICITUD_DESPACHO,
		X.NIT_CLIENTE,
		X.Fecha_solicitud,
		X.TOTAL FROM 
(select	ID_EMPRESA,
		ID_SOLICITUD_DESPACHO,
		NIT_CLIENTE,
		FECHA_SOLICITUD,
		(select SUM(D.Cantidad * d.precio_vta) from tbl_solicitud_Despacho_cliente_detalle d
		where d.Id_empresa=C.Id_empresa and d.Id_solicitud_despacho =C.id_solicitud_despacho)  as TOTAL
		from Tbl_solicitud_despacho_cliente c
WHERE	c.Id_empresa			=@id_empresa	AND
		c.Nit_cliente			=@nit				AND
		c.Autorizacion			IS NULL			AND
		c.Serie					IS NULL			AND
		c.Numero				IS NULL			AND
		C.Status_solicitud		='SOLICITADA'   AND
		C.LTIENE_ORDEN_ENTREGA=2) X		
WHERE	X.TOTAL					<>0

		


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
