-- =============================
-- SP: sp_mayoriza_mproyecto
-- =============================
/*
UPDATE TBL_PROYECTO SET VENTA_PROYECTO=0, TOTAL_PRESUPUESTO=0
select *from tbl_mproyecto  where id_transaccion_mproyecto=67
select *from  tbl_proyecto  where id_transaccion_mproyecto=67
SELECT *FROM TBL_RUBRO_PROYECTO
SELECT *FROM Tbl_Rubro_Proyecto set psugerido= WHERE Id_Transaccion_Proyecto=60 AND OPERATIVO=1

exec sp_mayoriza_mproyecto 72
*/



CREATE procedure [dbo].[sp_mayoriza_mproyecto] @id_transaccion_mproyecto int as
declare 
		@id_transaccion_proyecto int,
		@id_transaccion_tbl_rubro int,
		@id_rubro varchar(10),
		@id_rubro_madre varchar(10),
		@id_rubro_temporal varchar(10),
		@nivel int,
		@cantidad numeric(18,2),
		@costo	numeric(18,2),
		@TOTAL_GENERAL_PRESUPUESTO NUMERIC(18,2),
		@TOTAL_GENERAL_VENTA NUMERIC(18,2),
		@ID_MACROPROYECTO INT,
		@psugerido numeric(18,2)
--INICIALIZA EL TOTAL PRESUPUESTO EN TABLA MACROPYECTO
UPDATE TBL_MPROYECTO SET TOTAL_PRESUPUESTO=0,
							Venta_Sugerida=0
 WHERE ID_TRANSACCION_MPROYECTO=@id_transaccion_mproyecto

SELECT @TOTAL_GENERAL_PRESUPUESTO= SUM(RUBRO.total),
		@TOTAL_GENERAL_VENTA     = SUM(  RUBRO.psugerido )
from tbl_mproyecto macro 
inner join tbl_proyecto proy on macro.id_transaccion_mproyecto=proy.id_transaccion_mproyecto
inner join tbl_rubro_proyecto rubro on rubro.id_transaccion_proyecto=proy.id_transaccion_proyecto
where macro.id_transaccion_mproyecto=@Id_transaccion_mproyecto and rubro.operativo=1





--actualizando con valor cero los rubros madres
update tbl_rubro_proyecto set	costo=0,
								total=0,
								psugerido=0
from tbl_mproyecto macro 
inner join tbl_proyecto proy on macro.id_transaccion_mproyecto=proy.id_transaccion_mproyecto
inner join tbl_rubro_proyecto rubro on rubro.id_transaccion_proyecto=proy.id_transaccion_proyecto
where macro.id_transaccion_mproyecto=@Id_transaccion_mproyecto and rubro.operativo=0

--empieza a mayorizar rubros operativos
declare rubros cursor for
select	macro.Id_Transaccion_Mproyecto,
		proy.id_transaccion_proyecto,
		rubro.id_transaccion_tbl_rubro,
		rubro.id_rubro,
		rubro.Id_Rubro_Madre,
		rubro.nivel,
		rubro.cantidad,
		rubro.costo,
		rubro.psugerido
from tbl_mproyecto macro 
inner join tbl_proyecto proy on macro.id_transaccion_mproyecto=proy.id_transaccion_mproyecto
inner join tbl_rubro_proyecto rubro on rubro.id_transaccion_proyecto=proy.id_transaccion_proyecto
where macro.id_transaccion_mproyecto=@id_transaccion_mproyecto and rubro.operativo=1
open rubros
fetch rubros into	@Id_transaccion_mproyecto,
					@Id_transaccion_proyecto,
					@Id_transaccion_tbl_rubro,
					@Id_rubro,
					@Id_rubro_madre,
					@nivel,
					@cantidad,
					@costo,
					@psugerido
while @@fetch_status=0
begin
	 while @id_rubro_madre<>''
	 begin
	 print 'proyecto'
print @id_transaccion_proyecto
print @id_rubro
print 'precio sugerido'
print @psugerido
		update tbl_rubro_proyecto set	total=total +(@cantidad*@costo ),
										Psugerido=psugerido+ @psugerido 
		from tbl_mproyecto macro 
		inner join tbl_proyecto proy on macro.id_transaccion_mproyecto=proy.id_transaccion_mproyecto
		inner join tbl_rubro_proyecto rubro on rubro.id_transaccion_proyecto=proy.id_transaccion_proyecto
		where	macro.id_transaccion_mproyecto=@Id_transaccion_mproyecto and
				proy.id_transaccion_proyecto=@id_transaccion_proyecto and
				id_rubro=@id_rubro_madre and
				rubro.operativo=0 
		
		set @id_rubro_temporal=@Id_rubro_madre

		select @id_rubro_madre=id_rubro_madre from tbl_rubro_proyecto
		where id_rubro=@id_rubro_temporal and id_transaccion_proyecto=@Id_transaccion_proyecto
		print 'rubro madre'+@id_rubro_madre
		print @id_rubro_madre
	end	


fetch rubros into	@Id_transaccion_mproyecto,
					@Id_transaccion_proyecto,
					@Id_transaccion_tbl_rubro,
					@Id_rubro,
					@Id_rubro_madre,
					@nivel,
					@cantidad,
					@costo,
					@psugerido
		
end
