create procedure [dbo].[sp_pedidos_por_aplicar] @Id_empresa int,@nit char(20) as
select p.Id_empresa,p.nit,r.Id_recepcion,r.Id_pedido,sum(d.cantidad_por_recibir*d.precio_compra) as total
 from tbl_recepcion_pedidos r, tbl_recepcion_pedidos_Detalle d, tbl_pedidos p
where r.id_empresa=d.id_empresa and r.id_recepcion=d.id_recepcion	and p.id_empresa	=r.id_empresa	and
 p.id_pedido=r.id_pedido	and r.recepcion_aplicada=0	AND r.status=2 and p.nit=@nit and r.id_empresa=@Id_empresa
group by p.id_empresa,P.NIT,r.id_recepcion,r.Id_pedido order by r.id_recepcion


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
