--exec sp_provicion_cxp 1,'111111','FAC','ABC',112233
--Creando procedimiento que genera poliza de provision de facturas cuentas por pagar
CREATE procedure [dbo].[sp_provicion_cxp] 	@Id_Empresa	int,
					@Nit		char(20),
					@Id_Tipo_Cargo	char(3),
					@Serie			char(15),
					@Numero_Factura	numeric(15) as
/* Este procedimiento utiliza dos procesos uno para provisionar facturas que se originaron en inventarios
el otro procedimiento es para generar la provision de las facturas que se originan en cuentas por pagar*/

Declare @sistema			int,
		@fecha_documento	datetime,
		@apartirde			datetime,
		@Valor_FActura 		numeric(12,2),
		@ISR				numeric(12,2),
		@iva				NUMERIC(12,2),
		@error_number		INT,
		@error_message		VARCHAR(255),
		@coeficiente_iva	numeric(12,2),
		@Tipo_Contribuyente	int,
		@Id_Orden_Compra_Proyecto int
 
select 	@sistema		=sistema,
		@fecha_documento =fecha_documento,
		@Valor_Factura	=Valor_Factura,
		@Isr			=isr,
		@iva			=iva,
		@Id_Orden_Compra_Proyecto=id_orden_compra_proyecto from tbl_cargos 	where 	Id_Empresa	=@Id_Empresa	and
									Nit		=@Nit		and
									Serie   =@Serie     and
									Numero_Factura	=@Numero_Factura

Declare		@Id_CuentaCreditoFis 	char(10),
			@Id_Cuenta_Isr		char(10),
			@Id_Cuenta_Gasto	char(10),
			@Id_Cuenta_Aux		char(4),
			@Id_Cuenta_Depto	char(3),
			@Id_Cuenta_cxp		char(10),
			@Valor_Neto_Factura	numeric(12,2),
			@Porcentaje			numeric(12,2),
			@Linea				int,
			@porcentaje_iva_anterior numeric(12,2),
			@porcentaje_iva			numeric(12,2)	

set @valor_neto_Factura=@Valor_Factura-@Iva
--seleccionando cuentacontable creditofiscal,cuenta isr que se encuentra en el modulo de contabilidad
select 	@apartirde				=apartirde,
		@porcentaje_iva			=porcentaje_iva,
		@porcentaje_iva_anterior=porcentaje_iva_anterior,
		@Id_CuentaCreditoFis	=Id_CuentaCreditoFis,
		@Id_Cuenta_isr			=Id_Cuenta_Isr  from db_contabilidad_pfp.dbo.empresas where Id_Empresa	=@Id_Empresa
		


select 	@Id_cuenta_cxp		=id_cuenta_cxp,
		@Tipo_Contribuyente	=regimen_contribyente from tbl_proveedores where id_empresa=@Id_Empresa and nit=@nit

		
set dateformat dmy
Declare @Coef_anterior	numeric(12,2),
		@Coef_actual	numeric(12,2)
		
select	@coef_actual	=Porcentaje_iva,
		@coef_anterior	=Porcentaje_iva_anterior
from empresas where id_empresa=1
set @coef_actual	=1+round(@coef_actual/100,2)
set @coef_anterior	=1+round(@coef_anterior/100,2)
		


IF @Id_CuentaCreditoFis is null
Begin
	SELECT @error_number=50001,
        @error_message='Debe especificar Cuenta de Crédito Fiscal.'
	goto error
End

IF @Id_Cuenta_Isr is null AND
 (select Retiene_ISR   from Tbl_Proveedores where Id_Empresa=@Id_Empresa and Nit=@Nit )='SI'
Begin
	SELECT @error_number=50001,
        @error_message='Debe especificar Cuenta de ISR.'
	goto error
End



if @fecha_documento >=@apartirde 
	begin
		set @coeficiente_iva= 1+ round ( @porcentaje_iva/100,2 ) 
	end
	else 
		set @coeficiente_iva= 1+ round ( @porcentaje_iva_anterior/100,2 ) 


set @Linea=0
if @sistema =5  ---sistema 5 es cuentas por pagar
begin
	

	
		SELECT	@Id_cuenta_gasto=PROY.ID_CUENTA,
				@Id_Cuenta_Aux=Proy.Id_auxiliar,
				@Id_Cuenta_Depto=div.Id_Division 	 FROM Tbl_Orden_Compra_Proyecto O
 
		 INNER JOIN Tbl_Proyecto PROY
		 ON PROY.Id_transaccion_Proyecto=O.Id_transaccion_Proyecto
		 inner join Tbl_Mproyecto macro 
		 on macro.Id_Transaccion_Mproyecto=proy.Id_Transaccion_Mproyecto
		 inner join Tbl_Division div on
		 macro.id_transac_division=div.Id_Transac_Division
		 
		WHERE O.Id_Orden_Compra_Proyecto=@Id_Orden_Compra_Proyecto


--contabilizando las facturas de cuentas por pagar de acuerdo a la configuracion del proyecto
		set @linea=@linea+1
	
	--insertando la linea de gasto
	
		Insert tbl_contabiliza_cargos
		Select 	@Id_Empresa,
			@Nit,
			@Id_Tipo_Cargo,
			
