CREATE   procedure [dbo].[sp_recosteo] @Id_Empresa int,@Periodo_Inv char(7) ,@fecha_fin datetime as
set dateformat dmy
begin transaction t1
alter table tbl_det_facturacion disable trigger all
alter table tbl_detalle_movimientos disable trigger all
alter table Tbl_Orden_Servicio_Detalle_Integracion disable trigger all
alter table tbl_existencia disable  trigger all
alter table tbl_productos disable trigger all

Declare @Id_Producto		char(15),
	@Fecha_Ini		datetime,
	--@Fecha_Fin		datetime,
	@Fecha_periodo_anterior datetime,
	@Periodo_anterior	char(7),
	@existencia_total	numeric(12,2),
	@Existencia			numeric(12,4),
	@Costo_promedio		numeric(12,5),
	@Costo_total		numeric(12,5),
	@caja			int,
	@autorizacion		char(20),
