--procedimiento de series pendientes de asignar a caja
create procedure sp_series_pendientes_asignar @Id_Empresa	int as
select 	Id_Empresa,
	Autorizacion,
	Serie from tbl_Series	
where 	Id_Empresa	=@Id_Empresa	and
	Id_Empresa+Autorizacion+serie not in 
(select Id_Empresa+Autorizacion+serie from tbl_series_por_caja where Id_Empresa=@Id_Empresa)


GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
