--exec sp_traslada_vales_factura '1','243212-1','A','145','05/02/2013','traslado de facturas'
CREATE procedure [dbo].[sp_traslada_vales_factura]
@id_empresa  as int, 
@id_cliente  as varchar(20),
@serie	     as char(20), 
@numero		 as numeric(10,0), 
@fecha_fac	 as datetime, 
@descripcion as varchar(50) 
as

insert into TBL_CABECERA_VENTAS_VALE
select
@id_empresa 	as id_empresa,
@serie			as serie,
@numero			as numero,
@fecha_fac		as fecha_factura,
'POSPAGO'		as tipo_vale,
0				as cantidad_vales,
0				as vales_total,
'Pospago'		as usuario,
GETDATE()		as fecha_operacion,
@descripcion	as descripcion_ventas_vale,
@id_cliente     as id_cliente_vale,
Null			as fecha_cierre
from TBL_DETALLE_VALES_POR_APLICAR 
where ID_EMPRESA			  = @id_empresa and
	  ID_CLIENTE_VALE_DETALLE = @id_cliente and
	  ESTADO_VALE  				  = 2			



delete  from TBL_CABECERA_VENTAS_VALE 
where NUMERO = @numero	 and 
ID_TRANSACCION_FACTURA > (select min(id_transaccion_factura) 
						  from TBL_CABECERA_VENTAS_VALE 
						  where SERIE = @serie  and NUMERO = @numero)

