-- =============================
--exec sp_traslada_vales_factura_detalle '1','243212-1','A','145','05/02/2013',50,100,'traslado de facturas'
CREATE procedure [dbo].[sp_traslada_vales_factura_detalle]
@id_empresa			as int, 
@id_cliente			as varchar(20),
@serie				as char(20), 
@numero				as numeric(10,0), 
@fecha_fac			as datetime, 
@id_vale_post_pago	as int,
@descripcion		as varchar(50)
as

insert into TBL_DETALLE_VENTAS_VALES 
select
@id_empresa			as id_empresa,
@serie				as serie,
@numero				as numero_factura,
id_vale_post_pago,	
id_producto,
id_cliente_vale_detalle,
fecha_vale,
valor_vale,
cantidad_vale,
1 as estado_Vale
from TBL_DETALLE_VALES_POR_APLICAR 
where ID_EMPRESA			  = @id_empresa		and
	  ID_CLIENTE_VALE_DETALLE = @id_cliente		and
	  Estado_vale			  = 2				and
	   ID_VALE_POST_PAGO = @id_vale_post_pago


UPDATE TBL_DETALLE_VALES_POR_APLICAR 
SET ESTADO_VALE = 1, 
	FACTURADO	= 1
where ID_EMPRESA			  = @id_empresa		and
	  ID_CLIENTE_VALE_DETALLE = @id_cliente		and
	  ID_VALE_POST_PAGO		  = @id_vale_post_pago


--update TBL_CABECERA_VENTAS_VALE 
--set CANTIDAD_VALES  =  (select COUNT(*) from TBL_DETALLE_VENTAS_VALES where SERIE = @serie and NUMERO = @numero),
--	VALES_TOTAL		=  (select SUM(valor_vale) from TBL_DETALLE_VENTAS_VALES where SERIE = @serie and NUMERO = @numero)
--where  ID_EMPRESA = @id_empresa and
--	   SERIE	  = @serie		and
--	   NUMERO	  = @numero		
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
-- =============================
-- SP: sp_upgraddiagrams
-- =============================

	CREATE PROCEDURE dbo.sp_upgraddiagrams
	AS
	BEGIN
		IF OBJECT_ID(N'dbo.sysdiagrams') IS NOT NULL
			return 0;
	
		CREATE TABLE dbo.sysdiagrams
		(
			name sysname NOT NULL,
			principal_id int NOT NULL,	-- we may change it to varbinary(85)
			diagram_id int PRIMARY KEY IDENTITY,
			version int,
	
			definition varbinary(max)
			CONSTRAINT UK_principal_name UNIQUE
			(
				principal_id,
				name
			)
		);


		/* Add this if we need to have some form of extended properties for diagrams */
		/*
		IF OBJECT_ID(N'dbo.sysdiagram_properties') IS NULL
		BEGIN
			CREATE TABLE dbo.sysdiagram_properties
			(
				diagram_id int,
				name sysname,
				value varbinary(max) NOT NULL
			)
		END
		*/

		IF OBJECT_ID(N'dbo.dtproperties') IS NOT NULL
		begin
			insert into dbo.sysdiagrams
			(
				[name],
				[principal_id],
				[version],
				[definition]
			)
			select	 
				convert(sysname, dgnm.[uvalue]),
				DATABASE_PRINCIPAL_ID(N'dbo'),			-- will change to the sid of sa
				0,							-- zero for old format, dgdef.[version],
				dgdef.[lvalue]
			from dbo.[dtproperties] dgnm
				inner join dbo.[dtproperties] dggd on dggd.[property] = 'DtgSchemaGUID' and dggd.[objectid] = dgnm.[objectid]	
				inner join dbo.[dtproperties] dgdef on dgdef.[property] = 'DtgSchemaDATA' and dgdef.[objectid] = dgnm.[objectid]
				
			where dgnm.[property] = 'DtgSchemaNAME' and dggd.[uvalue] like N'_EA3E6268-D998-11CE-9454-00AA00A3F36E_' 
			return 2;
		end
		return 1;
	END
	
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
-- =============================
-- SP: sp_verifica_credito_cl
-- =============================
CREATE procedure sp_verifica_credito_cl @Id_empresa int,@nit char(20) as

select sum(limite) as limite,
		sum(saldo) as saldo
from 
(
select LIMITE_CREDITO_CLIENTE as limite, 0 as saldo from tbl_proveedores WHERE ID_EMPRESA=@Id_empresa AND NIT=@nit
union all
SELECT 0 as limite,
isnull( sum(saldo_docto),0)  as saldo FROM tbl_cuentas_por_cobrar
where id_empresa=@Id_empresa and nit=@nit ) x
GO
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       

